// Routine active : perso (db.routine) > gÃĐnÃĐrÃĐ (db.generatedProgram) > template > rien
function getRoutine() {
  // PrioritÃĐ 1 : routine personnalisÃĐe (modifiÃĐe dans RÃĐglages > Mon Programme)
  if (db.routine && Object.keys(db.routine).length > 0) return db.routine;
  // PrioritÃĐ 2 : routine gÃĐnÃĐrÃĐe Ã  l'onboarding
  if (db.generatedProgram && db.generatedProgram.length > 0) {
    const r = {};
    db.generatedProgram.forEach(d => { r[d.day] = d.isRest ? 'ðī Repos' : (d.label || d.day); });
    return r;
  }
  // PrioritÃĐ 3 : template par dÃĐfaut selon le mode
  const style = modeFeature('programStyle');
  if (style && ROUTINE_TEMPLATES[style]) return ROUTINE_TEMPLATES[style].routine;
  return DEFAULT_ROUTINE;
}

var _saveDBTimer = null;
var _saveDBDirty = false;

function saveDB() {
  clearCaches();
  _saveDBDirty = true;
  if (_saveDBTimer) return; // already scheduled
  _saveDBTimer = setTimeout(function() {
    _saveDBTimer = null;
    _flushDB();
  }, 2000);
  // Auto cloud-sync dÃĐjÃ  cÃĒblÃĐ ici : debouncedCloudSync() est offline-safe
  // (db.pendingSync + resync sur event 'online') et auth-guarded
  // (cloudSyncEnabled). Ne PAS ajouter de second timer de sync en parallÃĻle.
  debouncedCloudSync();
}

function saveDBNow() {
  clearCaches();
  if (_saveDBTimer) { clearTimeout(_saveDBTimer); _saveDBTimer = null; }
  _saveDBDirty = true;
  _flushDB();
  debouncedCloudSync();
}

function _flushDB() {
  if (!_saveDBDirty) return;
  _saveDBDirty = false;
  try {
    if (!db.gamification) db.gamification = {};
    db.updatedAt = Date.now();
    localStorage.setItem(STORAGE_KEY, JSON.stringify(db));
  } catch(e) {
    console.error('saveDB error:', e);
    // Surface quota errors to the user instead of failing silently â otherwise
    // users keep training and the data quietly stops persisting.
    var isQuota = e && (e.name === 'QuotaExceededError' || e.code === 22 || /quota/i.test(e.message || ''));
    if (isQuota && typeof showToast === 'function') {
      showToast('â ïļ Stockage local plein â synchronise avec le cloud');
    }
  }
}

// Flush before leaving/hiding the page
window.addEventListener('beforeunload', _flushDB);
document.addEventListener('visibilitychange', function() {
  if (document.visibilityState === 'hidden') _flushDB();
});

// Global error trap â capture "n is not a function" et autres TypeError
// minifiÃĐs pour que l'app ne plante pas silencieusement chez l'utilisateur.
window.addEventListener('error', function(event) {
  if (!event || !event.error) return;
  var msg = String(event.error.message || event.message || 'Unknown error');
  // Ignorer les erreurs rÃĐseau/Supabase dÃĐjÃ  gÃĐrÃĐes ailleurs
  if (/Failed to fetch|NetworkError|Load failed|ResizeObserver/i.test(msg)) return;
  try {
    if (typeof logErrorToSupabase === 'function') {
      logErrorToSupabase('window_error', msg.substring(0, 500),
        (event.filename || '?') + ':' + (event.lineno || '?'));
    }
  } catch(e) {}
});
window.addEventListener('unhandledrejection', function(event) {
  if (!event || !event.reason) return;
  var msg = String(event.reason.message || event.reason || 'Unhandled rejection');
  if (/Failed to fetch|NetworkError|Load failed|AbortError/i.test(msg)) return;
  try {
    if (typeof logErrorToSupabase === 'function') {
      logErrorToSupabase('unhandled_rejection', msg.substring(0, 500), 'promise');
    }
  } catch(e) {}
});
function debouncedCloudSync() {
  if (!cloudSyncEnabled) return;
  if (!navigator.onLine) {
    db.pendingSync = true;
    _flushDB();
    return;
  }
  clearTimeout(syncDebounceTimer);
  syncDebounceTimer = setTimeout(() => { syncToCloud(true); }, 2000);
}

window.addEventListener('online', function() {
  if (db.pendingSync && cloudSyncEnabled) {
    db.pendingSync = false;
    _flushDB();
    if (typeof syncToCloud === 'function') syncToCloud(true);
    if (typeof showToast === 'function') showToast('ðķ Connexion rÃĐtablie â sÃĐance synchronisÃĐe');
  }
});
function generateId() { return Math.random().toString(36).substr(2, 9); }

// Lazy-load chart.min.js on first chart render (A3-F3) â keeps its 204 KB parse
// off the synchronous boot path. The SW precaches it, so cache-first serves it
// near-instantly when a chart first needs it.
let _chartLoadPromise = null;
function ensureChartLoaded() {
  if (typeof Chart !== 'undefined') return Promise.resolve();
  if (_chartLoadPromise) return _chartLoadPromise;
  _chartLoadPromise = new Promise(function(resolve, reject) {
    var s = document.createElement('script');
    s.src = 'js/chart.min.js';
    s.onload = function() { resolve(); };
    s.onerror = function() { _chartLoadPromise = null; reject(new Error('chart load failed')); };
    document.head.appendChild(s);
  });
  return _chartLoadPromise;
}

// ââ GAMIFICATION â defensive init âââââââââââââââââââââââââââ
