function _obGenerateProgramCore() {
  gotoObStep('7');
  var logo   = document.getElementById('ob7-logo');
  var title  = document.getElementById('ob7-title');
  var sub    = document.getElementById('ob7-sub');
  var genAnim = document.getElementById('ob-gen-anim');
  var fill   = document.getElementById('ob-gen-bar-fill');
  var stepTxt = document.getElementById('ob-gen-step-text');
  var summary = document.getElementById('ob-summary');
  var finBtn  = document.getElementById('ob-finish-btn');
  if (logo)    logo.textContent  = 'âĄ';
  if (title)   title.textContent = 'GÃĐnÃĐration en coursâĶ';
  if (sub)     sub.textContent   = 'On assemble ton programme sur mesure.';
  if (genAnim) genAnim.style.display = 'block';
  if (summary) summary.style.display = 'none';
  if (finBtn)  finBtn.style.display  = 'none';
  if (fill)    fill.style.width = '0%';

  var steps = ['Analyse du profilâĶ', 'Calcul du volumeâĶ', 'SÃĐlection des exercicesâĶ', 'Adaptation aux blessuresâĶ', 'FinalisationâĶ'];
  var totalDur = 1600;
  var stepDur  = totalDur / steps.length;
  var i = 0;
  function animStep() {
    if (i < steps.length) {
      if (stepTxt) stepTxt.textContent = steps[i];
      if (fill)    fill.style.width = ((i + 1) / steps.length * 100) + '%';
      i++;
      setTimeout(animStep, stepDur);
    } else {
      // InfÃĐrence (Gemini) â remplir les champs manquants AVANT generateProgram
      // pour que db.user.level infÃĐrÃĐ soit utilisÃĐ. N'ÃĐcrase jamais l'existant.
      if (typeof inferMissingData === 'function') {
        try {
          var _enriched = inferMissingData({
            trainingMode: db.user.trainingMode,
            level:        db.user.level,
            mat:          obMat,
            freq:         obFreq,
            duration:     obDuration,
            goals:        db.user.goal ? [db.user.goal] : null,
            gender:       db.user.gender,
            bw:           db.user.bw,
            obProfile:    db.user.obProfile
          });
          if (!db.user.level && _enriched.level) db.user.level = _enriched.level;
          if ((db.user.vocabLevel === undefined || db.user.vocabLevel === null) && _enriched.vocabLevel !== undefined) {
            db.user.vocabLevel = _enriched.vocabLevel;
          }
          if (db.user.skipPRs === undefined && _enriched.skipPRs !== undefined) db.user.skipPRs = _enriched.skipPRs;
          if (db.user.skipRPE === undefined && _enriched.skipRPE !== undefined) db.user.skipRPE = _enriched.skipRPE;
        } catch (eInfer) {
          if (typeof logErrorToSupabase === 'function') logErrorToSupabase('infer_missing_data', String(eInfer && eInfer.message || eInfer), '_obGenerateProgramCore');
        }
      }

      // Compute injuries from db
      obInjuries = (db.user.injuries || [])
        .filter(function(inj) { return inj && inj.active && inj.level >= 1; })
        .map(function(inj) { return _OB_ZONE_TO_EXCL[inj.zone] || inj.zone; })
        .filter(Boolean);
      var goalObj = obGoals.find(function(g) { return g.id === (db.user.goal || 'masse'); }) || obGoals[1];
      var generated = generateProgram([goalObj], obFreq, obMat, obDuration, obInjuries, obCardio, null, null, db.user.level);
      db.generatedProgram = generated;
      db.user.programParams = { goals: [goalObj.id], freq: obFreq, mat: obMat, duration: obDuration, injuries: obInjuries, cardio: obCardio, level: db.user.level };

      // ComplÃĐter programParams avec les infÃĐrences (split notamment)
      if (typeof inferMissingData === 'function') {
        try {
          var _enrichedPP = inferMissingData({
            trainingMode: db.user.trainingMode,
            freq:         obFreq,
            duration:     obDuration,
            obProfile:    db.user.obProfile
          });
          if (!db.user.programParams.split && _enrichedPP.split) db.user.programParams.split = _enrichedPP.split;
        } catch(e) {}
      }
      db.routine = {};
      db.routineExos = db.routineExos || {};
      generated.forEach(function(d) {
        db.routine[d.day] = d.isRest ? 'ðī Repos' : (d.isCardio ? 'ð ' + d.label : d.label);
        if (!d.isRest && d.exos && d.exos.length > 0) {
          db.routineExos[d.day] = d.exos.map(function(id) { return EXO_DB[id] ? EXO_DB[id].name : id; });
        }
      });
      saveDB();
      // Show result
      if (genAnim) genAnim.style.display = 'none';
      if (logo)  logo.textContent  = 'âĻ';
      if (title) title.textContent = 'Ton programme est prÃŠt !';
      if (sub)   sub.textContent   = 'VoilÃ  ce qu\'on a prÃĐparÃĐ pour toi.';
      renderObSummary(generated);
      if (summary) summary.style.display = 'block';
      if (finBtn)  finBtn.style.display  = 'block';
      var _medWrap = document.getElementById('ob-medical-consent-wrap');
      if (_medWrap) _medWrap.style.display = 'block';
    }
  }
  animStep();
}

function renderObSummary(generated) {
  var el = document.getElementById('ob-summary');
  if (!el) return;
  var trainingDays = generated.filter(function(d) { return !d.isRest; });
  var html = '<div style="background:var(--surface);border:1px solid var(--border);border-radius:14px;padding:14px;margin-top:12px;">';
  html += '<div style="font-size:13px;font-weight:700;margin-bottom:10px;">ð ' + trainingDays.length + ' sÃĐances / semaine Â· ' + obMat + ' Â· ' + obDuration + 'min</div>';
  html += '<div style="display:flex;flex-direction:column;gap:6px;">';
  generated.forEach(function(d) {
    var icon = d.isRest ? 'ðī' : 'ðŠ';
    html += '<div style="display:flex;align-items:center;gap:8px;font-size:12px;">';
    html += '<span style="min-width:74px;font-weight:600;color:var(--sub);">' + d.day + '</span>';
    html += '<span>' + icon + ' ' + (d.isRest ? 'Repos' : d.label) + '</span>';
    html += '</div>';
  });
  html += '</div></div>';
  el.innerHTML = html;
}

