// ââ EXERCICES EXCLUS PAR BLESSURE âââââââââââââââââââââââââââ
const INJURY_EXCLUSIONS = {
  epaules:  ['ohp','ohp_halt','elev_lat','elev_front','incline_bench','dips_pec','dips_tri','face_pull','upright_row'],
  genoux:   ['squat','leg_press','leg_ext','fente','hack_squat','step_up','sissy'],
  dos:      ['deadlift','rdl','row_barre','row_halt','good_morning','shrug'],
  poignets: ['bench','bench_halt','curl_barre','skull','row_barre'],
  nuque:    ['lat_pull','traction','shrug','face_pull'],
  hanches:  ['deadlift','rdl','hip_thrust','fente','squat']
};

// ââ SETSÃREPS PAR NIVEAU âââââââââââââââââââââââââââââââââââââ
function getSetsReps(exoId, level, goalId) {
  const lp = LEVEL_PARAMS[level] || LEVEL_PARAMS.intermediaire;
  const isStrength = goalId === 'force' || goalId === 'recompo';
  const isHypertrophy = goalId === 'masse' || goalId === 'seche';
  const isCardioExo = exoId === 'cardio_hiit' || exoId === 'cardio_liss';

  if (isCardioExo) return EXO_DB[exoId]?.sets || '30min';

  const exo = EXO_DB[exoId];
  if (!exo) return lp.setsWork+'Ã10';

  if (exo.exoType === 'time' || exo.sets?.includes('s') || exo.sets?.includes('min')) return exo.sets;
  if (exo.sets?.includes('max')) return lp.setsWork+'Ãmax';

  if (isStrength) {
    const reps = level === 'debutant' ? 6 : level === 'intermediaire' ? 5 : level === 'avance' ? 3 : 2;
    return lp.setsWork+'Ã'+reps;
  }
  if (isHypertrophy) {
    return lp.setsWork+'Ã'+lp.repsHigh;
  }
  return lp.setsWork+'Ã'+(Math.round((lp.repsLow+lp.repsHigh)/2));
}

// ââ GÃNÃRATION PROGRAMME ENRICHIE âââââââââââââââââââââââââââ
function generateProgram(goals, freq, mat, duration, injuries, cardio, compDate, compType, level) {
  const g1    = goals[0]?.id || 'force';
  const lp    = LEVEL_PARAMS[level] || LEVEL_PARAMS.intermediaire;
  const exosN = lp.exosPerSession[duration] || lp.exosPerSession[60];
  const excluded = new Set((injuries||[]).flatMap(z => INJURY_EXCLUSIONS[z]||[]));

  // ââ 3-way split routing : powerlifting / powerbuilding / bodybuilding ââ
  var trainingMode = (typeof db !== 'undefined' && db && db.user && db.user.trainingMode) || '';
  var isPL = (g1 === 'force');
  var isPB = (trainingMode === 'powerbuilding' || g1 === 'mixte');
  var isBB = (!isPL && !isPB);

  // Filtrage exercices par blessures + matÃĐriel
  function filtSafe(ids, m) {
    return filtMat(ids.filter(id => !excluded.has(id)), m).slice(0, exosN);
  }

  // DÃĐbutants : remplacer les exercices complexes par des alternatives plus simples
  function filtLevel(ids) {
    if (lp.complexity === 'low') {
      const REPLACEMENTS = {
        'squat':    'leg_press',
        'deadlift': 'rdl',
        'rdl':      'leg_curl',
        'ohp':      'ohp_halt',
        'skull':    'tri_cable',
      };
      return ids.map(id => REPLACEMENTS[id] || id);
    }
    return ids;
  }

  const trainingDays = obSelectedDays.length === freq
    ? obSelectedDays
    : { 1:['Lundi'],2:['Lundi','Jeudi'],3:['Lundi','Mercredi','Vendredi'],4:['Lundi','Mardi','Jeudi','Vendredi'],5:['Lundi','Mardi','Mercredi','Jeudi','Vendredi'],6:['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi'] }[Math.min(freq,6)] || ['Lundi','Mercredi','Vendredi'];

  // Blocs ajustÃĐs
  const B = {
    force: {
      push:    { label:'Push â Force', exos: filtSafe(filtLevel(['bench','ohp','incline_bench','tri_cable','elev_lat']), mat) },
      pull:    { label:'Pull â Force', exos: filtSafe(filtLevel(['deadlift','row_barre','lat_pull','traction','curl_barre','face_pull']), mat) },
      legs:    { label:'Jambes â Force', exos: filtSafe(filtLevel(['squat','leg_press','rdl','mollet','leg_curl']), mat) },
      full_a:  { label:'Full Body A â Force', exos: filtSafe(filtLevel(['squat','bench','row_barre','ohp','curl_barre']), mat) },
      full_b:  { label:'Full Body B â Force', exos: filtSafe(filtLevel(['deadlift','incline_bench','lat_pull','elev_lat','tri_cable']), mat) },
      sbd:     { label:'SBD Technique', exos: filtSafe(['squat','bench','deadlift'], mat) },
      faibles: { label:'Points Faibles', exos: filtSafe(filtLevel(['elev_lat','face_pull','crunch','mollet','russian_twist']), mat) },
    },
    masse: {
      push:    { label:'Push â Volume', exos: filtSafe(filtLevel(['bench_halt','incline_bench','ecarte','dips_pec','tri_cable','elev_lat']), mat) },
      pull:    { label:'Pull â Volume', exos: filtSafe(filtLevel(['row_halt','lat_pull','traction','face_pull','curl_halt','shrug']), mat) },
      legs:    { label:'Jambes â Volume', exos: filtSafe(filtLevel(['leg_press','leg_curl','fente','hip_thrust','mollet','leg_ext']), mat) },
      full_a:  { label:'Full Body A â Volume', exos: filtSafe(filtLevel(['bench_halt','squat','row_halt','ohp_halt','curl_halt']), mat) },
      full_b:  { label:'Full Body B â Volume', exos: filtSafe(filtLevel(['incline_bench','rdl','lat_pull','elev_lat','tri_cable']), mat) },
      upper:   { label:'Upper Body', exos: filtSafe(filtLevel(['bench_halt','row_halt','ohp_halt','lat_pull','elev_lat','curl_halt']), mat) },
      lower:   { label:'Lower Body', exos: filtSafe(filtLevel(['squat','leg_press','rdl','leg_curl','hip_thrust','mollet']), mat) },
    },
    seche: {
      push:    { label:'Push + Cardio', exos: filtSafe(filtLevel(['bench_halt','incline_bench','pompe','tri_cable','cardio_hiit']), mat) },
      pull:    { label:'Pull + Cardio', exos: filtSafe(filtLevel(['row_halt','traction','lat_pull','curl_halt','cardio_liss']), mat) },
      legs:    { label:'Jambes + Cardio', exos: filtSafe(filtLevel(['squat','rdl','leg_press','fente','cardio_hiit']), mat) },
      full_a:  { label:'Full Body + HIIT', exos: filtSafe(filtLevel(['squat','pompe','rowing_inv','crunch','cardio_hiit']), mat) },
      cardio:  { label:'Cardio actif', exos: filtSafe(['cardio_hiit','cardio_liss','planche','crunch'], mat) },
    },
    recompo: {
      push:    { label:'Push (Recompo)', exos: filtSafe(filtLevel(['bench_halt','ohp_halt','ecarte','dips_pec','tri_cable']), mat) },
      pull:    { label:'Pull (Recompo)', exos: filtSafe(filtLevel(['traction','row_halt','lat_pull','curl_halt','face_pull']), mat) },
      legs:    { label:'Jambes (Recompo)', exos: filtSafe(filtLevel(['squat','rdl','leg_press','hip_thrust','mollet']), mat) },
      full_a:  { label:'Full Body A', exos: filtSafe(filtLevel(['squat','bench_halt','row_halt','crunch','planche']), mat) },
      full_b:  { label:'Full Body B', exos: filtSafe(filtLevel(['rdl','ohp_halt','traction','planche','russian_twist']), mat) },
      cardio:  { label:'Cardio modÃĐrÃĐ', exos: filtSafe(['cardio_liss','planche','crunch'], mat) },
    },
    maintien: {
      full_a:  { label:'Full Body A', exos: filtSafe(filtLevel(['squat','bench_halt','row_halt','ohp_halt','crunch']), mat) },
      full_b:  { label:'Full Body B', exos: filtSafe(filtLevel(['rdl','pompe','traction','elev_lat','planche']), mat) },
      full_c:  { label:'Full Body C', exos: filtSafe(filtLevel(['fente','incline_bench','lat_pull','crunch','cardio_liss']), mat) },
      cardio:  { label:'Cardio + MobilitÃĐ', exos: filtSafe(['cardio_liss','planche','russian_twist'], mat) },
    },
    reprise: {
      full_a:  { label:'Full Body Doux A', exos: filtSafe(['pompe','rowing_inv','planche','mollet','crunch'], mat) },
      full_b:  { label:'Full Body Doux B', exos: filtSafe(['leg_press','ohp_halt','lat_pull','crunch','planche'], mat) },
      cardio:  { label:'Cardio lÃĐger', exos: filtSafe(['cardio_liss','planche'], mat) },
    },
    bien_etre: {
      full_a:  { label:'Full Body Doux', exos: filtSafe(filtLevel(['pompe','rowing_inv','planche','pilates_bridge','crunch']), mat) },
      full_b:  { label:'Full Body ÃquilibrÃĐ', exos: filtSafe(filtLevel(['leg_press','ohp_halt','lat_pull','pilates_rollup','planche']), mat) },
      mobility:{ label:'MobilitÃĐ & RÃĐcupÃĐration', exos: filtSafe(['yoga_downdog','mobility_hip_flexor','mobility_thoracic','pilates_cat_cow','mobility_hamstring','yoga_child_pose','mobility_world_greatest'], mat) },
      pilates: { label:'Pilates â Core & StabilitÃĐ', exos: filtSafe(['pilates_hundred','pilates_rollup','pilates_bridge','pilates_swimming','pilates_teaser','pilates_mermaid','pilates_side_kick'], mat) },
      stretching:{ label:'Ãtirements Complets', exos: filtSafe(['mobility_hip_flexor','mobility_hamstring','mobility_pec_stretch','mobility_90_90','yoga_pigeon','yoga_downdog','mobility_shoulder_dislocate'], mat) },
      cardio:  { label:'Cardio Doux', exos: filtSafe(['cardio_liss','planche'], mat) },
    }
  };
  // Add shared mobility/pilates/stretching blocs to all goals
  var _sharedMobility = { label:'MobilitÃĐ & RÃĐcupÃĐration', exos: filtSafe(['yoga_downdog','mobility_hip_flexor','mobility_thoracic','pilates_cat_cow','mobility_hamstring','yoga_child_pose','mobility_world_greatest'], mat) };
  var _sharedPilates = { label:'Pilates â Core & StabilitÃĐ', exos: filtSafe(['pilates_hundred','pilates_rollup','pilates_bridge','pilates_swimming','pilates_teaser','pilates_mermaid','pilates_side_kick'], mat) };
  var _sharedStretching = { label:'Ãtirements Complets', exos: filtSafe(['mobility_hip_flexor','mobility_hamstring','mobility_pec_stretch','mobility_90_90','yoga_pigeon','yoga_downdog','mobility_shoulder_dislocate'], mat) };
  for (var _bk in B) { if (!B[_bk].mobility) B[_bk].mobility = _sharedMobility; if (!B[_bk].pilates) B[_bk].pilates = _sharedPilates; if (!B[_bk].stretching) B[_bk].stretching = _sharedStretching; }

  const Bg = B[g1] || B.maintien;

  // ââ Split intelligent basÃĐ sur frÃĐquence, objectif et niveau ââ
  // Chaque muscle entraÃŪnÃĐ 2Ã/sem minimum (pas de bro-split)
  // Sources : NSCA, Stronger by Science, meta-analyses 2024-2025
  function getSplitForFrequency(f, isPL, isPB, lvl) {
    if (f <= 2) return 'full_body';
    if (f === 3) return lvl === 'debutant' ? 'full_body' : 'upper_lower_alt';
    if (f === 4) {
      if (isPL) return 'powerlifting_4';
      if (isPB) return 'powerbuilding_4';
      return 'upper_lower';
    }
    if (f === 5) {
      if (isPL) return 'powerlifting_5';
      if (isPB) return 'powerbuilding_5';
      return 'ppl_ul';
    }
    if (f >= 6) {
      if (isPL) return 'powerlifting_6';
      if (isPB) return 'powerbuilding_6';
      return 'ppl_x2';
    }
    return 'upper_lower';
  }

  // Powerlifting-specific blocks (SBD chaque lift 2Ã/sem)
  const plBlocks = {
    squat_acc:  { label:'Squat + Accessoires', exos: filtSafe(filtLevel(['squat','leg_press','rdl','leg_curl','mollet']), mat) },
    bench_acc:  { label:'Bench + Accessoires', exos: filtSafe(filtLevel(['bench','incline_bench','ecarte','tri_cable','elev_lat']), mat) },
    dead_acc:   { label:'Deadlift + Accessoires', exos: filtSafe(filtLevel(['deadlift','row_barre','lat_pull','face_pull','curl_barre']), mat) },
    bench2_sq:  { label:'Bench 2 + Squat lÃĐger', exos: filtSafe(filtLevel(['bench_halt','ohp','squat','elev_lat','tri_cable']), mat) },
    squat2:     { label:'Squat 2', exos: filtSafe(filtLevel(['squat','leg_press','hip_thrust','leg_curl','mollet']), mat) },
    bench2:     { label:'Bench 2', exos: filtSafe(filtLevel(['bench_halt','incline_bench','dips_pec','tri_cable','elev_lat']), mat) },
    dead2_acc:  { label:'Deadlift 2 + Accessoires', exos: filtSafe(filtLevel(['deadlift','row_halt','traction','face_pull','curl_halt']), mat) },
    accessoires:{ label:'Accessoires', exos: filtSafe(filtLevel(['elev_lat','face_pull','curl_barre','tri_cable','crunch','mollet']), mat) },
  };

  // Powerbuilding-specific blocks (Gemini v200 â Ready for Prod)
  // Refonte complÃĻte : compound prioritaire, gainage fonctionnel, ÃĐquilibre antago/protag
  var pbBlocks = {
    // BLOC 1 â Squat Force/Hypertrophie : Presse pieds bas remplace Hack Squat post-Squat lourd
    sq_hyp:    { label:'Squat â Force & Volume',     exos: filtSafe(filtLevel(['squat','leg_press','leg_ext','mollet_presse','planche']), mat) },
    // BLOC 2 â Bench Force/Hypertrophie : santÃĐ ÃĐpaules (face_pull) crucial Ã  140kg+
    bench_hyp: { label:'Bench â Force & Volume',     exos: filtSafe(filtLevel(['bench','rowing_poulie','dips','face_pull','tri_cable']), mat) },
    // BLOC 3 â Deadlift Force/Hypertrophie : Squat Pause en position 2 (technical), leg_curl ajoutÃĐ
    // RelevÃĐ de Jambes retirÃĐ â flexion lombaire post-Dead = risque hernie discale (Gemini)
    dead_hyp:  { label:'Deadlift â Force & Volume',  exos: filtSafe(filtLevel(['deadlift','squat_pause','lat_pull','leg_curl','face_pull']), mat) },
    // BLOC 4 â Bench Volume/Variation : angle diffÃĐrent (incline + larsen) â  Bench barre J1
    bench2_hyp:{ label:'Bench 2 â Volume',           exos: filtSafe(filtLevel(['incline_bench','larsen_press','row_halt','elev_lat','curl_barre']), mat) },
    // BLOC 5 spec â SBD Technique/Vitesse (spÃĐcialisation quad si ratio S/B < 1.20)
    sq2_spec:  { label:'SBD â Technique & Vitesse',  exos: filtSafe(filtLevel(['squat','bench','speed_deadlift','leg_ext']), mat) },
    // BLOC 5 standard â Squat 2 sans spÃĐcialisation : Fentes ICI (pas dans sq_hyp)
    sq2_hyp:   { label:'Squat 2 â Volume Jambes',    exos: filtSafe(filtLevel(['squat','leg_press','leg_ext','fentes','mollet']), mat) },
    // BLOC 6 â RÃĐcupÃĐration active (6ÃĻme jour optionnel, non-systÃĐmique)
    recovery_day: { label:'RÃĐcupÃĐration Active',     exos: filtSafe(filtLevel(['face_pull','bird_dog','relevÃĐ_jambes','planche']), mat) },
    // Pull â gardÃĐ pour compatibilitÃĐ splits 6j (ne plus router par dÃĐfaut)
    pull_hyp:  { label:'Pull â Volume',              exos: filtSafe(filtLevel(['row_halt','lat_pull','traction','face_pull','curl_halt']), mat) },
  };

  // v201 â Phase-adaptive pbBlocks : exercices adaptÃĐs Ã  la phase courante macrocycle
  // Force/Intensification â Squat Pause + Close Grip Bench (technique spÃĐcifique SBD)
  // Peak â Volume rÃĐduit, exercices haute intensitÃĐ neuro uniquement
  // v216 â lire currentBlock.phase d'abord (canonical aprÃĻs generateWeeklyPlan),
  // fallback wpDetectPhase(), fallback 'hypertrophie' (jamais null)
  var _pbPhase = (typeof db !== 'undefined' && db && db.weeklyPlan && db.weeklyPlan.currentBlock && db.weeklyPlan.currentBlock.phase)
    || (typeof wpDetectPhase === 'function' ? wpDetectPhase() : null)
    || 'hypertrophie';
  if (_pbPhase === 'force' || _pbPhase === 'intensification') {
    pbBlocks.sq_hyp = { label:'Squat â Force',
      exos: filtSafe(filtLevel(['squat','squat_pause','leg_press','leg_ext','planche']), mat) };
    pbBlocks.bench_hyp = { label:'Bench â Force',
      exos: filtSafe(filtLevel(['bench','close_grip_bench','rowing_poulie','dips','face_pull']), mat) };
  }
  if (_pbPhase === 'peak') {
    pbBlocks.sq_hyp = { label:'Squat â Intensification',
      exos: filtSafe(filtLevel(['squat','squat_pause','leg_ext','planche']), mat) };
  }

  // ââ FATIGUE-BASED EXERCISE SELECTION (Gemini Next Big Feature) âââââââââââ
  // ACWR > 1.3 â remplacer Squat barre (axial lourd) par Leg Press (axial lÃĐger)
  var _acwrPB = typeof computeACWR === 'function' ? computeACWR() : null;
  if (isPB && _acwrPB && _acwrPB > 1.3) {
    pbBlocks.sq_hyp = { label: 'Lower Body â RÃĐcupÃĐration (ACWR ' + _acwrPB.toFixed(2) + ')',
      exos: filtSafe(filtLevel(['leg_press','rdl','hip_thrust','leg_curl','mollet']), mat) };
    pbBlocks.sq2_spec = { label: 'Lower Volume â RÃĐcupÃĐration',
      exos: filtSafe(filtLevel(['leg_press','leg_ext','hip_thrust','mollet']), mat) };
    pbBlocks.sq2_hyp = { label: 'Lower Volume â RÃĐcupÃĐration',
      exos: filtSafe(filtLevel(['leg_press','leg_ext','hip_thrust','mollet']), mat) };
    if (typeof db !== 'undefined' && db) {
      db.weeklyPlan = db.weeklyPlan || {};
      db.weeklyPlan.coachNotes = db.weeklyPlan.coachNotes || [];
      db.weeklyPlan.coachNotes.push(
        'ACWR ' + _acwrPB.toFixed(2) + ' > 1.3 â Squat remplacÃĐ par Leg Press (charge axiale rÃĐduite)'
      );
    }
  }

  // ââ ANALYSE BIOMÃCANIQUE â ratio antagonistes ââââââââââââââââââââââââââââ
  var bestPR = (typeof db !== 'undefined' && db && db.bestPR) || {};
  var prSq   = parseFloat(bestPR.squat) || 0;
  var prBn   = parseFloat(bestPR.bench) || 0;
  var squatBenchRatio = prBn > 0 ? prSq / prBn : 1.20;
  var needsSquatSpec  = squatBenchRatio < 1.20 && level === 'avance' && isPB;
  var _ratioNote = needsSquatSpec
    ? 'SpÃĐcialisation Squat activÃĐe (ratio ' + squatBenchRatio.toFixed(2) + ' < 1.20)'
    : null;

  // Map split â sÃĐquence de blocs
  function getSplitSequence(splitType, f) {
    switch (splitType) {
      case 'full_body':
        if (f === 1) return [Bg.full_a];
        if (f === 2) return [Bg.full_a, Bg.full_b];
        return [Bg.full_a, Bg.full_b, Bg.full_a || Bg.full_c]; // 3j FB
      case 'upper_lower_alt':
        // 3j : U/L/U puis semaine suivante L/U/L (on fait U/L/U pour la gÃĐnÃĐration)
        return [Bg.upper || Bg.push, Bg.lower || Bg.legs, Bg.upper || Bg.pull];
      case 'upper_lower':
        // 4j : U/L/U/L
        return [Bg.upper || Bg.push, Bg.lower || Bg.legs, Bg.upper || Bg.pull, Bg.lower || Bg.legs];
      case 'ppl_ul':
        // 5j : PPL + U/L
        return [Bg.push, Bg.pull, Bg.legs, Bg.upper || Bg.push, Bg.lower || Bg.legs];
      case 'ppl_x2':
        // 6j : PPL Ã 2
        return [Bg.push, Bg.pull, Bg.legs, Bg.push, Bg.pull, Bg.legs];
      case 'powerlifting_4':
        return [plBlocks.squat_acc, plBlocks.bench_acc, plBlocks.dead_acc, plBlocks.bench2_sq];
      case 'powerlifting_5':
        return [plBlocks.squat_acc, plBlocks.bench_acc, plBlocks.dead_acc, plBlocks.squat2, plBlocks.bench2];
      case 'powerlifting_6':
        return [plBlocks.squat_acc, plBlocks.bench_acc, plBlocks.dead_acc, plBlocks.squat2, plBlocks.bench2, plBlocks.dead2_acc];
      case 'powerbuilding_4':
        return [pbBlocks.sq_hyp, pbBlocks.bench_hyp, pbBlocks.dead_hyp, pbBlocks.bench2_hyp];
      case 'powerbuilding_5':
        return [pbBlocks.sq_hyp, pbBlocks.bench_hyp, pbBlocks.dead_hyp, pbBlocks.bench2_hyp,
                needsSquatSpec ? pbBlocks.sq2_spec : pbBlocks.sq2_hyp];
      case 'powerbuilding_6':
        return [pbBlocks.sq_hyp, pbBlocks.bench_hyp, pbBlocks.dead_hyp, pbBlocks.bench2_hyp,
                needsSquatSpec ? pbBlocks.sq2_spec : pbBlocks.sq2_hyp, pbBlocks.pull_hyp];
      default:
        return [Bg.full_a];
    }
  }

  // Bien-ÃŠtre et modes spÃĐciaux gardent leur logique dÃĐdiÃĐe
  const specialSequences = {
    bien_etre:{ 1:[Bg.full_a],2:[Bg.full_a,Bg.mobility],3:[Bg.full_a,Bg.mobility,Bg.full_b],4:[Bg.full_a,Bg.pilates,Bg.full_b,Bg.mobility],5:[Bg.full_a,Bg.pilates,Bg.full_b,Bg.stretching,Bg.cardio],6:[Bg.full_a,Bg.pilates,Bg.full_b,Bg.stretching,Bg.cardio,Bg.mobility] },
    seche:    { 1:[Bg.full_a],2:[Bg.full_a,Bg.cardio],3:[Bg.full_a,Bg.cardio,Bg.full_a],4:[Bg.push,Bg.pull,Bg.legs,Bg.cardio],5:[Bg.push,Bg.pull,Bg.legs,Bg.cardio,Bg.full_a],6:[Bg.push,Bg.pull,Bg.legs,Bg.cardio,Bg.full_a,Bg.cardio] },
    reprise:  { 1:[Bg.full_a],2:[Bg.full_a,Bg.full_b],3:[Bg.full_a,Bg.cardio,Bg.full_b],4:[Bg.full_a,Bg.cardio,Bg.full_b,Bg.mobility],5:[Bg.full_a,Bg.cardio,Bg.full_b,Bg.mobility,Bg.full_a],6:[Bg.full_a,Bg.cardio,Bg.full_b,Bg.mobility,Bg.full_a,Bg.cardio] },
    maintien: { 1:[Bg.full_a],2:[Bg.full_a,Bg.full_b],3:[Bg.full_a,Bg.full_b,Bg.full_c],4:[Bg.full_a,Bg.full_b,Bg.full_c,Bg.cardio],5:[Bg.full_a,Bg.full_b,Bg.full_c,Bg.cardio,Bg.mobility],6:[Bg.full_a,Bg.full_b,Bg.full_c,Bg.cardio,Bg.mobility,Bg.full_a] },
  };

  let seq;
  if (specialSequences[g1]) {
    seq = specialSequences[g1][Math.min(freq, 6)] || [Bg.full_a];
  } else {
    const splitType = getSplitForFrequency(Math.min(freq, 6), isPL, isPB, level);
    seq = getSplitSequence(splitType, Math.min(freq, 6));
  }

  // Audit trail : note de spÃĐcialisation injectÃĐe par le ratio
  if (_ratioNote) {
    if (typeof db !== 'undefined' && db) {
      db.weeklyPlan = db.weeklyPlan || {};
      db.weeklyPlan.coachNotes = db.weeklyPlan.coachNotes || [];
      db.weeklyPlan.coachNotes.push(_ratioNote);
    }
  }

  const plan = [];
  const allDays = ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi','Dimanche'];

  allDays.forEach(day => {
    const tIdx = trainingDays.indexOf(day);
    if (tIdx >= 0 && seq[tIdx]) {
      const bloc = seq[tIdx];
      const exosWithSets = (bloc.exos||[]).map(id => ({
        id,
        setsReps: getSetsReps(id, level, g1)
      }));
      // Cardio intÃĐgrÃĐ : ajouter cardio_liss Ã  la fin si option choisie et pas dÃĐjÃ  lÃ 
      if (cardio === 'integre' && !bloc.label.toLowerCase().includes('cardio') && !exosWithSets.some(e=>e.id==='cardio_liss'||e.id==='cardio_hiit')) {
        exosWithSets.push({ id:'cardio_liss', setsReps:'15min' });
      }
      plan.push({ day, label: bloc.label, exos: exosWithSets.map(e=>e.id), exosSets: exosWithSets, isRest: false, isCardio: bloc.label.toLowerCase().includes('cardio') });
    } else if (cardio === 'dedie' && !trainingDays.includes(day) && day !== 'Dimanche') {
      // Jours de repos â cardio lÃĐger dÃĐdiÃĐ
      plan.push({ day, label:'Cardio lÃĐger', exos:['cardio_liss','planche'], exosSets:[{id:'cardio_liss',setsReps:'30â40min'},{id:'planche',setsReps:'3Ã60s'}], isRest: false, isCardio: true });
    } else {
      plan.push({ day, label:'Repos', exos:[], exosSets:[], isRest:true });
    }
  });

  // CompÃĐtition : ajouter bloc info peak si date renseignÃĐe
  if (compDate) {
    const weeksOut = Math.round((new Date(compDate) - Date.now()) / 604800000);
    plan._compInfo = { date: compDate, weeksOut, type: compType };
  }
  plan._levelNote = lp.note;
  plan._level = level;
  if (_ratioNote) plan._ratioNote = _ratioNote;

  return plan;
}

function selectFreq(f) {
  obFreq = f;
  obSelectedDays = [];
  document.querySelectorAll('.ob-freq-btn').forEach(function(b, i) { b.classList.toggle('selected', i+1 === f); });
  if (document.getElementById('ob-days-grid')) renderDayPicker();
}

function renderDayPicker() {
  const grid = document.getElementById('ob-days-grid');
  const sub  = document.getElementById('ob-days-needed');
  if (sub) sub.textContent = obFreq;
  document.getElementById('ob-days-hint').textContent = '';

  const shorts = ['Lun','Mar','Mer','Jeu','Ven','Sam','Dim'];
  grid.innerHTML = DAYS_FULL.map((day, i) => {
    const sel = obSelectedDays.includes(day);
    return '<div class="ob-day-pick'+(sel?' selected':'')+'" data-day="'+day+'" onclick="toggleDayPick(\''+day+'\')">'+
      '<div class="dp-short">'+shorts[i]+'</div>'+
      '<div class="dp-full">'+day.substring(0,3)+'</div></div>';
  }).join('');
}

function toggleDayPick(day) {
  const hint = document.getElementById('ob-days-hint');
  if (obSelectedDays.includes(day)) {
    obSelectedDays = obSelectedDays.filter(d => d !== day);
  } else {
    if (obSelectedDays.length >= obFreq) {
      hint.textContent = 'Tu as dÃĐjÃ  sÃĐlectionnÃĐ ' + obFreq + ' jour(s). Retire-en un d\'abord.';
      return;
    }
    // Maintain week order
    const order = DAYS_FULL;
    obSelectedDays.push(day);
    obSelectedDays.sort((a, b) => order.indexOf(a) - order.indexOf(b));
  }
  hint.textContent = obSelectedDays.length === obFreq ? 'â Parfait !' :
    'Encore ' + (obFreq - obSelectedDays.length) + ' jour(s) Ã  sÃĐlectionner';
  renderDayPicker();
}

function selectMat(m) {
  obMat = m;
  document.querySelectorAll('.ob-mat-btn').forEach(b => b.classList.remove('selected'));
  event.currentTarget.classList.add('selected');
}

function autoPopulateKeyLifts() {
  if (db.keyLifts && db.keyLifts.length > 0) return; // dÃĐjÃ  configurÃĐs

  const lifts = [];

  // PrioritÃĐ 1 : exercices par dÃĐfaut du mode actif
  const modeDefaults = modeFeature('defaultKeyLifts') || [];
  if (modeDefaults.length > 0) {
    modeDefaults.forEach(name => {
      lifts.push({ name, target: 0 });
    });
  }

  // PrioritÃĐ 1b : exercices SBD si mode SBD et renseignÃĐs pendant l'onboarding
  if (modeFeature('showSBDCards') && lifts.length === 0) {
    const SBD_DEFAULTS = [
      { key: 'bench',    name: 'Bench Press (Barre)', targetKey: 'bench' },
      { key: 'squat',    name: 'Squat (Barre)',        targetKey: 'squat' },
      { key: 'deadlift', name: 'SoulevÃĐ de Terre',     targetKey: 'deadlift' }
    ];
    SBD_DEFAULTS.forEach(({ key, name, targetKey }) => {
      if ((db.bestPR[key] || 0) > 0 || (db.user.targets[targetKey] || 0) > 0) {
        lifts.push({ name, target: db.user.targets[targetKey] || 0 });
      }
    });
  }

  // PrioritÃĐ 2 : exercices du programme gÃĐnÃĐrÃĐ (si pas de SBD)
  if (lifts.length === 0 && db.generatedProgram) {
    const seen = new Set();
    for (const day of db.generatedProgram) {
      if (day.isRest || day.isCardio || day._compInfo) continue;
      const exos = day.exosSets || (day.exos || []).map(id => ({ id }));
      for (const e of exos) {
        const exo = EXO_DB[e.id];
        if (exo && !seen.has(exo.name) && seen.size < 4) {
          seen.add(exo.name);
          lifts.push({ name: exo.name, target: 0 });
        }
      }
      if (seen.size >= 4) break;
    }
  }

  // PrioritÃĐ 3 : exercices du programme importÃĐ manuellement
  if (lifts.length === 0 && db.routineExos) {
    const seen = new Set();
    for (const day of DAYS_FULL) {
      const exos = getProgExosForDay(day);
      for (const name of exos) {
        if (!seen.has(name) && seen.size < 4 && name) {
          seen.add(name);
          lifts.push({ name, target: 0 });
        }
      }
      if (seen.size >= 4) break;
    }
  }

  if (lifts.length > 0) {
    db.keyLifts = lifts.slice(0, 6);
  }
}

function obFinish() {
  var _medEl = document.getElementById('ob-medical-consent');
  if (_medEl && !_medEl.checked) {
    showToast('â ïļ Veuillez confirmer votre aptitude mÃĐdicale pour continuer');
    return;
  }
  if (_medEl) {
    db.user.medicalConsent = true;
    db.user.medicalConsentDate = new Date().toISOString();
  }
  db.user.onboarded = true;
  db.user.onboardingVersion = ONBOARDING_VERSION;
  if (!db.user.onboardingDate) db.user.onboardingDate = new Date().toISOString().split('T')[0];
  // Persist selectedDays into programParams â engine reads from here, not from the closure.
  if (Array.isArray(obSelectedDays) && obSelectedDays.length) {
    if (!db.user.programParams) db.user.programParams = {};
    db.user.programParams.selectedDays = obSelectedDays.slice();
  }
  if (typeof validateUserLevel === 'function') validateUserLevel();
  autoPopulateKeyLifts();
  saveDB();
  hideOnboarding();
  refreshUI();
  renderProgramViewer();
  showToast('Bienvenue ' + (db.user.name||'') + ' ! ð');
  // Bypass magicStart si le programme a dÃĐjÃ  ÃĐtÃĐ gÃĐnÃĐrÃĐ + dÃĐclencher le swipe
  // (Gemini : "Instant Value â jamais bloquer avant de montrer le programme")
  var _hasPlan = !!(db.weeklyPlan && db.weeklyPlan.days && db.weeklyPlan.days.length);
  var _isPowerlifting = db.user && db.user.trainingMode === 'powerlifting';
  if (_hasPlan && !db._magicStartDone) {
    db._magicStartDone = true;
    saveDB();
  }
  if (!db._magicStartDone) {
    setTimeout(showMagicStart, 400);
  }
  if (_hasPlan && !_isPowerlifting && !db.user._swipeCompleted) {
    setTimeout(function() {
      try { renderSwipeOnboarding(); } catch (e) {
        if (typeof logErrorToSupabase === 'function') logErrorToSupabase('render_crash', String(e && e.message || e), 'renderSwipeOnboarding');
      }
    }, 800);
  }
  // EnchaÃŪner l'onboarding social si user connectÃĐ et pas encore de pseudo
  setTimeout(async function() {
    var isLoggedIn = false;
    try {
      if (typeof supaClient !== 'undefined' && supaClient) {
        var session = await supaClient.auth.getSession();
        isLoggedIn = !!(session && session.data && session.data.session);
      }
    } catch(e) {}
    if (isLoggedIn && (!db.social || !db.social.onboardingCompleted)) {
      if (typeof showSocialOnboarding === 'function') showSocialOnboarding();
    }
  }, 500);
}

