// ââ VERSION DE L'APP (servie par le SW actif) ââââââââââââââââââââââââââââââââ
// Source de vÃĐritÃĐ = service worker ACTIF (CACHE_NAME), pas la constante JS
// Version du SW : la vÃĐritÃĐ vient du SW ACTIF (CACHE_NAME live), interrogÃĐ via
// MessageChannel. Helpers purs (testÃĐs) + accesseur mÃĐmoÃŊsÃĐ getSWVersion().

// 'trainhub-v291' â 'v291'. Pur.
function _appVersionLabel(cacheName) {
  var m = String(cacheName || '').match(/v\d[\w.]*/i);
  return m ? m[0] : '';
}

// Ãtat de mise Ã  jour depuis un registration : un SW en attente â MAJ prÃŠte. Pur.
function _swUpdateState(reg) {
  return { available: !!(reg && reg.waiting) };
}

// Demande sa version au SW ACTIF (controller) via MessageChannel. RÃĐsout Ã  null si
// pas de SW contrÃīleur / pas de rÃĐponse (ancien SW sans handler, dev, navigation privÃĐe).
function _querySWVersion(timeoutMs) {
  return new Promise(function(resolve) {
    try {
      var ctrl = (typeof navigator !== 'undefined' && navigator.serviceWorker)
        ? navigator.serviceWorker.controller : null;
      if (!ctrl || typeof MessageChannel === 'undefined') { resolve(null); return; }
      var mc = new MessageChannel();
      var settled = false;
      var t = setTimeout(function() { if (!settled) { settled = true; resolve(null); } }, timeoutMs || 1500);
      mc.port1.onmessage = function(ev) {
        if (settled) return;
        settled = true; clearTimeout(t);
        resolve((ev.data && ev.data.version) ? ev.data.version : null);
      };
      ctrl.postMessage({ type: 'GET_VERSION' }, [mc.port2]);
    } catch (e) { resolve(null); }
  });
}

// AccÃĻs mÃĐmoÃŊsÃĐ Ã  la version live du SW (CACHE_NAME) â source unique de version
// cÃītÃĐ app. RÃĐsout au littÃĐral 'trainhub-vNNN' du SW actif, ou null (dev/privÃĐ/
// pas de contrÃīleur). Met en cache _swLiveVersion pour les appels suivants.
function getSWVersion() {
  if (_swLiveVersion) return Promise.resolve(_swLiveVersion);
  return _querySWVersion(1500).then(function(v) { if (v) _swLiveVersion = v; return v || null; });
}

// Active le SW en attente sur tap â controllerchange (listener index.html) â reload.
function _swApplyUpdate() {
  if (typeof navigator === 'undefined' || !('serviceWorker' in navigator)) { location.reload(); return; }
  navigator.serviceWorker.getRegistration().then(function(reg) {
    if (reg && reg.waiting) reg.waiting.postMessage({ type: 'SKIP_WAITING' });
    else location.reload();
  }).catch(function() { location.reload(); });
}

function renderAppVersionLine() {
  var el = document.getElementById('appVersionLine');
  if (!el) return;

  // Plus de littÃĐral figÃĐ : quand aucune version servie n'est disponible, on
  // affiche un ÃĐtat honnÃŠte ('en cours de dÃĐtection' / 'non disponible') plutÃīt
  // qu'un numÃĐro pÃĐrimÃĐ. La seule source de version = le SW actif (CACHE_NAME live).
  function paint(servedLabel, reg, swSupported) {
    var html = 'SBD Hub';
    if (servedLabel) {
      html += ' Â· ' + _appVersionLabel(servedLabel);
      if (_swUpdateState(reg).available) {
        html += ' Â· <span style="color:var(--orange);font-weight:700;">nouvelle version prÃŠte</span>'
          + ' <button onclick="_swApplyUpdate()" style="margin-left:6px;background:var(--accent);'
          + 'color:#fff;border:none;border-radius:8px;padding:3px 10px;font-size:11px;font-weight:700;cursor:pointer;">Mettre Ã  jour</button>';
      } else {
        html += ' Â· Ã  jour';
      }
    } else if (swSupported) {
      html += ' Â· version en cours de dÃĐtectionâĶ';
    } else {
      html += ' Â· version non disponible';
    }
    el.innerHTML = html;
  }

  var hasSW = (typeof navigator !== 'undefined') && ('serviceWorker' in navigator)
    && !!navigator.serviceWorker.getRegistration;
  if (!hasSW) { paint(null, null, false); return; }
  navigator.serviceWorker.getRegistration().then(function(reg) {
    _querySWVersion(1500).then(function(v) { if (v) _swLiveVersion = v; paint(v, reg || null, true); });
  }).catch(function() {
    _querySWVersion(1500).then(function(v) { if (v) _swLiveVersion = v; paint(v, null, true); });
  });
}

