function _buildCollectorBadges(b) {
  const _nonColBadges = b.filter(x => !x.impossible);
  const _nonColCount = _nonColBadges.filter(x => x.ck()).length;
  function _colCount(threshold) {
    let count = _nonColCount;
    if (count >= 5) count++;
    if (count >= 15) count++;
    if (count >= 30) count++;
    if (count >= 50) count++;
    if (count >= 75) count++;
    if (count >= 100) count++;
    return count >= threshold;
  }
  const totalNormal = _nonColBadges.length + 7;
  b.push({id:'col5',    r:'common',    icon:'ð', name:'Premier Inventaire',      desc:'5 badges â ton inventaire commence Ã  se remplir d\'histoire', condition:'5 badges', ck:()=>_colCount(5)});
  b.push({id:'col15',   r:'uncommon',  icon:'ð', name:'Collectionneur de Gloire', desc:'15 badges â tu accumules les exploits comme un guerrier accompli', condition:'15 badges', ck:()=>_colCount(15)});
  b.push({id:'col30',   r:'rare',      icon:'ðš', name:'Chasseur de TrophÃĐes',    desc:'30 badges â les vitrines ne suffisent plus Ã  tout exposer', condition:'30 badges', ck:()=>_colCount(30)});
  b.push({id:'col50',   r:'epic',      icon:'ð', name:'Archiviste de l\'ArÃĻne',  desc:'50 badges â les grands archivistes t\'envient profondÃĐment', condition:'50 badges', ck:()=>_colCount(50)});
  b.push({id:'col75',   r:'legendary', icon:'ðĄïļ', name:'Gardien de Panoplie',     desc:'75 badges â ta panoplie lÃĐgendaire fait pÃĒlir tous les marchands', condition:'75 badges', ck:()=>_colCount(75)});
  b.push({id:'col100',  r:'mythic',    icon:'ð', name:'Arsenal Absolu',          desc:'100 badges â chaque badge est une arme supplÃĐmentaire dans ton arsenal', condition:'100 badges', ck:()=>_colCount(100)});
  b.push({id:'col_all', r:'divine',    icon:'ð', name:'ComplÃĐtionniste Divin',   desc:'Tous les badges â tu as tout accompli. LÃĐgende absolue de l\'arÃĻne', condition:'Tous les badges', ck:()=>{ let c=_nonColCount; [5,15,30,50,75,100].forEach(function(t){if(c>=t)c++;}); return c>=totalNormal; }});
}

