    // Dos lombaires
    'extension do machine':          'hyperextension',
    'back extension':                'hyperextension',
    // Leg curl / hamstrings
    'leg curl assi':                 'leg_curl_seated',
    'leg curl':                      'leg_curl_seated',
    'leg curl couche':               'leg_curl_lying',
    // Hip thrust
    'hip thrust machine':            'hip_thrust_barbell',
