const BODYWEIGHT_FALLBACK = {
  A: 1,
  B: 3,
  C: 5,
};

// Valeurs par dÃĐfaut pour exercices poids de corps sans donnÃĐes saisies.
// UtilisÃĐes uniquement en fallback quand l'utilisateur n'a pas entrÃĐ reps/durÃĐe.
const BW_DEFAULT_REPS = 10;       // reps moyennes (tractions, pompes, dipsâĶ)
const BW_DEFAULT_ISO_SECS = 45;   // durÃĐe isomÃĐtrique type (planche, gainage)
const BW_FALLBACK_KG = 80;        // poids de corps par dÃĐfaut quand l'utilisateur n'a rien saisi

// Source unique de vÃĐritÃĐ du poids de corps pour les niveaux de force.
// PrioritÃĐ : db.user.bw > bodyWeight > weight > currentWeight > BW_FALLBACK_KG.
function getUserBW() {
  return (db.user && (
    db.user.bw ||
    db.user.bodyWeight ||
    db.user.weight ||
    db.user.currentWeight
  )) || BW_FALLBACK_KG;
}


function _computeSetTonnage(s, bw, bwConfig, exoName) {
  var base = (s.weight || 0) * (s.reps || 0);
  if (base > 0) return base;

  if (s.weight === 0 && s.reps > 0 && exoName) {
    var dbEntry = findExoInDatabase(exoName);
    if (dbEntry && dbEntry.bwRatio) {
      return s.reps * bw * dbEntry.bwRatio;
    }
  }

  var _dbForType = exoName ? findExoInDatabase(exoName) : null;
  var _exoType = _dbForType && _dbForType.trackingType;
  if (_exoType === 'cardio_stairs') {
    var floors = s.floors || 0;
    var durMinFloors = s.duration || 0;
    return (floors * bw * 0.5) + (durMinFloors * bw * 0.8);
  }

  if (s.elevation > 0) {
    var distElev = s.distance || 0;
    var elev = s.elevation || 0;
    return (distElev * bw * 4) + (elev * bw * 0.05);
  }

  var est = 0;
  if (bwConfig) {
    if (bwConfig.type === 'iso') {
      var dur = s.duration || s.time || BW_DEFAULT_ISO_SECS;
      est = dur * bw * bwConfig.factor;
    } else if (bwConfig.type === 'bw') {
      var reps = s.reps || BW_DEFAULT_REPS;
      est = reps * bw * bwConfig.factor;
    } else if (bwConfig.type === 'cardio') {
      var durMin = (s.duration || s.time || 30) / 60;
      est = durMin * bw * bwConfig.factor;
      s._isCardio = true;
    } else if (bwConfig.type === 'cardio_dist') {
      var dist = s.distance || 5;
      est = dist * bw * bwConfig.factor;
      s._isCardio = true;
    } else if (bwConfig.type === 'mobility') {
      var durMin2 = (s.duration || s.time || 30) / 60;
      est = durMin2 * bw * bwConfig.factor;
    }
  } else if (!s.weight || s.weight === 0) {
    est = bw * BODYWEIGHT_FALLBACK.B;
  }
  return est;
}

function getMuscleVolumeAndFreq(logs4weeks) {
  var result = {};
  Object.keys(MUSCLE_TONNAGE_TARGETS).forEach(function(k) {
    result[k] = { tonnage: 0, sessions: 0 };
  });

  logs4weeks.forEach(function(log) {
    var musclesThisSession = {};

    (log.exercises || []).forEach(function(exo) {
      var exoNameLower = (exo.name || '').toLowerCase();

      // 1) Try EXO_DATABASE primary/secondary/tertiary
      var coeffMap = null;
      var dbEntry = findExoInDatabase(exo.name);
      if (dbEntry && dbEntry.muscles &&
          dbEntry.muscles.primary && dbEntry.muscles.primary.length > 0) {
        coeffMap = {};
        var addPlan = function(arr, coeff) {
          (arr || []).forEach(function(k) {
            var granular = MUSCLE_KEY_BRIDGE[k] || k;
            if (coeffMap[granular] == null || coeffMap[granular] < coeff) {
              coeffMap[granular] = coeff;
            }
            var parent = MUSCLE_PARENT_MAP[k] || MUSCLE_PARENT_MAP[granular];
            if (parent && parent !== granular) {
              if (coeffMap[parent] == null || coeffMap[parent] < coeff) {
                coeffMap[parent] = coeff;
              }
            }
          });
        };
        addPlan(dbEntry.muscles.primary,   1.0);
        addPlan(dbEntry.muscles.secondary, 0.4);
        addPlan(dbEntry.muscles.tertiary,  0.15);
      }

      // 2) Fallback on legacy EXERCISE_MUSCLE_MAP
      if (!coeffMap) {
        var mapping = null;
        for (var i = 0; i < EXERCISE_MUSCLE_MAP.length; i++) {
          var m = EXERCISE_MUSCLE_MAP[i];
          for (var j = 0; j < m.match.length; j++) {
            if (exoNameLower.indexOf(m.match[j].toLowerCase()) >= 0) {
              mapping = m;
              break;
            }
          }
          if (mapping) break;
        }
        if (!mapping) return;
        coeffMap = mapping.muscles;
      }

      // Compute exo volume â normal sets only, exclude warmups
      var exoVolume = 0;
      var bw = (db.user && (db.user.bodyWeight || db.user.weight)) || 80;
      var exoNameNorm = wpNormalizeName(exo.name || '');
      var bwConfig = BODYWEIGHT_FACTORS[exoNameNorm];

      if (exo.exoType === 'weight' && exo.allSets && exo.allSets.length > 0) {
        exo.allSets.forEach(function(s) {
          if (s.setType !== 'warmup') {
            exoVolume += _computeSetTonnage(s, bw, bwConfig, exo.name);
          }
        });
      } else if (exo.exoType === 'weight' && exo.series && exo.series.length > 0) {
        // Fallback for legacy logs without allSets
        exo.series.forEach(function(s) {
          if (s.setType !== 'warmup') {
            exoVolume += _computeSetTonnage(s, bw, bwConfig, exo.name);
          }
        });
      } else if (exo.exoType === 'time' || exo.isTime) {
        var nbSets = exo.sets || 0;
        exoVolume = nbSets * 100;
      } else {
        // Fallback allSets vide â utilise bwRatio si disponible
        var nbSetsFb = exo.sets || 3;
        var dbEntryFb = findExoInDatabase(exo.name);
        if (dbEntryFb && dbEntryFb.bwRatio) {
          exoVolume = nbSetsFb * BW_DEFAULT_REPS * bw * dbEntryFb.bwRatio;
        } else if (bwConfig) {
          if (bwConfig.type === 'iso') {
            exoVolume = nbSetsFb * BW_DEFAULT_ISO_SECS * bw * bwConfig.factor;
          } else if (bwConfig.type === 'bw') {
            exoVolume = nbSetsFb * BW_DEFAULT_REPS * bw * bwConfig.factor;
          } else if (bwConfig.type === 'cardio') {
            exoVolume = 0;
          }
        } else {
          exoVolume = nbSetsFb * bw * 3;
        }
      }

      Object.keys(coeffMap).forEach(function(muscleKey) {
        if (!result[muscleKey]) return;
        result[muscleKey].tonnage += exoVolume * coeffMap[muscleKey];
        musclesThisSession[muscleKey] = true;
      });
    });

    Object.keys(musclesThisSession).forEach(function(k) {
      if (result[k]) result[k].sessions += 1;
    });
  });

  return result;
}


function calcAndStoreMuscleRanks(force) {
  try {
    db.gamification = db.gamification || {};
    // Throttle 7j : protÃĻge les renders de tab (calcAndStoreMuscleRanks()),
    // mais pas le boot ni goFinishWorkout (qui appellent avec force=true).
    if (!force && db.gamification.muscleRanks &&
        db.gamification.muscleRanks._computedAt &&
        Date.now() - db.gamification.muscleRanks._computedAt < 7 * 24 * 3600 * 1000) {
      return;
    }

    var now = Date.now();
    var cutoff = now - 28 * 24 * 60 * 60 * 1000;
    var logs4w = (db.logs || []).filter(function(l) {
      return (l.timestamp || 0) >= cutoff;
    });

    var volumeFreq = getMuscleVolumeAndFreq(logs4w);
    var MUSCLE_TIER_THRESHOLDS = [
      { name:'AtrophiÃĐ',   index:0, color:'#555566' },
      { name:'DÃĐveloppÃĐ',  index:1, color:'#7A8C6E' },
      { name:'SculptÃĐ',    index:2, color:'#C8A24C' },
      { name:'Puissant',   index:3, color:'#78D8D0' },
      { name:'Massif',     index:4, color:'#6EB4FF' },
      { name:'Titanesque', index:5, color:'#BF5AF2' }
    ];
    var ranks = {};

    // Coefficient genre par muscle (seuils calibrÃĐs pour un homme de rÃĐfÃĐrence)
    var gender = (db.user && db.user.gender === 'female') ? 'female' : 'male';
    var genderCoeffs = GENDER_MUSCLE_COEFF[gender] || GENDER_MUSCLE_COEFF['male'];

    Object.keys(MUSCLE_TONNAGE_TARGETS).forEach(function(key) {
      var data = volumeFreq[key] || { tonnage: 0, sessions: 0 };
      var raw = MUSCLE_TONNAGE_TARGETS[key];
      var muscleCoeff = genderCoeffs[key] || 0.65;
      var thresholds = {
        atrophie:   getAdaptedTarget(key, 'atrophie'),
        developpe:  getAdaptedTarget(key, 'developpe'),
        sculpte:    getAdaptedTarget(key, 'sculpte'),
        puissant:   getAdaptedTarget(key, 'puissant'),
        massif:     getAdaptedTarget(key, 'massif'),
        titanesque: getAdaptedTarget(key, 'titanesque')
      };

      var tonnage = data.tonnage;
      var tierIndex = 0;
      var scoreInTier = 0;

      if (tonnage >= thresholds.titanesque) {
        tierIndex = 5; scoreInTier = 100;
      } else if (tonnage >= thresholds.massif) {
        tierIndex = 4;
        scoreInTier = Math.round((tonnage - thresholds.massif) /
          (thresholds.titanesque - thresholds.massif) * 100);
      } else if (tonnage >= thresholds.puissant) {
        tierIndex = 3;
        scoreInTier = Math.round((tonnage - thresholds.puissant) /
          (thresholds.massif - thresholds.puissant) * 100);
      } else if (tonnage >= thresholds.sculpte) {
        tierIndex = 2;
        scoreInTier = Math.round((tonnage - thresholds.sculpte) /
          (thresholds.puissant - thresholds.sculpte) * 100);
      } else if (tonnage >= thresholds.developpe) {
        tierIndex = 1;
        scoreInTier = Math.round((tonnage - thresholds.developpe) /
          (thresholds.sculpte - thresholds.developpe) * 100);
      } else {
        tierIndex = 0;
        scoreInTier = thresholds.atrophie > 0 ?
          Math.round(tonnage / thresholds.atrophie * 100) : 0;
      }

      // Score final : 80% volume + 20% frÃĐquence
      var freqScore = Math.min(100, Math.round(
        data.sessions / (MUSCLE_FREQ_TARGETS[key] || 4) * 100
      ));
      var finalScore = Math.min(100, Math.round(scoreInTier * 0.8 + freqScore * 0.2));

      var tier = MUSCLE_TIER_THRESHOLDS[tierIndex];
      ranks[key] = {
        tier: tier.name,
        index: tier.index,
        color: tier.color,
        score: finalScore,
        tonnage: Math.round(tonnage),
        updatedAt: now
      };
    });

    var _tierOrderFix = ['AtrophiÃĐ','DÃĐveloppÃĐ','SculptÃĐ','Puissant','Massif','Titanesque'];
    var _tierColorsFix = {
      'AtrophiÃĐ':'#555566','DÃĐveloppÃĐ':'#7A8C6E',
      'SculptÃĐ':'#C8A24C','Puissant':'#78D8D0',
      'Massif':'#6EB4FF','Titanesque':'#BF5AF2'
    };
    Object.keys(MUSCLE_GROUP_CHILDREN).forEach(function(parent) {
      var children = MUSCLE_GROUP_CHILDREN[parent];
      if (!ranks[parent]) return;
      var maxTierIdx = _tierOrderFix.indexOf(ranks[parent].tier);
      children.forEach(function(child) {
        if (!ranks[child]) return;
        var childIdx = _tierOrderFix.indexOf(ranks[child].tier);
        if (childIdx > maxTierIdx) maxTierIdx = childIdx;
      });
      var parentIdx = _tierOrderFix.indexOf(ranks[parent].tier);
      if (maxTierIdx > parentIdx) {
        ranks[parent].tier = _tierOrderFix[maxTierIdx];
        ranks[parent].color = _tierColorsFix[_tierOrderFix[maxTierIdx]];
        ranks[parent].index = maxTierIdx;
      }
    });

    var totalMuscleXP = 0;
    var previousRanks = db.gamification.muscleRanks || {};
    var tierOrder = ['AtrophiÃĐ','DÃĐveloppÃĐ','SculptÃĐ','Puissant','Massif','Titanesque'];

    Object.keys(ranks).forEach(function(key) {
      if (key === '_computedAt') return;
      var tier = ranks[key].tier;
      var xp = MUSCLE_TIER_XP[tier] || 0;
      totalMuscleXP += xp;

      var prevTier = previousRanks[key] && previousRanks[key].tier;
      if (prevTier && tierOrder.indexOf(tier) > tierOrder.indexOf(prevTier)) {
        if (typeof showTierUpNotification === 'function') {
          showTierUpNotification(key, tier);
        }
      }
    });

    ranks._computedAt = now;
    db.gamification.muscleRanks = ranks;
    db.gamification.muscleXP = totalMuscleXP;

    if (typeof saveDB === 'function') saveDB();
    if (typeof syncToCloud === 'function') syncToCloud(true);

    if (typeof renderMuscleColors === 'function') renderMuscleColors();
    if (typeof renderMuscleList === 'function') renderMuscleList();
  } catch(e) {
    console.error('calcAndStoreMuscleRanks error:', e);
  }
}

function showTierUpNotification(muscleKey, newTier) {
  var name = MUSCLE_NAMES_FR[muscleKey] || muscleKey;
  var tierColors = {
    'DÃĐveloppÃĐ':'#7A8C6E', 'SculptÃĐ':'#C8A24C',
    'Puissant':'#78D8D0', 'Massif':'#6EB4FF',
    'Titanesque':'#BF5AF2'
  };
  var color = tierColors[newTier] || '#BF5AF2';
  var xp = MUSCLE_TIER_XP[newTier] || 0;

  if (typeof showToast === 'function') {
    showToast('ðŠ ' + name + ' â ' + newTier + ' (+' + xp + ' XP)');
  } else if (typeof showNotification === 'function') {
    showNotification({
      title: 'ðŠ Nouveau tier !',
      message: name + ' est maintenant ' + newTier,
      color: color,
      xp: xp,
    });
  }
}

