function _calcTodayXP() {
  var now = new Date();
  var todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime();
  var todayEnd = todayStart + 86400000;
  var xp = 0;
  var runBest = {};
  getSortedLogs().slice().reverse().forEach(function(log) {
    var isToday = log.timestamp >= todayStart && log.timestamp < todayEnd;
    (log.exercises||[]).forEach(function(exo) {
      if (exo.maxRM > 0) {
        var prev = runBest[exo.name] || 0;
        if (isToday) {
          if (prev > 0 && exo.maxRM > prev) xp += 50;
          else if (prev === 0) xp += 20;
        }
        if (exo.maxRM > (runBest[exo.name]||0)) runBest[exo.name] = exo.maxRM;
      }
    });
    if (isToday) {
      xp += 100;
      xp += Math.min(10, (log.exercises||[]).length) * 8;
      xp += Math.floor((log.volume || 0) / 500);
    }
  });
  return xp;
}

function scrollToBadgeCategory(badgeId) {
  var sections = document.querySelectorAll('.bdg-section');
  sections.forEach(function(sec) {
    var found = sec.querySelector('[data-badge-id="' + badgeId + '"]');
    if (found) {
      var body = sec.querySelector('.bdg-sec-body');
      if (body && !body.classList.contains('open')) {
        toggleBdgSection(sec.querySelector('.bdg-sec-head'));
      }
      sec.scrollIntoView({ behavior: 'smooth', block: 'start' });
      found.style.outline = '2px solid var(--purple)';
      found.style.outlineOffset = '2px';
      setTimeout(function() { found.style.outline = ''; found.style.outlineOffset = ''; }, 2000);
    }
  });
}

function getTrainingDaysCount() {
  var routine = getRoutine();
  if (routine) {
    var days = 0;
    for (var k in routine) {
      var v = routine[k];
      if (v && typeof v === 'string' && v.toLowerCase() !== 'repos' && v.toLowerCase() !== 'rest' && v !== '') days++;
    }
    if (days > 0) return days;
  }
  if (db.user.trainingDays) return db.user.trainingDays;
  var last4w = getLogsInRange(28);
  if (last4w.length >= 4) return Math.round(last4w.length / 4);
  return 5;
}

function calcBadgeProgress(badge) {
  if (!badge || badge.impossible) return null;
  var id = badge.id;
  var logs = db.logs;
  var B = db.bestPR.bench||0, S = db.bestPR.squat||0, D = db.bestPR.deadlift||0;
  var bw = getUserBW();

  // Pre-compute stats
  var totalVol = 0, maxSessVol = 0, totalSets = 0, totalDur = 0, maxSessDur = 0;
  var uniqueExos = new Set();
  logs.forEach(function(l) {
    totalVol += (l.volume||0);
    if ((l.volume||0) > maxSessVol) maxSessVol = l.volume||0;
    var ss = 0;
    (l.exercises||[]).forEach(function(e) { ss += (e.sets||0); uniqueExos.add(e.name); });
    totalSets += ss;
    var dur = l.duration || (ss * 210);
    if (dur > maxSessDur) maxSessDur = dur;
    totalDur += dur;
  });

  // Sessions
  if (/^s\d+$/.test(id)) { var t = parseInt(id.slice(1)); return { current: logs.length, target: t, pct: Math.min(100, Math.round(logs.length/t*100)) }; }
  // Volume session
  if (/^vs\d+$/.test(id) || id === 'v10t') { var t = id === 'v10t' ? 10000 : parseInt(id.slice(2)) * 1000; return { current: maxSessVol, target: t, pct: Math.min(100, Math.round(maxSessVol/t*100)) }; }
  // Volume cumul
  if (/^vt\d+$/.test(id)) { var t = parseInt(id.slice(2)) * 1000; return { current: totalVol, target: t, pct: Math.min(100, Math.round(totalVol/t*100)) }; }
  // Duration session
  if (/^dur\d+$/.test(id)) { var mins = parseInt(id.slice(3)); var t = mins * 60; return { current: maxSessDur, target: t, pct: Math.min(100, Math.round(maxSessDur/t*100)) }; }
  // Duration cumul
  if (/^tdur\d+$/.test(id)) { var h = parseInt(id.slice(4)); var t = h * 3600; return { current: totalDur, target: t, pct: Math.min(100, Math.round(totalDur/t*100)) }; }
  // Sets
  if (/^st\d+$/.test(id)) { var t = parseInt(id.slice(2)); return { current: totalSets, target: t, pct: Math.min(100, Math.round(totalSets/t*100)) }; }
  // Exercises
  if (/^ex\d+$/.test(id)) { var t = parseInt(id.slice(2)); return { current: uniqueExos.size, target: t, pct: Math.min(100, Math.round(uniqueExos.size/t*100)) }; }
  // Bench
  if (id.startsWith('bench_')) { var t = parseInt(id.split('_')[1]); return { current: B, target: t, pct: Math.min(100, Math.round(B/t*100)) }; }
  // Squat
  if (id.startsWith('squat_')) { var t = parseInt(id.split('_')[1]); return { current: S, target: t, pct: Math.min(100, Math.round(S/t*100)) }; }
  // Deadlift
  if (id.startsWith('dead_')) { var t = parseInt(id.split('_')[1]); return { current: D, target: t, pct: Math.min(100, Math.round(D/t*100)) }; }
  // OHP
  if (id.startsWith('ohp_')) {
    var ohpRM = 0;
    var _ohpRe = /overhead|militaire|\bohp\b|press mil/i;
    logs.forEach(function(l) { (l.exercises||[]).forEach(function(e) { if (_ohpRe.test(e.name) && (e.maxRM||0) > ohpRM) ohpRM = e.maxRM; }); });
    var t = parseInt(id.split('_')[1]);
    return { current: ohpRM, target: t, pct: Math.min(100, Math.round(ohpRM/t*100)) };
  }
  // Total SBD
  if (id.startsWith('total_')) { var t = parseInt(id.split('_')[1]); var total = B+S+D; return { current: total, target: t, pct: Math.min(100, Math.round(total/t*100)) }; }
  // BW ratios
  if (id.startsWith('bw_')) {
    var m = id.match(/bw_(b|s|d)(\d+)/);
    if (m) {
      var val = m[1] === 'b' ? B : m[1] === 's' ? S : D;
      var ratio = parseFloat(m[2]) / 10 || 1;
      // Determine actual ratio from badge condition
      if (badge.condition) {
        var rm = badge.condition.match(/([\d.]+)Ã/);
        if (rm) ratio = parseFloat(rm[1]);
      }
      var t = bw * ratio;
      return t > 0 ? { current: val, target: Math.round(t), pct: Math.min(100, Math.round(val/t*100)) } : null;
    }
  }
  // Streak
  if (id.startsWith('streak_')) { var t = parseInt(id.split('_')[1]); var s = calcStreak(); return { current: s, target: t, pct: Math.min(100, Math.round(s/t*100)) }; }
  // Collector â count non-collector badges only (matches _colCount unlock logic)
  if (id.startsWith('col')) {
    var allB = getAllBadges();
    var nonCol = allB.filter(function(x){return !x.impossible && !x.id.startsWith('col');});
    var unl = nonCol.filter(function(x){return x.ck();}).length;
    var t2;
    if (id === 'col_all') {
      // For col_all, target = total non-impossible badges (including collector)
      var allNorm = allB.filter(function(x){return !x.impossible;});
      t2 = allNorm.length;
      unl = allNorm.filter(function(x){return x.ck();}).length;
    } else {
      t2 = parseInt(id.slice(3));
    }
    return t2 > 0 ? { current: unl, target: t2, pct: Math.min(100, Math.round(unl/t2*100)) } : null;
  }
  return null;
}

function calcXPBreakdown() {
  var xpSeances = 0, xpRecords = 0, xpTonnage = 0;
  var sorted = getSortedLogs().slice().reverse();
  var runningBest = {};
  sorted.forEach(function(log) {
    xpSeances += 100;
    xpSeances += Math.min(10, (log.exercises||[]).length) * 8;
    xpTonnage += Math.floor((log.volume||0) / 500);
    (log.exercises||[]).forEach(function(exo) {
      if (exo.maxRM > 0) {
        var prev = runningBest[exo.name] || 0;
        if (prev > 0 && exo.maxRM > prev) xpRecords += 50;
        else if (prev === 0) xpRecords += 20;
        if (exo.maxRM > (runningBest[exo.name]||0)) runningBest[exo.name] = exo.maxRM;
      }
    });
  });
  var xpRegularite = calcStreak() * 25;
  var xpDefis = 0;
  if (db.weeklyChallenges && db.weeklyChallenges.challenges) {
    db.weeklyChallenges.challenges.forEach(function(c) { if (c.completed) xpDefis += (c.xpReward||0); });
  }
  if (db.monthlyChallenges && db.monthlyChallenges.challenges) {
    db.monthlyChallenges.challenges.forEach(function(c) { if (c.completed) xpDefis += (c.xpReward||0); });
  }
  (db.secretQuestsCompleted || []).forEach(function(sqId) {
    var sq = SECRET_QUESTS.find(function(s) { return s.id === sqId; });
    if (sq) xpDefis += sq.xp;
  });
  var xpCorps = (db.gamification && db.gamification.muscleXP) || 0;
  return { seances: xpSeances, records: xpRecords, regularite: xpRegularite, tonnage: xpTonnage, defis: xpDefis, corps: xpCorps };
}

// ââ PROGRESSION SCORE â leaderboard relatif (Gemini v207) ââââââââââââ
// Compare le volume moyen des derniÃĻres 30j vs le volume moyen
// d'une fenÃŠtre ÃĐquivalente (mÃŠme nombre de sÃĐances) juste avant.
// Permet de classer les profils lÃĐgers Ã  ÃĐgalitÃĐ avec les lourds.
function getProgressionScore(userId) {
  var _logs;
  if (userId === undefined || userId === null || userId === (db.user && db.user.id)) {
    _logs = db.logs || [];
  } else if (typeof _getFriendLogs === 'function') {
    _logs = _getFriendLogs(userId) || [];
  } else {
    _logs = [];
  }
  if (!_logs || _logs.length < 2) return 0;

  var _now = Date.now();
  var _30d = _now - 30 * 86400000;
  var _recent = _logs.filter(function(l) { return (l.timestamp || 0) > _30d; });
  var _older  = _logs.filter(function(l) { return (l.timestamp || 0) <= _30d; });
  if (!_recent.length || !_older.length) return 0;

  var _recentVol = _recent.reduce(function(s, l) { return s + (l.volume || 0); }, 0) / _recent.length;
  var _olderSlice = _older.slice(-_recent.length);
  var _olderVol = _olderSlice.reduce(function(s, l) { return s + (l.volume || 0); }, 0)
    / Math.max(_olderSlice.length, 1);
  return _olderVol > 0 ? Math.round((_recentVol - _olderVol) / _olderVol * 100) : 0;
}

async function _renderLeaderboard() {
  var el = document.getElementById('gamLeaderboard');
  if (!el) return;
  if (typeof navigator !== 'undefined' && navigator.onLine === false) {
    el.innerHTML = '<div style="font-size:12px;color:var(--sub);text-align:center;padding:12px;">ðķ Classement disponible en ligne uniquement.</div>';
    return;
  }

  var currentMetric = db._leaderboardMetric || 'dots';
  var periodType = currentMetric === 'dots' ? 'alltime' : (currentMetric === 'progression' ? 'monthly' : 'weekly');
  var weekKey = typeof getLeaderboardPeriodKey === 'function' ? getLeaderboardPeriodKey('weekly') : '';
  var monthKey = typeof getLeaderboardPeriodKey === 'function' ? getLeaderboardPeriodKey('monthly') : '';
  var periodKey = currentMetric === 'dots' ? 'alltime' : (currentMetric === 'progression' ? monthKey : weekKey);
  var unitLabel = currentMetric === 'dots' ? 'pts' : (currentMetric === 'progression' ? '%' : 'XP');
  var periodLabel = currentMetric === 'dots' ? 'Tout temps â DOTS'
    : (currentMetric === 'progression' ? 'Sur 30 jours â Progression' : 'Cette semaine â XP');

  el.innerHTML = '<div style="font-size:12px;color:var(--sub);">Chargement...</div>';
  try {
    if (typeof supaClient === 'undefined' || !supaClient) { el.innerHTML = ''; return; }
    var res = await supaClient.from('leaderboard_entries').select('username,value,user_id')
      .eq('period_type', periodType).eq('period_key', periodKey).eq('metric', currentMetric)
      .order('value', { ascending: false }).limit(10);
    var data = res.data;

    // Toggle header (rendered regardless of data)
    var html = '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;">';
    html += '<div style="font-size:11px;color:var(--sub);text-transform:uppercase;letter-spacing:0.8px;">'
      + periodLabel + '</div>';
    html += '<div style="display:flex;gap:4px;">';
    html += '<button onclick="db._leaderboardMetric=\'dots\';saveDB();_renderLeaderboard();" '
      + 'style="padding:3px 8px;border-radius:6px;font-size:10px;border:none;cursor:pointer;'
      + 'background:' + (currentMetric === 'dots' ? 'var(--accent)' : 'var(--surface)') + ';'
      + 'color:' + (currentMetric === 'dots' ? '#fff' : 'var(--sub)') + ';">DOTS</button>';
    html += '<button onclick="db._leaderboardMetric=\'xp\';saveDB();_renderLeaderboard();" '
      + 'style="padding:3px 8px;border-radius:6px;font-size:10px;border:none;cursor:pointer;'
      + 'background:' + (currentMetric === 'xp' ? 'var(--accent)' : 'var(--surface)') + ';'
      + 'color:' + (currentMetric === 'xp' ? '#fff' : 'var(--sub)') + ';">XP</button>';
    html += '<button onclick="db._leaderboardMetric=\'progression\';saveDB();_renderLeaderboard();" '
      + 'style="padding:3px 8px;border-radius:6px;font-size:10px;border:none;cursor:pointer;'
      + 'background:' + (currentMetric === 'progression' ? 'var(--accent)' : 'var(--surface)') + ';'
      + 'color:' + (currentMetric === 'progression' ? '#fff' : 'var(--sub)') + ';">Progression</button>';
    html += '</div></div>';

    if (!data || !data.length) {
      html += '<div style="font-size:12px;color:var(--sub);text-align:center;padding:16px;">ð Le classement se remplit au fur et Ã  mesure des sÃĐances.</div>';
      el.innerHTML = html;
      return;
    }
    var authRes = await supaClient.auth.getUser();
    var myId = authRes.data && authRes.data.user ? authRes.data.user.id : null;
    data.forEach(function(entry, i) {
      var isMe = entry.user_id === myId;
      var medal = i===0?'ðĨ':i===1?'ðĨ':i===2?'ðĨ':(i+1)+'.';
      var valueStr;
      if (currentMetric === 'progression') {
        var pct = Math.round(entry.value);
        var sign = pct > 0 ? '+' : '';
        valueStr = (pct === 0 ? '0' : sign + pct) + ' ' + unitLabel;
      } else {
        valueStr = entry.value > 0 ? Math.round(entry.value) + ' ' + unitLabel : 'â';
      }
      html += '<div style="display:flex;justify-content:space-between;align-items:center;padding:8px 10px;border-radius:10px;margin-bottom:4px;background:'+(isMe?'rgba(10,132,255,0.1)':'var(--surface)')+';border:1px solid '+(isMe?'var(--accent)':'transparent')+';">';
      html += '<div style="display:flex;align-items:center;gap:8px;"><div style="font-size:14px;">'+medal+'</div>';
      html += '<div style="font-size:13px;font-weight:'+(isMe?'700':'400')+';">'+(entry.username||'AthlÃĻte').replace(/</g,'&lt;')+(isMe?' (toi)':'')+'</div></div>';
      html += '<div style="font-size:13px;font-weight:700;color:var(--accent);">'+valueStr+'</div></div>';
    });
    el.innerHTML = html;
  } catch(e) { el.innerHTML = ''; }
}

// ââ DAILY HIGHLIGHT + GHOST MODE â Gemini v207 ââââââââââââââââââââââââ
// Max 1 notification sociale par jour : rÃĐsumÃĐ groupÃĐ des PRs des amis.
async function triggerDailyHighlight() {
  var _today = getTodayStr();
  if (db._lastDailyHighlight === _today) return;

  var _names = [];
  try {
    if (typeof loadFeedItems === 'function') {
      var _items = await loadFeedItems(0);
      var _todayStart = new Date(_today + 'T00:00:00').getTime();
      (_items || []).forEach(function(it) {
        if (it.type !== 'pr') return;
        var _ts = it.created_at ? new Date(it.created_at).getTime() : 0;
        if (_ts < _todayStart) return;
        var _name = (it.data && (it.data.username || it.data.name)) || 'Un ami';
        if (_names.indexOf(_name) === -1) _names.push(_name);
      });
    }
  } catch(e) {}

  if (_names.length === 0) {
    db._lastDailyHighlight = _today;
    if (typeof saveDB === 'function') saveDB();
    return;
  }

  var _msg;
  if (_names.length === 1) {
    _msg = _names[0] + ' a battu un record aujourd\'hui ! ð';
  } else if (_names.length === 2) {
    _msg = _names[0] + ' et ' + _names[1] + ' ont battu des records aujourd\'hui ! ð';
  } else {
    _msg = _names.slice(0, 2).join(', ') + ' et ' + (_names.length - 2)
      + ' autre' + (_names.length - 2 > 1 ? 's' : '')
      + ' ont battu des records aujourd\'hui ! ð';
  }
  if (typeof showToast === 'function') showToast(_msg, 6000);
  if (typeof sendLocalNotification === 'function') sendLocalNotification('ð Daily Highlight', _msg);
  db._lastDailyHighlight = _today;
  if (typeof saveDB === 'function') saveDB();
}

// Mode Ghost : l'user voit les autres, les autres ne le voient pas
function setGhostMode(enabled) {
  if (!db.user) db.user = {};
  if (!db.user.social) db.user.social = {};
  db.user.social.ghostMode = !!enabled;
  if (enabled) {
    db.user.social.visibility = {
      bio: 'private', prs: 'private', programme: 'private',
      seances: 'private', stats: 'private', feed: 'private'
    };
  } else {
    db.user.social.visibility = {
      bio: 'friends', prs: 'friends', programme: 'friends',
      seances: 'friends', stats: 'friends', feed: 'friends'
    };
  }
  if (typeof saveDB === 'function') saveDB();
  if (typeof showToast === 'function') {
    showToast(enabled ? 'ðŧ Mode privÃĐ activÃĐ' : 'ðĨ Profil visible par tes amis');
  }
}

