      '<div><div class="gam-recap-text">' + (isPerfect?'ðĨ Semaine parfaite !':'ð Semaine derniÃĻre') + '</div>' +
      '<div class="gam-recap-sub">' + prevDone + '/' + ch.length + ' quÃŠtes Â· +' + prevXP + ' XP Â· ' + prevSessions + ' sÃĐances</div></div>' +
      '<button class="gam-recap-close" onclick="this.parentElement.remove();sessionStorage.setItem(\'gamRecapDismissed\',\'1\')">â</button></div>';
    levelCardEl.insertAdjacentHTML('beforebegin', recapHtml);
