// ââ QUICK-LOG ACTIVITÃ PONCTUELLE (v201) ââââââââââââââââââââââââââââââââââ
// Carte dashboard : logger une activitÃĐ hors salle avant la sÃĐance

var _QUICK_LOG_IMPACT = {
  rando:    { zone: 'legs',   pct: -20, minDur: 120 },
  cardio:   { zone: 'global', pct: -15, minDur: 60  },
  velo:     { zone: 'global', pct: -10, minDur: 60  },
  natation: { zone: 'global', pct: -10, minDur: 45  },
  yoga:     null,
  autre:    null
};

var _QUICK_LOG_TYPES = [
  { key: 'rando',    label: 'RandonnÃĐe',  emoji: 'ðĨū' },
  { key: 'cardio',   label: 'Cardio',     emoji: 'ð' },
  { key: 'velo',     label: 'VÃĐlo',       emoji: 'ðī' },
  { key: 'natation', label: 'Natation',   emoji: 'ð' },
  { key: 'yoga',     label: 'Yoga',       emoji: 'ð§' },
  { key: 'autre',    label: 'Autre',      emoji: 'ð' }
];

function renderQuickLogCard() {
  var el = document.getElementById('quickLogCard');
  if (!el) return;
  var todayStr = new Date().toISOString().split('T')[0];
  var _logged = (db._quickLogActivities || []).find(function(a) { return a.date === todayStr; });
  el.style.display = '';
  if (_logged) {
    el.innerHTML = '<div style="display:flex;align-items:center;gap:8px;font-size:12px;color:var(--sub);">'
      + '<span style="color:var(--green);font-size:14px;">â</span>'
      + escapeHtml(_logged.emoji) + ' ' + escapeHtml(_logged.label) + ' ' + _logged.duration + 'min loggÃĐ'
      + '<button onclick="clearQuickLog()" style="margin-left:auto;font-size:11px;color:var(--sub);'
      + 'background:none;border:none;cursor:pointer;padding:2px 6px;">Ã</button></div>';
    return;
  }
  var html = '<div style="font-size:11px;color:var(--sub);text-transform:uppercase;'
    + 'letter-spacing:0.8px;margin-bottom:10px;">ð ActivitÃĐ hors salle aujourd\'hui ?</div>';
  html += '<div style="display:flex;flex-wrap:wrap;gap:6px;">';
  _QUICK_LOG_TYPES.forEach(function(t) { html += _quickLogBtn(t); });
  html += '</div>';
  el.innerHTML = html;
}

function _quickLogBtn(t) {
  return '<button onclick="showQuickLogDuration(\'' + escapeHtml(t.key) + '\',\''
    + escapeHtml(t.label) + '\',\'' + escapeHtml(t.emoji) + '\')" '
    + 'style="padding:6px 10px;border-radius:20px;background:var(--surface);border:1px solid var(--border);'
    + 'font-size:12px;cursor:pointer;">'
    + escapeHtml(t.emoji) + ' ' + escapeHtml(t.label) + '</button>';
}

function showQuickLogDuration(key, label, emoji) {
  var el = document.getElementById('quickLogCard');
  if (!el) return;
  var durations = [30, 45, 60, 90, 120];
  var html = '<div style="font-size:12px;color:var(--sub);margin-bottom:8px;">'
    + escapeHtml(emoji) + ' ' + escapeHtml(label) + ' â DurÃĐe ?</div>';
  html += '<div style="display:flex;gap:6px;flex-wrap:wrap;align-items:center;">';
  durations.forEach(function(d) {
    html += '<button onclick="saveQuickLog(\'' + escapeHtml(key) + '\',\'' + escapeHtml(label)
      + '\',\'' + escapeHtml(emoji) + '\',' + d + ')" '
      + 'style="padding:6px 12px;border-radius:20px;background:var(--accent);border:none;'
      + 'color:#fff;font-size:12px;cursor:pointer;">' + d + 'min</button>';
  });
  html += '<button onclick="renderQuickLogCard()" '
    + 'style="padding:6px 10px;border-radius:20px;background:var(--surface);border:1px solid var(--border);'
    + 'font-size:12px;color:var(--sub);cursor:pointer;">â</button></div>';
  el.innerHTML = html;
}

function saveQuickLog(key, label, emoji, duration) {
  var todayStr = new Date().toISOString().split('T')[0];
  if (!db._quickLogActivities) db._quickLogActivities = [];
  db._quickLogActivities = db._quickLogActivities.filter(function(a) { return a.date !== todayStr; });
  db._quickLogActivities.push({ date: todayStr, key: key, label: label, emoji: emoji, duration: duration });
  _applyQuickLogToProgram(key, duration);
  saveDB();
  renderQuickLogCard();
  if (typeof showToast === 'function') showToast(emoji + ' ' + label + ' ' + duration + 'min loggÃĐ');
}

function clearQuickLog() {
  var todayStr = new Date().toISOString().split('T')[0];
  db._quickLogActivities = (db._quickLogActivities || []).filter(function(a) { return a.date !== todayStr; });
  if (db.weeklyPlan) delete db.weeklyPlan._quickLogAdjustment;
  saveDB();
  renderQuickLogCard();
}

function _applyQuickLogToProgram(key, duration) {
  var impact = _QUICK_LOG_IMPACT[key];
  if (!impact || duration < impact.minDur) return;
  if (!db.weeklyPlan) return;
  db.weeklyPlan._quickLogAdjustment = {
    zone: impact.zone, pct: impact.pct,
    date: new Date().toISOString().split('T')[0]
  };
}

// ââ VALIDATION GATE â Transition de phase assistÃĐe (v202) âââââââââââââââââ

function isEndOfPhaseBlock() {
  var cb = db.weeklyPlan && db.weeklyPlan.currentBlock;
  if (!cb || !cb.phase) return false;
  var mode = (db.user && db.user.trainingMode) || 'powerbuilding';
  var level = (db.user && db.user.level) || 'intermediaire';
  var durations = typeof BLOCK_DURATION !== 'undefined' && BLOCK_DURATION[mode] && BLOCK_DURATION[mode][level];
  if (!durations) return false;
  var maxWeeks = durations[cb.phase] || 4;
  var weeksSince = cb.blockStartDate
    ? Math.max(0, Math.round((Date.now() - cb.blockStartDate) / (7 * 86400000))) : 0;
  return weeksSince >= maxWeeks;
}

function getNextPhase(currentPhase) {
  var sequence = ['hypertrophie','accumulation','force','intensification','peak','deload'];
  var idx = sequence.indexOf(currentPhase);
  return sequence[idx + 1] || 'hypertrophie';
}

function _computeBlockVolumeGain() {
  var cb = db.weeklyPlan && db.weeklyPlan.currentBlock;
  if (!cb || !cb.blockStartDate) return 0;
  var blockLogs = (db.logs||[]).filter(function(l) { return (l.timestamp||0) >= cb.blockStartDate; });
  if (blockLogs.length < 4) return 0;
  var half = Math.floor(blockLogs.length / 2);
  var v1 = blockLogs.slice(0, half).reduce(function(s,l){return s+(l.volume||0);},0) / half;
  var v2 = blockLogs.slice(half).reduce(function(s,l){return s+(l.volume||0);},0) / Math.max(1, blockLogs.length - half);
  return v1 > 0 ? Math.round((v2 - v1) / v1 * 100) : 0;
}

function showPhaseValidationGate() {
  var cb = db.weeklyPlan && db.weeklyPlan.currentBlock;
  if (!cb) return;
  var nextPhase = getNextPhase(cb.phase);
  var phaseLabels = {
    hypertrophie:'Hypertrophie', force:'Force', intensification:'Intensification',
    peak:'Peak', deload:'Deload', accumulation:'Accumulation'
  };
  var _gain = _computeBlockVolumeGain();
  var _gainStr = _gain > 0 ? '+' + _gain + '% de volume total sur ce bloc' : 'bloc complÃĐtÃĐ';

  var overlay = document.createElement('div');
  overlay.className = 'modal-overlay';
  overlay.innerHTML = '<div class="modal-box" style="max-width:360px;text-align:left;">'
    + '<div style="font-size:16px;font-weight:700;margin-bottom:8px;">ð Bloc '
    + escapeHtml(phaseLabels[cb.phase] || cb.phase) + ' complÃĐtÃĐ !</div>'
    + '<div style="font-size:13px;color:var(--sub);margin-bottom:14px;">'
    + escapeHtml(_gainStr) + '. La data suggÃĻre que tu es prÃŠt pour la phase <strong>'
    + escapeHtml(phaseLabels[nextPhase] || nextPhase) + '</strong>. On bascule lundi ?</div>'
    + '<div style="display:flex;gap:8px;">'
    + '<button onclick="confirmPhaseTransition(\'' + escapeHtml(nextPhase) + '\')" '
    + 'style="flex:1;padding:12px;border-radius:10px;background:var(--accent);border:none;'
    + 'color:#fff;font-weight:700;cursor:pointer;">Oui, c\'est parti ð</button>'
    + '<button onclick="postponePhaseTransition()" '
    + 'style="flex:1;padding:12px;border-radius:10px;background:var(--surface);'
    + 'border:0.5px solid var(--border);color:var(--sub);cursor:pointer;">Je refais une semaine</button>'
    + '</div></div>';
  _uiOpen(overlay, { dismissible: false });
}

function confirmPhaseTransition(nextPhase) {
  closeAllOverlays();
  if (!db.weeklyPlan) db.weeklyPlan = {};
  if (!db.weeklyPlan.currentBlock) db.weeklyPlan.currentBlock = {};
  // Retour Ã  hypertrophie = fin d'un macrocycle complet (Gemini v211)
  if (nextPhase === 'hypertrophie' && typeof incrementMacrocycleCounter === 'function') {
    incrementMacrocycleCounter();
  }
  db.weeklyPlan.currentBlock.phase = nextPhase;
  db.weeklyPlan.currentBlock.blockStartDate = Date.now();
  db.weeklyPlan.currentBlock.forcedAt = Date.now();
  // v212 â strip prÃĐfixe deload ð de db.routine quand on quitte la phase deload
  if (db.routine) {
    Object.keys(db.routine).forEach(function(day) {
      if (typeof db.routine[day] === 'string') {
        db.routine[day] = db.routine[day].replace(/^ð\s*/, '');
      }
    });
  }
  db._phaseGateShownAt = null;
  saveDB();
  if (typeof showToast === 'function') showToast('ð Phase ' + nextPhase + ' activÃĐe lundi !');
  renderDash();
}

function postponePhaseTransition() {
  closeAllOverlays();
  if (db.weeklyPlan && db.weeklyPlan.currentBlock && db.weeklyPlan.currentBlock.blockStartDate) {
    db.weeklyPlan.currentBlock.blockStartDate -= 7 * 86400000; // -1 semaine
  }
  db._phaseGateShownAt = null;
  saveDB();
  if (typeof showToast === 'function') showToast('â Semaine supplÃĐmentaire ajoutÃĐe.');
}

function renderDash() {
  try {
    // Carte bienvenue (visible si aucune sÃĐance importÃĐe)
    const welcomeCard = document.getElementById('welcomeCard');
    if (welcomeCard) {
      const noData = !db.logs || db.logs.length === 0;
      welcomeCard.style.display = noData ? '' : 'none';
      if (noData && db.user.name) {
        const title = document.getElementById('welcomeTitle');
        if (title) title.textContent = 'Salut ' + db.user.name + ' ! Tout est prÃŠt.';
      }
    }

    // Maison v264 â anciennes cards remplacÃĐes par la composition 4 zones
    // (programme timeline + sÃĐance sÃĐlectionnÃĐe + stats + records personnels)
    ['dashWeekCard', 'quickLogCard', 'perfCard'].forEach(function(id) {
      var el = document.getElementById(id);
      if (el) el.style.display = 'none';
    });

    try { renderTodaySessionInline(); } catch (e) {
      if (typeof logErrorToSupabase === 'function') logErrorToSupabase('render_crash', String(e && e.message || e), 'renderTodaySessionInline');
    }

    try {
      var _domsMorningEl = document.getElementById('doms-morning-card');
      if (_domsMorningEl) _domsMorningEl.innerHTML = renderDOMSMorningCard();
    } catch(e) {}

    // v202 â Validation Gate : afficher une fois par fin de bloc
    try {
      if (isEndOfPhaseBlock() && !db._phaseGateShownAt) {
        db._phaseGateShownAt = Date.now();
        saveDB();
        setTimeout(showPhaseValidationGate, 1000);
      }
    } catch(e) {}
  } catch (err) {
    if (typeof logErrorToSupabase === 'function') {
      logErrorToSupabase('render_crash', String(err && err.message || err), 'renderDash');
    }
  }
}


// ============================================================
// Total SBD estimÃĐ â barres + progression
// ============================================================
function toggleSBDChart(mode) {
  sbdChartMode = mode;
  renderSBDTotal();
}

function renderSBDTotal() {
  var el = document.getElementById('sbdTotalDisplay');
  if (!el) return;
  var card = document.getElementById('sbdTotalCard');

  if (chartSBD) { try { chartSBD.destroy(); } catch(e) {} chartSBD = null; }
  chartSBDs.forEach(function(c) { try { c.destroy(); } catch(e) {} });
  chartSBDs = [];

  var realBench = db.bestPR.bench || 0;
  var realSquat = db.bestPR.squat || 0;
  var realDead  = db.bestPR.deadlift || 0;

  var estBench = 0, estSquat = 0, estDead = 0;
  db.logs.forEach(function(log) {
    (log.exercises || []).forEach(function(exo) {
      var type = getSBDType(exo.name);
      if (!type) return;
      var rm = exo.maxRM || 0;
      if (!rm && exo.repRecords) {
        Object.entries(exo.repRecords).forEach(function(kv) {
          var e = calcE1RM(kv[1], parseInt(kv[0]));
          if (e > rm) rm = Math.round(e);
        });
      }
      if (type === 'bench'    && rm > estBench) estBench = rm;
      if (type === 'squat'    && rm > estSquat) estSquat = rm;
      if (type === 'deadlift' && rm > estDead)  estDead  = rm;
    });
  });

  var tgt = db.user.targets || {};
  var tgtBench = tgt.bench || 0, tgtSquat = tgt.squat || 0, tgtDead = tgt.deadlift || 0;

  var toggleHtml =
    '<div style="display:flex;gap:6px;margin-bottom:12px;">' +
    '<button onclick="toggleSBDChart(\'bars\')" class="period-btn' + (sbdChartMode === 'bars' ? ' active' : '') + '">ð Barres</button>' +
    '<button onclick="toggleSBDChart(\'line\')" class="period-btn' + (sbdChartMode === 'line' ? ' active' : '') + '">ð Progression</button>' +
    '</div>';

  if (sbdChartMode === 'bars') {
    if (!realBench && !realSquat && !realDead && !estBench && !estSquat && !estDead) {
      el.innerHTML = toggleHtml + '<div style="text-align:center;font-size:12px;color:var(--sub);padding:16px 0;">Importe des sÃĐances pour voir tes performances</div>';
      if (card) { var tl = card.querySelector('.sbd-total-line'); if (tl) tl.innerHTML = ''; }
      return;
    }
    var total = realBench + realSquat + realDead;
    if (card) {
      var totalEl = card.querySelector('.sbd-total-line');
      if (!totalEl) { totalEl = document.createElement('div'); totalEl.className = 'sbd-total-line'; totalEl.style.cssText = 'text-align:center;margin-top:10px;font-size:13px;color:var(--sub);'; card.appendChild(totalEl); }
      totalEl.innerHTML = total > 0 ? 'Total : <strong style="color:var(--text);font-size:18px;">' + total + 'kg</strong>' : '';
    }
    var sbdPairs = [
      { label: 'Bench',    real: realBench, est: estBench, tgt: tgtBench, color: '#0A84FF' },
      { label: 'Squat',    real: realSquat, est: estSquat, tgt: tgtSquat, color: '#FF453A' },
      { label: 'Deadlift', real: realDead,  est: estDead,  tgt: tgtDead,  color: '#FF9F0A' }
    ];
    var miniHtml = '<div style="display:flex;gap:6px;height:120px;overflow:hidden;">';
    sbdPairs.forEach(function(p) { miniHtml += '<div style="flex:1;min-width:0;position:relative;"><canvas id="chartSBD_' + p.label + '"></canvas></div>'; });
    miniHtml += '</div>';
    miniHtml += '<div style="display:flex;justify-content:center;gap:14px;margin-top:6px;">' +
      '<span style="font-size:10px;color:var(--sub);">&#9646; RÃĐel</span>' +
      '<span style="font-size:10px;color:var(--sub);opacity:0.6;">&#9646; EstimÃĐ</span>' +
      '<span style="font-size:10px;color:var(--sub);opacity:0.3;">&#9646; Objectif</span></div>';
    el.innerHTML = toggleHtml + miniHtml;
    requestAnimationFrame(function() {
      if (typeof Chart === 'undefined') { ensureChartLoaded().then(renderSBDTotal).catch(function(){}); return; }
      sbdPairs.forEach(function(p) {
        var ctx = document.getElementById('chartSBD_' + p.label);
        if (!ctx) return;
        // DÃĐtruire toute instance Chart.js existante attachÃĐe au canvas
        try {
          var _existingP = (Chart.getChart) ? Chart.getChart(ctx) : null;
          if (_existingP) _existingP.destroy();
        } catch(e) {}
        var vals = [p.real, p.est, p.tgt].filter(function(v) { return v > 0; });
        var maxVal = vals.length ? Math.max.apply(null, vals) : 100;
        var minVal = vals.length ? Math.min.apply(null, vals) : 0;
        chartSBDs.push(new Chart(ctx, {
          type: 'bar',
          data: {
            labels: ['RÃĐel', 'Est.', 'Obj.'],
            datasets: [{ label: p.label, data: [p.real || null, p.est || null, p.tgt || null],
              backgroundColor: [p.color, p.color + '66', p.color + '22'],
              borderColor: [p.color, p.color + '99', p.color + '55'],
              borderWidth: 1, borderRadius: 4 }]
          },
          options: {
            responsive: true, maintainAspectRatio: false,
            plugins: {
              legend: { display: false },
              title: { display: true, text: p.label, color: p.color, font: { size: 11, weight: '600' }, align: 'center', padding: { top: 0, bottom: 2 } },
              tooltip: { callbacks: { label: function(c) { return (c.parsed.y || 'â') + ' kg'; }, title: function() { return p.label; } } }
            },
            scales: {
              x: { display: false },
              y: { display: false, beginAtZero: false, min: Math.floor(minVal * 0.85), suggestedMax: Math.ceil(maxVal * 1.1) }
            }
          }
        }));
      });
    });

  } else {
    var sbdDef = [
      { type: 'bench',    label: 'Bench',    color: '#0A84FF' },
      { type: 'squat',    label: 'Squat',    color: '#FF453A' },
      { type: 'deadlift', label: 'Deadlift', color: '#FF9F0A' }
    ];
    var sortedLogs = db.logs.slice().sort(function(a, b) { return a.timestamp - b.timestamp; });
    var datasets = [];
    sbdDef.forEach(function(def) {
      var seen = {};
      sortedLogs.forEach(function(log) {
        (log.exercises || []).forEach(function(exo) {
          if (getSBDType(exo.name) !== def.type) return;
          var rm = exo.maxRM || 0;
          if (!rm && exo.repRecords) {
            Object.entries(exo.repRecords).forEach(function(kv) {
              var e = calcE1RM(kv[1], parseInt(kv[0]));
              if (e > rm) rm = Math.round(e);
            });
          }
          if (!(rm > 0)) return;
          var lbl = new Date(log.timestamp).toLocaleDateString('fr-FR', { day: '2-digit', month: '2-digit' });
          if (!seen[lbl] || rm > seen[lbl].val) seen[lbl] = { ts: log.timestamp, val: Math.round(rm) };
        });
      });
      var pts = Object.values(seen).sort(function(a, b) { return a.ts - b.ts; }).slice(-20);
      if (pts.length < 2) return;
      datasets.push({
        label: def.label,
        _xlabels: pts.map(function(p) { return new Date(p.ts).toLocaleDateString('fr-FR', { day: '2-digit', month: '2-digit' }); }),
        data: pts.map(function(p) { return p.val; }),
        borderColor: def.color, backgroundColor: def.color + '22',
        borderWidth: 2, pointRadius: 3, pointBackgroundColor: def.color,
        fill: false, tension: 0.35
      });
    });
    if (!datasets.length) {
      el.innerHTML = toggleHtml + '<div style="text-align:center;font-size:12px;color:var(--sub);padding:16px 0;">Importe des sÃĐances pour voir ta progression</div>';
      if (card) { var tl2 = card.querySelector('.sbd-total-line'); if (tl2) tl2.innerHTML = ''; }
      return;
    }
    el.innerHTML = toggleHtml + '<div style="position:relative;height:180px;"><canvas id="chartSBDCanvas"></canvas></div>';
    if (card) { var tl3 = card.querySelector('.sbd-total-line'); if (tl3) tl3.innerHTML = ''; }
    requestAnimationFrame(function() {
      var ctx = document.getElementById('chartSBDCanvas');
      if (!ctx) return;
      // DÃĐtruire toute instance Chart.js existante attachÃĐe au canvas
      try {
        var _existingS = (Chart.getChart) ? Chart.getChart(ctx) : null;
        if (_existingS) _existingS.destroy();
      } catch(e) {}
      var longestLabels = datasets.reduce(function(a, b) { return a._xlabels.length >= b._xlabels.length ? a : b; })._xlabels;
      chartSBD = new Chart(ctx, {
        type: 'line',
        data: {
          labels: longestLabels,
          datasets: datasets.map(function(ds) {
            return { label: ds.label, data: ds.data, borderColor: ds.borderColor,
              backgroundColor: ds.backgroundColor, borderWidth: ds.borderWidth,
              pointRadius: ds.pointRadius, pointBackgroundColor: ds.pointBackgroundColor,
              fill: ds.fill, tension: ds.tension };
          })
        },
        options: {
          responsive: true, maintainAspectRatio: false,
          plugins: {
            legend: { display: true, labels: { color: '#86868B', font: { size: 10 }, boxWidth: 10 } },
            tooltip: { callbacks: { label: function(ctx) { return ctx.dataset.label + ': ' + ctx.parsed.y + ' kg'; } } }
          },
          scales: {
            x: { ticks: { color: '#86868B', font: { size: 10 } }, grid: { display: false } },
            y: { ticks: { color: '#86868B', font: { size: 10 } }, grid: { color: 'rgba(255,255,255,0.05)' }, beginAtZero: false }
          }
        }
      });
    });
  }
}

function _normalizeMuscle(name) {
  var n = (name || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  if (n.indexOf('pec') >= 0 || n.indexOf('chest') >= 0) return 'pecs';
  if (n.indexOf('epaule') >= 0 || n.indexOf('deltoid') >= 0 || n.indexOf('shoulder') >= 0) return 'epaules';
  if (n.indexOf('bicep') >= 0) return 'biceps';
  if (n.indexOf('tricep') >= 0) return 'triceps';
  if (n.indexOf('abdo') >= 0 || n.indexOf('core') >= 0) return 'abdos';
  if (n.indexOf('quad') >= 0) return 'quadriceps';
  if (n.indexOf('ischio') >= 0 || n.indexOf('hamstring') >= 0) return 'ischiojambiers';
  if (n.indexOf('fessier') >= 0 || n.indexOf('glute') >= 0) return 'fessiers';
  if (n.indexOf('mollet') >= 0 || n.indexOf('calf') >= 0 || n.indexOf('calves') >= 0) return 'mollets';
  if (n.indexOf('dorsal') >= 0 || n.indexOf('dos') >= 0 || n.indexOf('lat') >= 0 || n.indexOf('back') >= 0) return 'dos';
  if (n.indexOf('trapez') >= 0 || n.indexOf('haut du dos') >= 0) return 'trapezes';
  if (n.indexOf('lombaire') >= 0 || n.indexOf('lower back') >= 0) return 'lombaires';
  if (n.indexOf('avant-bras') >= 0 || n.indexOf('forearm') >= 0) return 'biceps'; // regroupÃĐ
  return n;
}

