var _pgmEditMode = false;
var _pgmOriginalDays = null;
var _todayCardExpanded = false;

// v231 â Badge phase + barre de progression du bloc
function renderPhaseProgressBadge() {
  var _block = db.weeklyPlan && db.weeklyPlan.currentBlock;
  if (!_block) return '';

  var _phase = _block.phase || 'hypertrophie';
  var _week = _block.week || 1;
  var _mode = (db.user && db.user.trainingMode) || 'powerbuilding';
  var _level = (db.user && db.user.level) || 'intermediaire';

  var _durations = (typeof BLOCK_DURATION !== 'undefined'
    && BLOCK_DURATION[_mode] && BLOCK_DURATION[_mode][_level])
    ? Object.assign({}, BLOCK_DURATION[_mode][_level]) : {};
  if (db.user && db.user.programMode === 'custom' && db.user.customBlockDuration) {
    Object.keys(db.user.customBlockDuration).forEach(function(p) {
      if (db.user.customBlockDuration[p] > 0) _durations[p] = db.user.customBlockDuration[p];
    });
  }

  var _phaseDur = _durations[_phase] || 4;
  var _pct = Math.min(100, Math.round((_week / _phaseDur) * 100));

  // Ordre des phases par mode (cohÃĐrent avec wpDetectPhase v229)
  var _phasesByMode = {
    powerbuilding: ['hypertrophie','force','intensification','peak','deload'],
    powerlifting:  ['hypertrophie','force','intensification','peak','deload'],
    musculation:   ['accumulation','volume','recuperation','deload'],
    calisthenics:  ['accumulation','volume','deload'],
    bien_etre:     ['accumulation']
  };
  var _phasesOrder = _phasesByMode[_mode] || _phasesByMode.powerbuilding;
  var _idx = _phasesOrder.indexOf(_phase);
  var _nextPhase = _idx >= 0 && _idx < _phasesOrder.length - 1
    ? _phasesOrder[_idx + 1] : null;
  var _weeksLeft = Math.max(0, _phaseDur - _week);

  var _phaseLabels = {
    hypertrophie:'Hypertrophie', accumulation:'Accumulation',
    force:'Force', intensification:'Intensification', peak:'Peak',
    deload:'Deload', volume:'Volume', recuperation:'RÃĐcupÃĐration'
  };
  var _phaseEmojis = {
    hypertrophie:'ðŠ', accumulation:'ð', force:'ðïļ',
    intensification:'âĄ', peak:'ð', deload:'ðī',
    volume:'ðĨ', recuperation:'ðŋ'
  };

  var _nextLabel = _weeksLeft > 0 && _nextPhase
    ? (_phaseLabels[_nextPhase] || _nextPhase) + ' dans ' + _weeksLeft + ' sem.'
    : 'Fin de bloc cette semaine';

  return '<div style="padding:10px 16px 6px;">'
    + '<div style="display:inline-flex;align-items:center;gap:6px;'
    + 'background:rgba(167,139,250,0.1);border:0.5px solid rgba(167,139,250,0.25);'
    + 'border-radius:20px;padding:5px 12px;margin-bottom:8px;">'
    + '<span style="font-size:13px;">' + (_phaseEmojis[_phase] || 'ðŠ') + '</span>'
    + '<span style="color:#a78bfa;font-size:12px;font-weight:500;">'
    + (_phaseLabels[_phase] || _phase) + ' Â· S' + _week + ' / ' + _phaseDur
    + '</span></div>'
    + '<div style="display:flex;align-items:center;gap:8px;">'
    + '<div style="flex:1;height:3px;background:var(--surface2,#1e1e2e);border-radius:2px;">'
    + '<div style="height:100%;width:' + _pct + '%;background:#a78bfa;border-radius:2px;"></div>'
    + '</div>'
    + '<span style="color:var(--sub);font-size:11px;">' + _nextLabel + '</span>'
    + '</div></div>';
}

// v231 â Carte "Aujourd'hui" mise en avant
function renderTodayCard() {
  var _todayName = DAYS_FULL[new Date().getDay()];
  var _days = (db.weeklyPlan && db.weeklyPlan.days) || [];
  var _todayDay = _days.find(function(d) { return d.day === _todayName; });

  if (!_todayDay || _todayDay.rest || !_todayDay.exercises || !_todayDay.exercises.length) {
    return '<div style="padding:0 0 4px;">'
      + '<div style="color:var(--sub);font-size:11px;letter-spacing:0.05em;'
      + 'text-transform:uppercase;padding:6px 16px 4px;">Aujourd\'hui Â· ' + _todayName + '</div>'
      + '<div style="margin:0 12px 8px;padding:14px;background:var(--surface,#13131f);'
      + 'border:0.5px solid var(--border,#1e1e2e);border-radius:14px;'
      + 'color:var(--sub);font-size:13px;">ðī Repos aujourd\'hui</div></div>';
  }

  var _exos = _todayDay.exercises.filter(function(e) {
    return e && !e.isWarmup && !(e.setType === 'warmup');
  });

  var _top3 = _todayCardExpanded ? _exos : _exos.slice(0, 3);
  var _more = _todayCardExpanded ? 0 : _exos.length - 3;

  var _exoRows = _top3.map(function(e) {
    var _setsArr = Array.isArray(e.sets) ? e.sets.filter(function(s) {
      return s && !s.isWarmup && s.setType !== 'warmup';
    }) : [];
    var _setsCount = _setsArr.length || (typeof e.sets === 'number' ? e.sets : 3);
    var _reps = e.reps || (_setsArr[0] && _setsArr[0].reps) || '10';
    var _weight = (_setsArr[0] && _setsArr[0].weight) || e.workWeight || e.weight || '';
    var _detail;
    if (e.type === 'cardio') {
      var _cDur = _setsArr[0] && (_setsArr[0].durationMin || _setsArr[0].durationSec);
      _detail = _cDur ? (_setsArr[0].durationMin ? _setsArr[0].durationMin + ' min' : _setsArr[0].durationSec + 's') : (_setsCount + ' min');
    } else if (e.type === 'time') {
      var _tSec = _setsArr[0] && _setsArr[0].durationSec;
      _detail = _tSec ? _setsCount + 'Ã' + _tSec + 's' : _setsCount + 'Ã' + _reps;
    } else {
      _detail = _weight
        ? _setsCount + 'Ã' + _reps + ' Â· <span style="color:#a78bfa;font-weight:500;">' + _weight + 'kg</span>'
        : _setsCount + 'Ã' + _reps;
    }

    return '<div style="display:flex;align-items:center;gap:8px;padding:3px 0;">'
      + '<div style="width:5px;height:5px;border-radius:50%;background:#a78bfa;'
      + 'opacity:0.6;flex-shrink:0;"></div>'
      + '<span style="color:var(--sub);font-size:12px;flex:1;white-space:nowrap;'
      + 'overflow:hidden;text-overflow:ellipsis;">' + (e.name || e.exercise || '') + '</span>'
      + '<span style="color:var(--sub2,#666);font-size:11px;flex-shrink:0;">' + _detail + '</span>'
      + '</div>';
  }).join('');

  if (_more > 0) {
    _exoRows += '<div onclick="_todayCardExpanded=true;if(typeof renderProgrammeV2===\'function\')renderProgrammeV2();" '
      + 'style="display:flex;align-items:center;gap:8px;padding:3px 0;cursor:pointer;">'
      + '<div style="width:5px;height:5px;border-radius:50%;background:#a78bfa;'
      + 'opacity:0.2;flex-shrink:0;"></div>'
      + '<span style="color:#a78bfa;font-size:12px;">+' + _more + ' exercices âū</span>'
      + '</div>';
  }

  var _durMin = (db.user && db.user.programParams && db.user.programParams.duration)
    || (db.user && db.user.trainingDuration) || 90;

  var _todayStr = getTodayStr();
  var _done = (db.logs || []).some(function(l) {
    if (!l) return false;
    if (l.date === _todayStr) return true;
    if (l.timestamp) {
      var d = new Date(l.timestamp);
      if (!isNaN(d.getTime()) && d.toISOString().slice(0, 10) === _todayStr) return true;
    }
    return false;
  });

  var _goBtn = _done
    ? '<span style="background:rgba(26,188,126,0.15);color:#1abc7e;border-radius:10px;'
      + 'padding:6px 12px;font-size:12px;font-weight:500;">â Fait</span>'
    : '<button onclick="showSeancesSub(\'s-go\',document.querySelector(\'#tab-seances .seances-nav .stats-sub-pill:nth-child(3)\'))" '
      + 'style="background:#a78bfa;border:none;border-radius:10px;padding:7px 14px;'
      + 'color:#fff;font-size:12px;font-weight:600;cursor:pointer;">âķ GO</button>';

  return '<div style="padding:0 0 4px;">'
    + '<div style="color:var(--sub);font-size:11px;letter-spacing:0.05em;'
    + 'text-transform:uppercase;padding:6px 16px 4px;">Aujourd\'hui Â· ' + _todayName + '</div>'
    + '<div style="margin:0 12px 8px;background:var(--surface,#16162a);'
    + 'border:0.5px solid rgba(167,139,250,0.2);border-radius:16px;padding:14px;">'
    + '<div style="display:flex;justify-content:space-between;align-items:flex-start;'
    + 'margin-bottom:10px;gap:10px;">'
    + '<div style="min-width:0;flex:1;">'
    + '<div style="color:var(--text);font-size:14px;font-weight:600;white-space:nowrap;'
    + 'overflow:hidden;text-overflow:ellipsis;">' + (_todayDay.title || 'SÃĐance') + '</div>'
    + '<div style="color:var(--sub);font-size:11px;margin-top:2px;">~' + _durMin + ' min</div>'
    + '</div>' + _goBtn + '</div>'
    + _exoRows
    + '</div></div>';
}

// ââ MAISON v264 â Programme + SÃĐance + Stats + Records ââââââââââââââââââââââ
function renderTodaySessionInline() {
  var container = document.getElementById('todaySessionInline');
  if (!container) return;
  var selectedDay = db._selectedProgramDay || null;
  container.innerHTML =
    renderProgrammeSemaineTimeline(selectedDay) +
    '<div style="height:8px;"></div>' +
    renderSeanceSelected(selectedDay) +
    renderStatsCompact() +
    renderRecordsPersonnels();
}

// DÃĐtermine le jour de sÃĐance actif (sÃĐlection manuelle > aujourd'hui > prochaine sÃĐance).
// Retourne un objet { day, ...data } depuis db.weeklyPlan.days, ou null.
function getActiveProgramDay() {
  var joursFR = ['Dimanche','Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi'];
  var todayName = joursFR[new Date().getDay()];
  var days = (db.weeklyPlan && db.weeklyPlan.days) || [];
  if (!days.length) return null;

  // 1. Jour sÃĐlectionnÃĐ manuellement
  var selectedDay = db._selectedProgramDay;
  if (selectedDay) {
    var found = days.find(function(d) { return d.day === selectedDay; });
    if (found) return found;
  }

  // 2. Aujourd'hui s'il a une sÃĐance
  var todayData = days.find(function(d) { return d.day === todayName && !d.rest && d.exercises && d.exercises.length; });
  if (todayData) return todayData;

  // 3. Prochain jour de sÃĐance (sans repos)
  var joursOrder = ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi','Dimanche'];
  var todayIdx = joursOrder.indexOf(todayName);
  for (var i = 1; i <= 7; i++) {
    var nextIdx = (todayIdx + i) % 7;
    var nextDay = days.find(function(d) { return d.day === joursOrder[nextIdx] && !d.rest && d.exercises && d.exercises.length; });
    if (nextDay) return nextDay;
  }

  // 4. Fallback â premier jour non-repos puis n'importe quel jour
  return days.find(function(d) { return !d.rest; }) || days[0];
}

window.goDirectFromHome = function() {
  // PrÃĐ-sÃĐlectionne le bon jour (auj. ou prochaine sÃĐance si auj. = repos)
  var active = typeof getActiveProgramDay === 'function' ? getActiveProgramDay() : null;
  if (active && active.day) {
    db._selectedProgramDay = active.day;
    if (typeof saveDB === 'function') saveDB();
  }

  // Flux strictement identique Ã  "Lancer la sÃĐance du jour"
  if (typeof showTab === 'function') showTab('tab-seances');
  if (typeof showSeancesSub === 'function') showSeancesSub('s-go');
  setTimeout(function() {
    if (typeof goStartWorkout === 'function' && !(db && db._currentGoSession)) {
      goStartWorkout(true);
    }
  }, 150);
};

window.selectProgramDay = function(jour) {
  db._selectedProgramDay = jour;
  renderTodaySessionInline();
};

// ââ 1. PROGRAMME SEMAINE â timeline 7 jours cliquable ââââââââââââââââââââââââ
function renderProgrammeSemaineTimeline(selectedDay) {
  var days = (db.weeklyPlan && db.weeklyPlan.days) || [];
  var joursFR = ['Dimanche','Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi'];
  var todayName = joursFR[new Date().getDay()];
  var activeName = selectedDay || todayName;

  var typeColors = { hypertrophie: '#7c6bff', force: '#ff6b6b', deload: '#5fc85f' };
  var currentPhase = (db.weeklyPlan && db.weeklyPlan.currentBlock && db.weeklyPlan.currentBlock.phase) || 'hypertrophie';
  var accentColor = typeColors[currentPhase] || '#7c6bff';

  var weekStart = typeof _getWeekStart === 'function' ? _getWeekStart(Date.now()).getTime() : Date.now() - 7 * 86400000;
  var loggedDays = {};
  (db.logs || []).forEach(function(log) {
    if (log.timestamp >= weekStart) {
      loggedDays[joursFR[new Date(log.timestamp).getDay()]] = true;
    }
  });

  var jours7 = ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi','Dimanche'];
  var totalPlanned = 0;
  jours7.forEach(function(j) {
    var d = days.find(function(x) { return x.day === j; });
    if (d && !d.rest && d.exercises && d.exercises.length) totalPlanned++;
  });
  var doneCount = Object.keys(loggedDays).length;

  var cols = jours7.map(function(jour) {
    var dayData = days.find(function(d) { return d.day === jour; });
    var isDone = !!loggedDays[jour];
    var isSelected = jour === activeName;
    var isRest = !dayData || dayData.rest;
    var shortName = jour.slice(0, 3).toUpperCase();
    var sessionTitle = dayData && !isRest
      ? (dayData.title || jour).replace(/[^A-Za-zÃ-Ãŋ0-9\s]/g, '').split(' ').slice(0, 2).join(' ')
      : '';

    var bg = isDone ? 'rgba(26,58,26,0.8)' : isSelected ? 'rgba(26,26,58,1)' : 'rgba(20,20,40,0.7)';
    var border = isSelected ? '2px solid ' + accentColor : (isDone ? '1px solid #2a4a2a' : '1px solid #1a1a2e');
    var dayColor = isDone ? '#5fc85f' : isSelected ? accentColor : '#4a4a6a';

    return '<div onclick="selectProgramDay(\'' + jour + '\')" style="flex:1;background:' + bg + ';'
      + 'border:' + border + ';border-radius:8px;padding:4px 2px;text-align:center;cursor:pointer;min-width:0;">'
      + '<div style="font-size:7px;font-family:monospace;color:' + dayColor + ';letter-spacing:1px;margin-bottom:4px;">' + shortName + '</div>'
      + (isDone ? '<div style="font-size:11px;color:#5fc85f;">â</div>'
         : isRest ? '<div style="font-size:14px;">ðĪ</div>'
         : isSelected ? '<div style="width:8px;height:8px;border-radius:50%;background:' + accentColor + ';margin:2px auto;"></div>'
         : '<div style="font-size:8px;color:#3a3a5a;">Â·</div>')
      + (sessionTitle ? '<div style="font-size:6px;color:' + (isSelected ? '#fff' : '#9999bb')
          + ';margin-top:2px;line-height:1.2;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + sessionTitle + '</div>' : '')
      + (dayData && !isRest
          ? '<div style="width:14px;height:2px;border-radius:1px;background:' + (isSelected ? accentColor : accentColor + '55') + ';margin:3px auto 0;"></div>'
          : '')
      + '</div>';
  }).join('');

  var weekNum = (db.weeklyPlan && db.weeklyPlan.currentBlock && db.weeklyPlan.currentBlock.week) || 'â';

  return '<div style="padding:0 12px;">'
    + '<div style="margin-bottom:4px;display:flex;justify-content:space-between;align-items:center;">'
    + '<span style="font-size:8px;color:#9999bb;font-family:monospace;letter-spacing:2px;">SEMAINE ' + weekNum + '</span>'
    + '<span style="font-size:8px;color:#5fc85f;font-family:monospace;">' + doneCount + '/' + (totalPlanned || 'â') + ' â</span>'
    + '</div>'
    + '<div style="display:flex;gap:4px;">' + cols + '</div>'
    + '</div>';
}

// ââ 2. SÃANCE SÃLECTIONNÃE â tous les exercices numÃĐrotÃĐs + GO âââââââââââââââ
function renderSeanceSelected(selectedDay) {
  var days = (db.weeklyPlan && db.weeklyPlan.days) || [];
  var joursFR = ['Dimanche','Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi'];
  var todayName = joursFR[new Date().getDay()];

  // Si aucune sÃĐlection manuelle : utiliser le prochain jour de sÃĐance plutÃīt que today (qui peut ÃŠtre repos)
  var dayData;
  var activeName;
  if (selectedDay) {
    activeName = selectedDay;
    dayData = days.find(function(d) { return d.day === activeName; });
  } else {
    var active = typeof getActiveProgramDay === 'function' ? getActiveProgramDay() : null;
    dayData = active || days.find(function(d) { return d.day === todayName; });
    activeName = (dayData && dayData.day) || todayName;
  }
  var currentPhase = (db.weeklyPlan && db.weeklyPlan.currentBlock && db.weeklyPlan.currentBlock.phase) || 'hypertrophie';
  var gradient = currentPhase === 'force'
    ? 'linear-gradient(135deg,#8b1a1a,#5a1010)'
    : currentPhase === 'deload'
    ? 'linear-gradient(135deg,#1a3a2a,#0f2a1a)'
    : 'linear-gradient(135deg,#7c6bff,#4a3ab8)';

  var isToday = activeName === todayName;
  // Sans sÃĐlection manuelle, un jour de repos fait sauter la carte au prochain
  // jour d'entraÃŪnement (getActiveProgramDay) : l'annoncer explicitement pour
  // ne pas laisser croire que c'est la sÃĐance du jour (audit ð -2).
  var isNextDay = !selectedDay && !isToday;
  var dateStr = activeName + (isToday ? ' Â· Aujourd\'hui' : '');

  if (!dayData || dayData.rest) {
    return '<div style="padding:0 12px;">'
      + '<div style="background:#141428;border-radius:14px;padding:16px;text-align:center;margin-bottom:8px;">'
      + '<div style="font-size:11px;color:#4a4a6a;letter-spacing:2px;font-family:monospace;margin-bottom:8px;">SÃANCE Â· ' + activeName.toUpperCase() + '</div>'
      + '<div style="font-size:28px;">ðĪ</div>'
      + '<div style="font-size:11px;color:#6a6a8a;margin-top:6px;">Repos Â· rÃĐcupÃĐration active</div>'
      + '</div></div>';
  }

  var exercises = dayData.exercises || [];
  var displayExos = exercises.filter(function(e) {
    return e && e.name && !e.isWarmup && !(e.setType === 'warmup') && !e.isWarmupOnly;
  });

  var exosHtml = displayExos.map(function(exo, i) {
    var setsAll = Array.isArray(exo.sets) ? exo.sets : [];
    var workSets = setsAll.filter(function(s) { return s && !s.isWarmup && s.setType !== 'warmup'; });
    var firstWork = workSets[0] || {};
    var weightStr = firstWork.weight ? firstWork.weight + 'kg' : (exo.useBodyweight || exo.bodyweight ? 'PDC' : 'â');
    var setsStr = workSets.length > 0
      ? workSets.length + 'Ã' + (firstWork.reps || 'â')
      : (setsAll.length ? setsAll.length + 'Ãâ' : 'â');
    var isCardio = /tapis|cardio|natation|vÃĐlo|velo|course/i.test(exo.name || '');
    var opacity = isCardio ? '0.5' : '0.9';
    var numStr = (i + 1 < 10 ? '0' : '') + (i + 1);

    return '<div style="display:flex;align-items:center;padding:7px 0;">'
      + '<span style="font-size:7px;color:#fff;opacity:0.35;font-family:monospace;width:18px;flex-shrink:0;">' + numStr + '</span>'
      + '<span style="font-size:10px;color:#fff;opacity:' + opacity + ';flex:1;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + (exo.name || '') + '</span>'
      + '<span style="font-size:9px;color:#fff;opacity:0.8;font-family:monospace;flex-shrink:0;margin-left:8px;">' + setsStr + ' Â· ' + weightStr + '</span>'
      + '</div>'
      + (i < displayExos.length - 1 ? '<div style="height:0.5px;background:#fff;opacity:0.08;"></div>' : '');
  }).join('');

  var srsScore = null;
  try { srsScore = typeof computeSRS === 'function' ? computeSRS() : null; } catch (e) {}
  var coachHint = (srsScore && srsScore.score < 50)
    ? '<div style="background:rgba(255,255,255,0.12);border-radius:6px;padding:4px 10px;display:inline-block;margin-bottom:8px;">'
      + '<span style="font-size:7.5px;font-family:monospace;color:#fff;">â  Forme basse Â· adapte le volume</span></div>'
    : '';

  var duration = dayData.estimatedDuration
    || (db.user && db.user.programParams && db.user.programParams.duration)
    || 90;

  var btnHtml = isToday
    ? '<button onclick="goDirectFromHome()" style="padding:8px 20px;background:#fff;border:none;border-radius:20px;'
      + 'font-size:11px;font-weight:700;color:#7c6bff;cursor:pointer;">GO ðŠ</button>'
    : '<span style="font-size:9px;color:#fff;opacity:0.5;font-family:monospace;">AperÃ§u</span>';

  return '<div style="padding:0 12px;">'
    + '<div style="font-size:8px;color:#7c6bff;font-family:monospace;letter-spacing:2px;margin-bottom:4px;">' + (isNextDay ? 'PROCHAINE SÃANCE Â· ' : 'SÃANCE Â· ') + dateStr.toUpperCase() + '</div>'
    + '<div style="background:' + gradient + ';border-radius:14px;padding:14px 16px;margin-bottom:8px;">'
    + coachHint
    + '<div style="font-size:16px;font-weight:700;color:#fff;margin-bottom:2px;">' + (dayData.title || activeName) + '</div>'
    + '<div style="font-size:9px;color:#fff;opacity:0.6;margin-bottom:8px;">'
    + duration + ' min Â· ' + displayExos.length + ' exercice' + (displayExos.length > 1 ? 's' : '')
    + '</div>'
    + '<div style="border-top:1px solid rgba(255,255,255,0.1);padding-top:6px;margin-bottom:10px;">' + exosHtml + '</div>'
    + '<div style="display:flex;justify-content:flex-end;align-items:center;">' + btnHtml + '</div>'
    + '</div></div>';
}

// ââ 3. STATS COMPACT â 1 ligne (4 colonnes) ââââââââââââââââââââââââââââââââââ
function renderStatsCompact() {
  var logs = db.logs || [];
  var weekStart = typeof _getWeekStart === 'function' ? _getWeekStart(Date.now()).getTime() : Date.now() - 7 * 86400000;
  var weekLogs = logs.filter(function(l) { return l && l.timestamp >= weekStart; });
  var totalDurationSec = weekLogs.reduce(function(acc, l) { return acc + (l.duration || 0); }, 0);
  var totalDurationMin = Math.round(totalDurationSec / 60);
  var totalTonnage = weekLogs.reduce(function(acc, l) {
    if (l.volume) return acc + l.volume;
    (l.exercises || []).forEach(function(e) {
      (e.allSets || e.series || []).forEach(function(s) {
        if (!s.isWarmup && s.setType !== 'warmup' && s.weight && s.reps) acc += s.weight * s.reps;
      });
    });
    return acc;
  }, 0);

  var streak = (typeof calcStreak === 'function') ? calcStreak() : ((db.user && db.user.weekStreak) || 0);

  var durationStr;
  if (totalDurationMin <= 0) durationStr = 'â';
  else if (totalDurationMin >= 60) {
    var h = Math.floor(totalDurationMin / 60);
    var m = totalDurationMin % 60;
    durationStr = h + 'h' + (m > 0 ? (m < 10 ? '0' : '') + m : '');
  } else durationStr = totalDurationMin + 'm';

  var tonnageStr = totalTonnage > 0
    ? (totalTonnage >= 1000 ? Math.round(totalTonnage / 1000) + 't' : Math.round(totalTonnage) + 'kg')
    : 'â';

  var items = [
    { val: weekLogs.length || 'â', lbl: 'SÃANCES', color: '#5fc85f' },
    { val: durationStr,            lbl: 'DURÃE',   color: '#7c6bff' },
    { val: tonnageStr,             lbl: 'TONNAGE', color: '#ffa500' },
    { val: streak > 0 ? streak + ' ðĨ' : 'â', lbl: 'STREAK', color: '#ff8c42' }
  ];

  var cols = items.map(function(item, i) {
    return (i > 0 ? '<div style="width:0.5px;background:#2a2a45;margin:4px 0;"></div>' : '')
      + '<div style="flex:1;text-align:center;min-width:0;">'
      + '<div style="font-size:13px;font-weight:700;color:' + item.color + ';font-family:ui-monospace,monospace;">' + item.val + '</div>'
      + '<div style="font-size:6px;color:#4a4a6a;letter-spacing:1px;margin-top:2px;">' + item.lbl + '</div>'
      + '</div>';
  }).join('');

  return '<div style="padding:0 12px;">'
    + '<div style="display:flex;align-items:center;background:#141428;border-radius:10px;padding:6px 8px;margin-bottom:8px;">' + cols + '</div>'
    + '</div>';
}

// ââ 4. RECORDS PERSONNELS â barres + messages Gemini âââââââââââââââââââââââââ
function renderRecordsPersonnels() {
  var tgt = (db.user && db.user.targets) || {};
  // e1RM affichÃĐ = max HISTORIQUE (mÃŠme source que StatsâRecords), jamais le
  // registre DUP vivant (il baisse avec l'autorÃĐgulation â 138 vs 148 device).
  // Garde-fou : jamais < la vraie barre (bestPR).
  function _displayE1RM(key) {
    var best = (typeof getBestE1RMForLift === 'function') ? getBestE1RMForLift(key) : 0;
    return Math.max(best, (db.bestPR && db.bestPR[key]) || 0);
  }
  var lifts = [
    { key: 'squat', label: 'SQUAT', color: '#4a8fff',
      pr: (db.bestPR && db.bestPR.squat) || 0,
      e1rm: _displayE1RM('squat'),
      obj: tgt.squat || 160 },
    { key: 'bench', label: 'BENCH', color: '#5fc85f',
      pr: (db.bestPR && db.bestPR.bench) || 0,
      e1rm: _displayE1RM('bench'),
      obj: tgt.bench || 143 },
    { key: 'deadlift', label: 'DEAD', color: '#ff6b6b',
      pr: (db.bestPR && db.bestPR.deadlift) || 0,
      e1rm: _displayE1RM('deadlift'),
      obj: tgt.deadlift || 190 }
  ];

  var plannedTestDate = (db.user && db.user.plannedTestDate)
    ? new Date(db.user.plannedTestDate)
    : new Date(Date.now() + 35 * 86400000);
  var testDateStr = plannedTestDate.toLocaleDateString('fr-FR', { day: 'numeric', month: 'short' });
  var vocabLevel = (db.user && db.user.vocabLevel) || 2;

  var statusColors = { ON_TRACK: '#5fc85f', AMBITIOUS: '#ffa500', FATIGUE_MASKED: '#9966ff' };
  var statusIcons  = { ON_TRACK: 'â',        AMBITIOUS: 'âĄ',       FATIGUE_MASKED: 'âģ' };

  var rows = lifts.map(function(lift, i) {
    var history = (typeof buildE1rmHistory === 'function') ? buildE1rmHistory(lift.key) : [];
    var msg = (typeof getProgressionMessage === 'function')
      ? getProgressionMessage(lift.key, history, lift.pr, lift.obj, plannedTestDate, vocabLevel)
      : { line1: '', line2: '', status: 'ON_TRACK' };

    var msgColor = statusColors[msg.status] || lift.color;
    var msgIcon  = statusIcons[msg.status] || '';
    var pct = lift.obj > 0 ? Math.min(100, Math.round((lift.pr / lift.obj) * 100)) : 0;

    return (i > 0 ? '<div style="height:0.5px;background:#1e1e2e;"></div>' : '')
      + '<div style="padding:12px 14px;">'
      + '<div style="display:flex;align-items:baseline;margin-bottom:5px;">'
      + '<span style="font-size:9px;color:' + lift.color + ';font-family:monospace;letter-spacing:1px;">' + lift.label + '</span>'
      + '<span style="flex:1;"></span>'
      + '<span style="font-size:14px;font-weight:700;color:#e8e8ff;font-family:ui-monospace,monospace;">' + lift.pr + '<span style="font-size:9px;color:#4a4a6a;">kg</span></span>'
      + '<span style="font-size:9px;color:#4a4a6a;font-family:monospace;margin-left:6px;">/ ' + lift.obj + '</span>'
      + '</div>'
      + '<div style="background:#1a1a2e;border-radius:2px;height:4px;margin-bottom:8px;overflow:hidden;">'
      + '<div style="height:4px;width:' + pct + '%;background:' + lift.color + ';border-radius:2px;opacity:0.85;"></div>'
      + '</div>'
      // Philosophie B : la vraie barre (bestPR) est le record ; l'e1RM reste
      // visible mais toujours ÃĐtiquetÃĐ comme estimation, jamais comme record.
      + (lift.e1rm > 0 ? '<div style="font-size:8px;color:#6a6a8a;font-family:monospace;margin-bottom:4px;">e1RM estimÃĐ : ' + Math.round(lift.e1rm) + ' kg</div>' : '')
      + '<div style="font-size:8.5px;color:' + msgColor + ';font-weight:600;margin-bottom:2px;">' + msgIcon + ' ' + (msg.line1 || '') + '</div>'
      + '<div style="font-size:7.5px;color:#6a6a8a;">' + (msg.line2 || '') + '</div>'
      + '</div>';
  }).join('');

  return '<div style="padding:0 12px 16px;">'
    + '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px;">'
    + '<span style="font-size:8px;color:#9999bb;font-family:monospace;letter-spacing:2px;">RECORDS PERSONNELS</span>'
    + '<span style="font-size:7.5px;color:#4a4a6a;font-family:monospace;">Test : ' + testDateStr + '</span>'
    + '</div>'
    + '<div style="background:#141428;border-radius:14px;overflow:hidden;margin-bottom:8px;">' + rows + '</div>'
    + '</div>';
}

// ââ SWIPE EXERCICES â Onboarding bonus (Gemini) ââââââââââââââââââââââââââââââ
