function pbStartGuided() {
  // Pre-select goal/freq/days/duration from existing programParams + trainingMode
  // so users with an existing program land on their current settings.
  var currentMode = (db.user && db.user.trainingMode) || 'powerbuilding';
  var modeToGoal = {
    powerbuilding:  'mixte',
    powerlifting:   'force',
    musculation:    'hypertrophie',
    bien_etre:      'remise_en_forme',
    bodybuilding:   'hypertrophie'
  };
  var pp = (db.user && db.user.programParams) || {};
  _pbState = {
    mode: 'guided',
    step: 1,
    days: pp.freq || 4,
    selectedDays: (Array.isArray(pp.selectedDays) && pp.selectedDays.length > 0) ? pp.selectedDays.slice() : [],
    goal: modeToGoal[currentMode] || 'mixte',
    equipment: _pbEquipmentFromMat(pp.mat || 'salle'),
    duration: pp.duration || 60,
    level: db.user.level || 'intermediaire',
    blockedDays: []
  };
  _pbDayMode = 'manual';
  renderProgramBuilder();
}

// Translate the saved 'mat' setting back into the wizard equipment array.
function _pbEquipmentFromMat(mat) {
  if (mat === 'halteres') return ['dumbbell','cable'];
  if (mat === 'maison')   return ['dumbbell','bodyweight'];
  return ['barbell','dumbbell','machine','cable'];
}

// Default day-of-week distributions for each frequency â avoids Wed/Sun by default
function _pbDefaultDaysForFreq(freq) {
  var defaults = {
    2: ['Lundi','Jeudi'],
    3: ['Lundi','Mercredi','Vendredi'],
    4: ['Lundi','Mardi','Jeudi','Vendredi'],
    5: ['Lundi','Mardi','Jeudi','Vendredi','Samedi'],
    6: ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi']
  };
  return (defaults[freq] || ['Lundi','Mercredi','Vendredi']).slice();
}

function pbSetDaysAndAdvance(d) {
  _pbState.days = d;
  // Pre-seed sensible day distribution so user can adjust rather than start blank
  _pbState.selectedDays = _pbDefaultDaysForFreq(d);
  _pbState.step = 2;
  renderProgramBuilder();
}

function pbToggleDay(day) {
  if (!_pbState.selectedDays) _pbState.selectedDays = [];
  var idx = _pbState.selectedDays.indexOf(day);
  if (idx >= 0) {
    _pbState.selectedDays.splice(idx, 1);
  } else if (_pbState.selectedDays.length < _pbState.days) {
    _pbState.selectedDays.push(day);
  }
  renderProgramBuilder();
}

// Pick freq best training days from `available` (excludes blocked days).
// Prefers a per-frequency ideal spread (e.g. Mon/Wed/Fri for 3j), then fills
// from remaining available days if blocked days reduced the ideal set below freq.
function _pbOptimizeDays(available, freq) {
  var dayIdx = { Lundi:0, Mardi:1, Mercredi:2, Jeudi:3, Vendredi:4, Samedi:5, Dimanche:6 };
  var IDEAL = {
    2: ['Lundi','Jeudi'],
    3: ['Lundi','Mercredi','Vendredi'],
    4: ['Lundi','Mardi','Jeudi','Vendredi'],
    5: ['Lundi','Mardi','Jeudi','Vendredi','Samedi'],
    6: ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi']
  };
  var ideal = IDEAL[freq] || IDEAL[4];
  var picked = ideal.filter(function(d) { return available.indexOf(d) >= 0; });
  if (picked.length < freq) {
    available.forEach(function(d) {
      if (picked.length < freq && picked.indexOf(d) < 0) picked.push(d);
    });
  }
  picked.sort(function(a, b) { return (dayIdx[a]||0) - (dayIdx[b]||0); });
  return picked.slice(0, freq);
}

// Mode B â Algo libre : pick days, avoiding days blocked by secondary activities.
function pbAlgoPickDays() {
  var freq = _pbState.days || 4;
  var allDaysW = ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi','Dimanche'];
  var blocked = [];
  var template = (db.user && db.user.activityTemplate) || [];
  template.forEach(function(act) {
    (act.days || []).forEach(function(d) {
      if (blocked.indexOf(d) < 0) blocked.push(d);
    });
  });
  var available = allDaysW.filter(function(d) { return blocked.indexOf(d) < 0; });
  _pbState.selectedDays = _pbOptimizeDays(available, freq);
}

// Mode C â Algo contraint : toggle a user-blocked day (rouge), algo re-picks.
function pbToggleBlockedDay(day) {
  if (!_pbState.blockedDays) _pbState.blockedDays = [];
  var idx = _pbState.blockedDays.indexOf(day);
  if (idx >= 0) _pbState.blockedDays.splice(idx, 1);
  else _pbState.blockedDays.push(day);
  renderProgramBuilder();
}

function showCustomBuilderChoice() {
  var hasExisting = db.customProgramTemplate ||
    (db.weeklyPlan && db.weeklyPlan.days && db.weeklyPlan.days.some(function(d) { return !d.rest; }));
  if (!hasExisting) { pbStartCustomBuilder(false); return; }

  var o = document.createElement('div');
  o.className = 'modal-overlay';
  o.innerHTML = '<div class="modal-box">'
    + '<p style="margin:0 0 16px;font-size:14px;font-weight:700;">Point de dÃĐpart :</p>'
    + '<div style="display:flex;flex-direction:column;gap:10px;">'
    + '<button id="_cbFromExisting" style="padding:12px;background:rgba(10,132,255,0.1);'
    + 'border:1px solid var(--accent);border-radius:10px;color:var(--accent);'
    + 'font-size:14px;font-weight:600;cursor:pointer;">ð Partir de mon programme actuel</button>'
    + '<button id="_cbBlank" style="padding:12px;background:var(--surface);'
    + 'border:1px solid var(--border);border-radius:10px;color:var(--text);'
    + 'font-size:14px;cursor:pointer;">ð Page blanche</button>'
    + '</div></div>';
  _uiOpen(o, { dismissible: true });
  o.querySelector('#_cbFromExisting').onclick = function() { closeModalEl(o); pbStartCustomBuilder(true); };
  o.querySelector('#_cbBlank').onclick = function() { closeModalEl(o); pbStartCustomBuilder(false); };
}

// ââ CUSTOM BUILDER â state âââââââââââââââââââââââââââââââââââ
var _customBuilderState = null;
var _customBuilderDaySelected = null;

function pbStartCustomBuilder(fromExisting) {
  var now = Date.now();
  if (fromExisting && db.customProgramTemplate) {
    _customBuilderState = JSON.parse(JSON.stringify(db.customProgramTemplate));
  } else if (fromExisting && db.weeklyPlan && db.weeklyPlan.days) {
    var allDaysFull = ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi','Dimanche'];
    _customBuilderState = {
      id: 'template_' + now,
      name: 'Mon Programme',
      createdAt: now,
      updatedAt: now,
      coachProfile: (db.user && db.user.coachProfile) || 'full',
      currentBlockIndex: 0,
      currentBlockStartDate: now,
      blocks: [{
        id: 'block_1',
        name: 'Bloc 1',
        durationWeeks: 8,
        deloadAfter: true,
        sessions: db.weeklyPlan.days
          .filter(function(d) { return !d.rest; })
          .map(function(d, i) {
            var dayIdx = allDaysFull.indexOf(d.day);
            return {
              dayIndex: dayIdx >= 0 ? dayIdx : i,
              label: d.title || d.day,
              exercises: (d.exercises || [])
                .filter(function(e) { return !e.isWarmup && !e.isPrehab; })
                .map(function(e) {
                  var meta = typeof wpGetExoMeta === 'function' ? wpGetExoMeta(e.name) : null;
                  var defaultSlot = e.isPrimary ? 'main_lift'
                    : (meta && meta.mechanic === 'isolation') ? 'isolation' : 'accessory';
                  return {
                    id: (e.name || '').toLowerCase().replace(/\s+/g,'_').replace(/[^a-z0-9_]/g,''),
                    name: e.name,
                    slot: defaultSlot,
                    defaultSlot: defaultSlot,
                    customNote: '',
                    addedAt: now
                  };
                })
            };
          })
      }]
    };
  } else {
    _customBuilderState = {
      id: 'template_' + now,
      name: 'Mon Programme',
      createdAt: now,
      updatedAt: now,
      coachProfile: (db.user && db.user.coachProfile) || 'full',
      currentBlockIndex: 0,
      currentBlockStartDate: now,
      blocks: [{ id: 'block_1', name: 'Bloc 1', durationWeeks: 8, deloadAfter: true, sessions: [] }]
    };
  }
  _customBuilderDaySelected = null;
  renderCustomBuilder();
}

function renderCustomBuilder() {
  var container = document.getElementById('programBuilderContent');
  if (!container) return;
  if (!_customBuilderState) { renderProgramBuilder(); return; }

  var tmpl = _customBuilderState;
  var block = tmpl.blocks[tmpl.currentBlockIndex || 0];
  var allDays = ['Lun','Mar','Mer','Jeu','Ven','Sam','Dim'];
  var allDaysFull = ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi','Dimanche'];

  var h = '';

  // Header â nom + bouton sauver + bouton annuler
  h += '<div style="display:flex;align-items:center;gap:10px;margin-bottom:14px;">';
  h += '<input value="' + escapeHtml(tmpl.name) + '" '
    + 'oninput="_customBuilderState.name=this.value" '
    + 'style="flex:1;padding:8px 10px;background:var(--surface);border:1px solid var(--border);'
    + 'border-radius:10px;color:var(--text);font-size:15px;font-weight:700;">';
  h += '<button onclick="cancelCustomBuilder()" '
    + 'style="padding:8px 12px;background:none;border:1px solid var(--border);border-radius:10px;'
    + 'color:var(--sub);font-size:13px;cursor:pointer;">â</button>';
  h += '<button onclick="saveCustomTemplate()" '
    + 'style="padding:8px 14px;background:var(--accent);border:none;border-radius:10px;'
    + 'color:#fff;font-weight:700;font-size:13px;cursor:pointer;">ðū Sauver</button>';
  h += '</div>';

  // Vue semaine â 7 cases
  h += '<div style="display:grid;grid-template-columns:repeat(7,1fr);gap:4px;margin-bottom:14px;">';
  allDaysFull.forEach(function(dayFull, idx) {
    var session = (block.sessions || []).find(function(s) { return s.dayIndex === idx; });
    var hasSession = !!session;
    var isSelected = _customBuilderDaySelected === idx;
    var dayShort = allDays[idx];
    h += '<div onclick="selectCustomDay(' + idx + ')" style="padding:8px 4px;border-radius:10px;'
      + 'border:1px solid ' + (isSelected ? 'var(--accent)' : hasSession ? 'rgba(50,215,75,0.4)' : 'var(--border)') + ';'
      + 'background:' + (isSelected ? 'rgba(10,132,255,0.15)' : hasSession ? 'rgba(50,215,75,0.08)' : 'var(--surface)') + ';'
      + 'text-align:center;cursor:pointer;">';
    h += '<div style="font-size:10px;font-weight:600;color:'
      + (isSelected ? 'var(--accent)' : hasSession ? 'var(--green)' : 'var(--sub)') + ';">'
      + dayShort + '</div>';
    h += '<div style="width:6px;height:6px;border-radius:50%;margin:4px auto 0;background:'
      + (hasSession ? 'var(--green)' : 'transparent') + ';border:1px solid var(--border);"></div>';
    h += '</div>';
  });
  h += '</div>';

  // Ãditeur du jour sÃĐlectionnÃĐ
  if (_customBuilderDaySelected !== null) {
    var dayFull = allDaysFull[_customBuilderDaySelected];
    var session = (block.sessions || []).find(function(s) { return s.dayIndex === _customBuilderDaySelected; });

    h += '<div style="background:var(--surface);border-radius:12px;padding:14px;margin-bottom:12px;">';
    if (!session) {
      h += '<div style="text-align:center;padding:20px 0;">';
      h += '<div style="font-size:13px;color:var(--sub);margin-bottom:12px;">' + escapeHtml(dayFull) + ' â Repos</div>';
      h += '<button onclick="addCustomSession(' + _customBuilderDaySelected + ')" '
        + 'style="padding:8px 16px;background:rgba(10,132,255,0.1);border:1px dashed var(--accent);'
        + 'border-radius:10px;color:var(--accent);font-size:13px;cursor:pointer;">+ Ajouter une sÃĐance</button>';
      h += '</div>';
    } else {
      h += '<div style="display:flex;align-items:center;gap:8px;margin-bottom:12px;">';
      h += '<input value="' + escapeHtml(session.label || dayFull) + '" '
        + 'oninput="updateCustomSessionLabel(' + _customBuilderDaySelected + ',this.value)" '
        + 'style="flex:1;padding:7px 10px;background:var(--bg);border:1px solid var(--border);'
        + 'border-radius:8px;color:var(--text);font-size:13px;font-weight:700;">';
      h += '<button onclick="removeCustomSession(' + _customBuilderDaySelected + ')" '
        + 'style="background:none;border:none;color:var(--red);font-size:18px;cursor:pointer;">ð</button>';
      h += '</div>';
      h += '<div style="font-size:10px;color:var(--sub);margin-bottom:10px;">ðĄ Appuie sur le badge pour changer le type d\'exercice</div>';

      var exos = session.exercises || [];
      if (exos.length === 0) {
        h += '<div style="text-align:center;padding:10px;color:var(--sub);font-size:12px;">Aucun exercice â ajoutes-en depuis la bibliothÃĻque</div>';
      } else {
        exos.forEach(function(exo, ei) {
          var slotColor = exo.slot === 'main_lift' ? 'var(--accent)' : exo.slot === 'isolation' ? 'var(--purple,#bf5af2)' : 'var(--orange)';
          var slotLabel = exo.slot === 'main_lift' ? 'ðïļ Principal' : exo.slot === 'isolation' ? 'ðŊ Isolation' : 'ðŠ Accessoire';
          var isMainLiftMisplaced = exo.slot === 'main_lift' && ei > 0;
          h += '<div style="display:flex;align-items:center;gap:8px;padding:8px 0;border-bottom:1px solid rgba(255,255,255,0.05);">';
          h += '<span style="width:8px;height:8px;border-radius:50%;background:' + slotColor + ';flex-shrink:0;"></span>';
          h += '<div style="flex:1;font-size:13px;color:var(--text);">' + escapeHtml(exo.name);
          if (isMainLiftMisplaced) h += ' <span style="font-size:10px;">ðĄ</span>';
          h += '</div>';
          h += '<div style="display:flex;gap:2px;align-items:center;">';
          if (ei > 0) {
            h += '<button onclick="moveCustomExo(' + _customBuilderDaySelected + ',' + ei + ',-1)" '
              + 'style="background:none;border:none;color:var(--sub);cursor:pointer;font-size:14px;padding:2px 4px;">â</button>';
          }
          if (ei < exos.length - 1) {
            h += '<button onclick="moveCustomExo(' + _customBuilderDaySelected + ',' + ei + ',1)" '
              + 'style="background:none;border:none;color:var(--sub);cursor:pointer;font-size:14px;padding:2px 4px;">â</button>';
          }
          h += '<button onclick="cycleCustomExoSlot(' + _customBuilderDaySelected + ',' + ei + ')" '
            + 'style="background:none;border:none;color:' + slotColor + ';cursor:pointer;font-size:10px;font-weight:600;'
            + 'padding:2px 7px;border:1px solid ' + slotColor + '40;border-radius:6px;white-space:nowrap;">' + slotLabel + '</button>';
          h += '<button onclick="removeCustomExo(' + _customBuilderDaySelected + ',' + ei + ')" '
            + 'style="background:none;border:none;color:var(--red);cursor:pointer;font-size:14px;padding:2px 4px;">Ã</button>';
          h += '</div>';
          h += '</div>';
        });
      }
      h += '<button onclick="openExoLibrary(' + _customBuilderDaySelected + ')" '
        + 'style="width:100%;margin-top:10px;padding:8px;background:none;border:1px dashed var(--accent);'
        + 'border-radius:10px;color:var(--accent);font-size:13px;cursor:pointer;">+ Ajouter un exercice</button>';
    }
    h += '</div>';
  }

  container.innerHTML = h;

  if (_customBuilderDaySelected !== null) {
    var sess = (block.sessions || []).find(function(s) { return s.dayIndex === _customBuilderDaySelected; });
    if (sess) renderExoLibrary(_customBuilderDaySelected);
  }
}

// ââ BIBLIOTHÃQUE D'EXERCICES âââââââââââââââââââââââââââââââââ
var _libraryFilter = { group: null, search: '' };
var _skipNextPlanSnapshot = false;

function updateActiveProgramStats() {
  if (!db.customProgramBackups || !db.customProgramBackups.length) return;
  var active = db.customProgramBackups[0];
  active.sessionCount = (active.sessionCount || 0) + 1;
  active.lastUsedAt = Date.now();
}

// ââ BACKUPS DE PROGRAMME (allÃĐgÃĐs v291) ââââââââââââââââââââââ
// Un backup ne stocke plus weeklyPlan/mesoWeeks (dÃĐrivÃĐ, rÃĐgÃĐnÃĐrable) quand il
// porte une structure rÃĐgÃĐnÃĐrable (customProgramTemplate). Sans template (legacy/
// auto), on conserve le weeklyPlan figÃĐ : c'est sa seule structure restaurable.
// Discriminant FIABLE = prÃĐsence de customProgramTemplate (PAS programMode, qui
// peut valoir 'auto' mÃŠme pour un programme Ã  template). Fonctions pures â testÃĐes.
function _backupHasTemplate(backup) {
  return !!(backup && backup.customProgramTemplate);
}

// Construit l'objet backup. Avec template â SANS weeklyPlan. Sans template â AVEC
// weeklyPlan figÃĐ. Pur (aucun accÃĻs global ; deep-copies faites par l'appelant).
function _buildBackupSnapshot(weeklyPlan, routine, template, programMode, now) {
  var snap = {
    savedAt: now, firstUsedAt: now, lastUsedAt: now, sessionCount: 0,
    programMode: programMode || 'auto',
    routine: routine || null,
    customProgramTemplate: template || null
  };
  if (!template) snap.weeklyPlan = weeklyPlan || null; // legacy/auto : seule structure
  return snap;
}

// AllÃĻge un backup existant : retire weeklyPlan (donc mesoWeeks) s'il a un template.
// Idempotent ; backups sans template inchangÃĐs. Pur (renvoie le mÃŠme ref si rien Ã 
// faire, un nouvel objet sinon).
function _lightenBackup(backup) {
  if (!_backupHasTemplate(backup) || backup.weeklyPlan == null) return backup;
  var out = {};
  for (var k in backup) { if (backup.hasOwnProperty(k) && k !== 'weeklyPlan') out[k] = backup[k]; }
  return out;
}

// Migration locale : allÃĻge les backups en localStorage (le sync propagera le blob
// lÃĐger). Pur sur le tableau passÃĐ ; renvoie le nombre de backups modifiÃĐs.
function _migrateLightenBackups(backups) {
  if (!backups || !backups.length) return 0;
  var n = 0;
  for (var i = 0; i < backups.length; i++) {
    var light = _lightenBackup(backups[i]);
    if (light !== backups[i]) { backups[i] = light; n++; }
  }
  return n;
}

function _snapshotCurrentProgram() {
  if (!db.customProgramBackups) db.customProgramBackups = [];
  var hasTemplate = !!db.customProgramTemplate;
  var snap = _buildBackupSnapshot(
    (!hasTemplate && db.weeklyPlan) ? JSON.parse(JSON.stringify(db.weeklyPlan)) : null,
    db.routine ? JSON.parse(JSON.stringify(db.routine)) : null,
    hasTemplate ? JSON.parse(JSON.stringify(db.customProgramTemplate)) : null,
    (db.user && db.user.programMode) || 'auto',
    Date.now()
  );
  db.customProgramBackups.unshift(snap);
  if (db.customProgramBackups.length > 15) db.customProgramBackups.pop();
}

function getHevyOnlyExercises() {
  var inDB = {};
  Object.keys(EXO_DATABASE || {}).forEach(function(k) {
    var e = EXO_DATABASE[k];
    if (e.name) inDB[e.name.toLowerCase()] = true;
    (e.nameAlt || []).forEach(function(a) { inDB[a.toLowerCase()] = true; });
  });
  var seen = {};
  var result = [];
  (db.logs || []).forEach(function(log) {
    (log.exercises || []).forEach(function(exo) {
      var name = exo.name || '';
      if (name && !seen[name] && !inDB[name.toLowerCase()]) {
        seen[name] = true;
        result.push(name);
      }
    });
  });
  return result.sort();
}

function renderExoLibrary(dayIndex) {
  var container = document.getElementById('programBuilderContent');
  if (!container) return;

  var libDiv = document.getElementById('exoLibraryPanel');
  if (!libDiv) {
    libDiv = document.createElement('div');
    libDiv.id = 'exoLibraryPanel';
    container.appendChild(libDiv);
  }

  // Build set of all logged exercise names for the "already used" indicator
  var loggedSet = {};
  (db.logs || []).forEach(function(log) {
    (log.exercises || []).forEach(function(exo) {
      if (exo.name) loggedSet[exo.name.toLowerCase()] = true;
    });
  });

  var groups = [];
  var seen = {};
  Object.keys(EXO_DATABASE || {}).forEach(function(id) {
    var g = EXO_DATABASE[id].primaryMuscles && EXO_DATABASE[id].primaryMuscles[0];
    if (g && !seen[g]) { seen[g] = true; groups.push(g); }
  });
  groups.sort();

  var recentExos = getRecentExercises(5);

  var h = '<div style="border-top:1px solid var(--border);padding-top:12px;margin-top:4px;">';
  h += '<div style="font-size:11px;color:var(--sub);text-transform:uppercase;letter-spacing:0.8px;'
    + 'font-weight:600;margin-bottom:8px;">BibliothÃĻque</div>';

  h += '<input id="exoLibSearch" placeholder="Rechercher..." value="' + escapeHtml(_libraryFilter.search) + '" '
    + 'oninput="_libraryFilter.search=this.value;renderExoLibrary(' + dayIndex + ')" '
    + 'style="width:100%;box-sizing:border-box;padding:8px 10px;background:var(--surface);'
    + 'border:1px solid var(--border);border-radius:8px;color:var(--text);font-size:13px;margin-bottom:8px;">';

  h += '<div style="display:flex;gap:6px;overflow-x:auto;padding-bottom:6px;margin-bottom:10px;">';
  var allActive = !_libraryFilter.group;
  h += '<button onclick="_libraryFilter.group=null;renderExoLibrary(' + dayIndex + ')" '
    + 'style="padding:4px 10px;border-radius:20px;font-size:11px;font-weight:600;white-space:nowrap;cursor:pointer;'
    + 'border:1px solid ' + (allActive ? 'var(--accent)' : 'var(--border)') + ';'
    + 'background:' + (allActive ? 'rgba(10,132,255,0.15)' : 'var(--surface)') + ';'
    + 'color:' + (allActive ? 'var(--accent)' : 'var(--sub)') + ';">Tous</button>';
  groups.forEach(function(g) {
    var active = _libraryFilter.group === g;
    var safeG = g.replace(/\\/g, '\\\\').replace(/'/g, "\\'");
    h += '<button onclick="_libraryFilter.group=\'' + safeG + '\';renderExoLibrary(' + dayIndex + ')" '
      + 'style="padding:4px 10px;border-radius:20px;font-size:11px;font-weight:600;white-space:nowrap;cursor:pointer;'
      + 'border:1px solid ' + (active ? 'var(--accent)' : 'var(--border)') + ';'
      + 'background:' + (active ? 'rgba(10,132,255,0.15)' : 'var(--surface)') + ';'
      + 'color:' + (active ? 'var(--accent)' : 'var(--sub)') + ';">' + escapeHtml(g) + '</button>';
  });
  h += '</div>';

  if (recentExos.length && !_libraryFilter.search && !_libraryFilter.group) {
    h += '<div style="font-size:10px;color:var(--sub);margin-bottom:6px;">RÃĐcents</div>';
    recentExos.forEach(function(name) {
      var exoEntry = null;
      var dbKeys = Object.keys(EXO_DATABASE || {});
      for (var i = 0; i < dbKeys.length; i++) {
        var e = EXO_DATABASE[dbKeys[i]];
        if (e.name === name || (e.nameAlt || []).indexOf(name) >= 0) { exoEntry = e; break; }
      }
      var grp = exoEntry && exoEntry.primaryMuscles && exoEntry.primaryMuscles[0] || '';
      h += renderLibExoRow(name, grp, dayIndex, true); // recent = always logged
    });
    h += '<div style="height:8px;"></div>';
  }

  var search = _libraryFilter.search.toLowerCase();
  var filtered = Object.keys(EXO_DATABASE || {}).filter(function(id) {
    var exo = EXO_DATABASE[id];
    if (_libraryFilter.group && (!exo.primaryMuscles || exo.primaryMuscles[0] !== _libraryFilter.group)) return false;
    if (search && exo.name.toLowerCase().indexOf(search) < 0) return false;
    return true;
  }).sort(function(a, b) {
    return (EXO_DATABASE[a].name || '').localeCompare(EXO_DATABASE[b].name || '');
  });

  h += '<div style="max-height:200px;overflow-y:auto;">';
  filtered.forEach(function(id) {
    var exo = EXO_DATABASE[id];
    var isLogged = !!loggedSet[exo.name.toLowerCase()];
    h += renderLibExoRow(exo.name, exo.primaryMuscles && exo.primaryMuscles[0] || '', dayIndex, isLogged);
  });
  h += '</div>';

  // Hevy-only exercises (in logs but not in EXO_DATABASE) â no group filter since group is unknown
  if (!_libraryFilter.group) {
    var hevyOnly = getHevyOnlyExercises();
    if (search) hevyOnly = hevyOnly.filter(function(n) { return n.toLowerCase().indexOf(search) >= 0; });
    if (hevyOnly.length) {
      h += '<div style="margin-top:10px;padding-top:8px;border-top:1px solid rgba(255,255,255,0.05);">';
      h += '<div style="font-size:10px;color:var(--sub);margin-bottom:6px;">ð Mes exercices Hevy</div>';
      hevyOnly.forEach(function(name) { h += renderLibExoRow(name, '', dayIndex, true); });
      h += '</div>';
    }
  }

  h += '</div>';
  libDiv.innerHTML = h;
}

function renderLibExoRow(exoName, group, dayIndex, isLogged) {
  var safeName = exoName.replace(/\\/g,'\\\\').replace(/'/g,"\\'");
  var dot = isLogged ? '<span style="color:var(--green);font-size:9px;margin-right:4px;flex-shrink:0;">â</span>' : '';
  return '<div style="display:flex;align-items:center;justify-content:space-between;'
    + 'padding:7px 8px;border-radius:8px;margin-bottom:2px;">'
    + '<div style="display:flex;flex-direction:column;min-width:0;">'
    + '<div style="display:flex;align-items:center;font-size:13px;color:var(--text);">'
    + dot + escapeHtml(exoName) + '</div>'
    + (group ? '<div style="font-size:10px;color:var(--sub);margin-top:1px;">' + escapeHtml(group) + '</div>' : '')
    + '</div>'
    + '<button onclick="addExoToCustomSession(' + dayIndex + ',\'' + safeName + '\')" '
    + 'style="background:none;border:none;color:var(--accent);font-size:20px;cursor:pointer;padding:0 4px;flex-shrink:0;">+</button>'
    + '</div>';
}

function getRecentExercises(n) {
  var counts = {};
  (db.logs || []).forEach(function(log) {
    (log.exercises || []).forEach(function(exo) {
      if (exo.name) counts[exo.name] = (counts[exo.name] || 0) + 1;
    });
  });
  return Object.keys(counts)
    .sort(function(a, b) { return counts[b] - counts[a]; })
    .slice(0, n);
}

// ââ CUSTOM BUILDER â CRUD ââââââââââââââââââââââââââââââââââââ

function selectCustomDay(dayIndex) {
  _customBuilderDaySelected = (_customBuilderDaySelected === dayIndex) ? null : dayIndex;
  _libraryFilter = { group: null, search: '' };
  renderCustomBuilder();
}

function addCustomSession(dayIndex) {
  var block = _customBuilderState.blocks[_customBuilderState.currentBlockIndex || 0];
  var dayNames = ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi','Dimanche'];
  block.sessions.push({ dayIndex: dayIndex, label: dayNames[dayIndex], exercises: [] });
  renderCustomBuilder();
}

function removeCustomSession(dayIndex) {
  var block = _customBuilderState.blocks[_customBuilderState.currentBlockIndex || 0];
  block.sessions = block.sessions.filter(function(s) { return s.dayIndex !== dayIndex; });
  _customBuilderDaySelected = null;
  renderCustomBuilder();
}

function updateCustomSessionLabel(dayIndex, label) {
  var block = _customBuilderState.blocks[_customBuilderState.currentBlockIndex || 0];
  var session = block.sessions.find(function(s) { return s.dayIndex === dayIndex; });
  if (session) session.label = label;
}

function addExoToCustomSession(dayIndex, exoName) {
  var block = _customBuilderState.blocks[_customBuilderState.currentBlockIndex || 0];
  var session = block.sessions.find(function(s) { return s.dayIndex === dayIndex; });
  if (!session) return;

  if (session.exercises.some(function(e) { return e.name === exoName; })) {
    showToast('Exercice dÃĐjÃ  dans la sÃĐance');
    return;
  }

  var exoEntry = null;
  if (typeof EXO_DATABASE !== 'undefined' && EXO_DATABASE) {
    var _dbKeys = Object.keys(EXO_DATABASE);
    for (var _di = 0; _di < _dbKeys.length; _di++) {
      var _de = EXO_DATABASE[_dbKeys[_di]];
      if (_de.name === exoName || (_de.nameAlt || []).indexOf(exoName) >= 0) { exoEntry = _de; break; }
    }
  }
  var defaultSlot = exoEntry
    ? (exoEntry.category === 'isolation' ? 'isolation' : 'accessory')
    : ((typeof wpGetExoMeta === 'function' && wpGetExoMeta(exoName) && wpGetExoMeta(exoName).mechanic === 'isolation') ? 'isolation' : 'accessory');
  if (session.exercises.length === 0 && defaultSlot !== 'isolation') defaultSlot = 'main_lift';

  session.exercises.push({
    id: exoName.toLowerCase().replace(/\s+/g,'_').replace(/[^a-z0-9_]/g,''),
    name: exoName,
    slot: defaultSlot,
    defaultSlot: defaultSlot,
    customNote: '',
    addedAt: Date.now()
  });
  renderCustomBuilder();
}

function removeCustomExo(dayIndex, exoIndex) {
  var block = _customBuilderState.blocks[_customBuilderState.currentBlockIndex || 0];
  var session = block.sessions.find(function(s) { return s.dayIndex === dayIndex; });
  if (session) session.exercises.splice(exoIndex, 1);
  renderCustomBuilder();
}

function moveCustomExo(dayIndex, exoIndex, direction) {
  var block = _customBuilderState.blocks[_customBuilderState.currentBlockIndex || 0];
  var session = block.sessions.find(function(s) { return s.dayIndex === dayIndex; });
  if (!session) return;
  var newIdx = exoIndex + direction;
  if (newIdx < 0 || newIdx >= session.exercises.length) return;
  var tmp = session.exercises[exoIndex];
  session.exercises[exoIndex] = session.exercises[newIdx];
  session.exercises[newIdx] = tmp;
  renderCustomBuilder();
}

function cycleCustomExoSlot(dayIndex, exoIndex) {
  var block = _customBuilderState.blocks[_customBuilderState.currentBlockIndex || 0];
  var session = block.sessions.find(function(s) { return s.dayIndex === dayIndex; });
  if (!session) return;
  var exo = session.exercises[exoIndex];
  if (!exo) return;

  var slots = ['main_lift', 'accessory', 'isolation'];
  var nextSlot = slots[(slots.indexOf(exo.slot) + 1) % slots.length];

  if (nextSlot === 'main_lift') {
    var blacklisted = (typeof SLOT_PROMOTION_BLACKLIST !== 'undefined' ? SLOT_PROMOTION_BLACKLIST : [])
      .some(function(p) { return exo.name.toLowerCase().indexOf(p.toLowerCase()) >= 0; });
    if (blacklisted) {
      showToast('â ïļ ' + exo.name + ' ne peut pas ÃŠtre promu en lift principal');
      return;
    }
  }

  exo.slot = nextSlot;
  renderCustomBuilder();
}

function cancelCustomBuilder() {
  showConfirm({ title: 'Quitter sans sauvegarder ?', body: 'Tes modifications seront perdues.', confirmLabel: 'Quitter', danger: true, onConfirm: function() {
    _customBuilderState = null;
    _customBuilderDaySelected = null;
    _libraryFilter = { group: null, search: '' };
    renderProgramBuilder();
  }});
}

function saveCustomTemplate() {
  if (!_customBuilderState) return;
  if (db.customProgramTemplate || db.weeklyPlan) _snapshotCurrentProgram();
  _customBuilderState.updatedAt = Date.now();
  db.customProgramTemplate = JSON.parse(JSON.stringify(_customBuilderState));
  db.user.programMode = 'custom';
  // Sync db.routine so _wpIsStaleVsRoutine and renderProgDaysList read current labels
  var _block = db.customProgramTemplate.blocks && db.customProgramTemplate.blocks[0];
  if (!db.routine) db.routine = {};
  ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi','Dimanche'].forEach(function(day, idx) {
    var s = _block && (_block.sessions || []).find(function(s) { return s.dayIndex === idx; });
    db.routine[day] = s ? s.label : 'ðī Repos';
  });
  _customBuilderState = null;
  _customBuilderDaySelected = null;
  saveDB();
  if (typeof debouncedCloudSync === 'function') debouncedCloudSync();
  if (typeof calculateParametersForCustomPlan === 'function') calculateParametersForCustomPlan();
  showToast('â Programme sauvegardÃĐ !');
  renderProgramBuilder();
}

function restoreCustomProgramBackup(index) {
  var backup = db.customProgramBackups && db.customProgramBackups[index];
  if (!backup) return;
  var d = new Date(backup.savedAt);
  var label = d.toLocaleDateString('fr-FR', { day: '2-digit', month: 'long' });
  showConfirm({ title: 'Restaurer la version du ' + label + ' ?', body: 'Le programme actuel sera remplacÃĐ.', confirmLabel: 'Restaurer', onConfirm: function() {
    // Snapshot current before restoring so user can undo; capture whether we did so BEFORE overwriting
    var didSnapshot = !!(db.weeklyPlan || db.customProgramTemplate);
    if (didSnapshot) _snapshotCurrentProgram();
    // Restore structure + meta from the backup
    db.user.programMode = backup.programMode || 'auto';
    db.routine = backup.routine ? JSON.parse(JSON.stringify(backup.routine)) : null;
    db.customProgramTemplate = backup.customProgramTemplate ? JSON.parse(JSON.stringify(backup.customProgramTemplate)) : null;
    if (_backupHasTemplate(backup)) {
      // Structure rÃĐgÃĐnÃĐrable : on rÃĐcupÃĻre la STRUCTURE (template) et on RECALCULE
      // les charges sur les PR ACTUELS â pas de weeklyPlan figÃĐ (les backups allÃĐgÃĐs
      // n'en ont plus ; pour un ancien backup lourd, days/mesoWeeks figÃĐs seraient de
      // toute faÃ§on ÃĐcrasÃĐs par la rÃĐgÃĐnÃĐration). currentBlock (phase/semaine) suit la
      // timeline courante ; mesoWeeks est reconstruit au rendu (buildMesoWeeks).
      db.user.programMode = 'custom'; // un template â custom (programMode non fiable en base)
      if (!db.weeklyPlan) db.weeklyPlan = {};
      var _block = db.customProgramTemplate.blocks && db.customProgramTemplate.blocks[0];
      if (!db.routine) db.routine = {};
      ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi','Dimanche'].forEach(function(day, idx) {
        var s = _block && (_block.sessions || []).find(function(s) { return s.dayIndex === idx; });
        db.routine[day] = s ? s.label : 'ðī Repos';
      });
      if (typeof calculateParametersForCustomPlan === 'function') calculateParametersForCustomPlan();
    } else {
      // Legacy / sans template : le weeklyPlan figÃĐ est la seule structure restaurable.
      db.weeklyPlan = backup.weeklyPlan ? JSON.parse(JSON.stringify(backup.weeklyPlan)) : null;
    }
    // Remove the restored entry (shifted by 1 if we prepended an undo snapshot)
    var realIdx = didSnapshot ? index + 1 : index;
    db.customProgramBackups.splice(realIdx, 1);
    if (db.customProgramBackups.length > 15) db.customProgramBackups.pop();
    saveDB();
    showToast('â Programme restaurÃĐ !');
    renderProgramBuilder();
  }});
}

function openExoLibrary(dayIndex) {
  _customBuilderDaySelected = dayIndex;
  renderCustomBuilder();
}

// v194 â DÃĐtecte si l'user a dÃĐjÃ  un profil complet (raccourci wizard)
function _pbHasFullProfile() {
  var pp = db.user && db.user.programParams;
  return !!(pp && pp.freq && pp.mat && pp.goals && pp.goals.length > 0
    && Array.isArray(pp.selectedDays) && pp.selectedDays.length === pp.freq);
}

