    '<button onclick="_pbState._skipShortcut=true;renderProgramBuilder();" style="width:100%;padding:12px;border-radius:12px;background:var(--surface);border:0.5px solid var(--border);color:var(--sub);font-size:13px;cursor:pointer;">âïļ Modifier les paramÃĻtres</button>',
    '<button onclick="_pbState=null;renderProgramBuilder();" style="width:100%;padding:10px;background:none;border:none;color:var(--sub);font-size:12px;cursor:pointer;margin-top:6px;">â Annuler</button>',
