function checkDisciplinePercentile() {
  var monthStart = new Date();
  monthStart.setDate(1); monthStart.setHours(0, 0, 0, 0);
  var count = (db.logs || []).filter(function(l) {
    return (l.timestamp || 0) > monthStart.getTime();
  }).length;
  if ((Date.now() - (db._lastPercentileNotif || 0)) / 86400000 < 7) return;
  var rank = REGULARITY_BENCHMARKS.find(function(b) { return count >= b.sessions; });
  if (!rank) return;
  sendLocalNotification(
    rank.emoji + ' RÃĐgularitÃĐ ' + rank.label,
    'Avec ' + count + ' sÃĐances ce mois, tu es dans le ' + rank.label + '.'
  );
  db._lastPercentileNotif = Date.now();
  saveDB();
}

function checkPersonalRecord() {
  var now = new Date();
  var thisMonth = (db.logs || []).filter(function(l) {
    var d = new Date(l.timestamp || 0);
    return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
  }).length;
  var lastYear = (db.logs || []).filter(function(l) {
    var d = new Date(l.timestamp || 0);
    return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear() - 1;
  }).length;
  if (lastYear < 3 || thisMonth <= lastYear) return;
  if ((Date.now() - (db._lastGhostNotif || 0)) / 86400000 < 7) return;
  showToast('ðŧ ' + thisMonth + ' sÃĐances ce mois â record vs l\'an dernier (' + lastYear + ') !');
  db._lastGhostNotif = Date.now();
  saveDB();
}

async function checkScheduledNotifications() {
  if (!db.user || !db.user.onboardingDate) return;
  if (!('Notification' in window) || Notification.permission !== 'granted') return;
  var onboardingDate = new Date(db.user.onboardingDate);
  var daysSince = Math.floor((Date.now() - onboardingDate.getTime()) / 86400000) + 1;
  if (daysSince < 1 || daysSince > 30) return;
  var sent = db.notificationsSent || [];

  for (var i = 0; i < NOTIFICATION_SCHEDULE.length; i++) {
    var notif = NOTIFICATION_SCHEDULE[i];
    if (notif.day !== daysSince) continue;
    if (sent.indexOf('day_' + notif.day) >= 0) continue;
    if (notif.profileFilter && db.user.obProfile !== notif.profileFilter) continue;

    var shouldSend = false;
    if (notif.trigger === 'morning' || notif.trigger === 'evening'
        || notif.trigger === 'training_time' || notif.trigger === 'friend_activity') {
      shouldSend = true;
    }
    if (notif.trigger === 'high_srs') {
      var srs = typeof computeSRS === 'function' ? computeSRS() : { score: 75 };
      shouldSend = srs.score >= 80;
    }
    if (!shouldSend) continue;

    var body = notif.body;
    if (body.includes('{{tonnage}}')) {
      body = body.replace('{{tonnage}}', calcWeeklyTonnage());
    }

    sendLocalNotification(notif.title, body);

    if (!db.notificationsSent) db.notificationsSent = [];
    db.notificationsSent.push('day_' + notif.day);
    saveDB();
    break; // Une seule notification par jour
  }

  // ââ Triggers comportementaux (indÃĐpendants du calendrier J1âJ30) âââââââââ

  // Trigger ACWR optimal â max 1x par semaine
  var _srsForAcwr = typeof computeSRS === 'function' ? computeSRS() : null;
  var _acwr = _srsForAcwr ? (_srsForAcwr.acwr || 1.0) : null;
  if (_acwr && _acwr >= 0.8 && _acwr <= 1.3) {
    var _lastAcwrNotif = db._lastAcwrNotif || 0;
    if ((Date.now() - _lastAcwrNotif) / 86400000 >= 7) {
      sendLocalNotification(
        'âĄ FenÃŠtre optimale',
        'Ton ratio charge/rÃĐcupÃĐration est parfait cette semaine. C\'est le bon moment pour pousser un peu plus.'
      );
      db._lastAcwrNotif = Date.now();
      saveDB();
    }
  }

  // Trigger sÃĐances manquÃĐes â max 1x tous les 3 jours
  var _lastLog = (db.logs || []).slice().sort(function(a, b) { return (b.timestamp||0) - (a.timestamp||0); })[0];
  if (_lastLog) {
    var _daysSinceSession = (Date.now() - (_lastLog.timestamp || 0)) / 86400000;
    var _lastMissedNotif = db._lastMissedNotif || 0;
    if (_daysSinceSession >= 2 && (Date.now() - _lastMissedNotif) / 86400000 >= 3) {
      sendLocalNotification(
        'ðŠ On se retrouve ?',
        'Ãa fait ' + Math.floor(_daysSinceSession) + ' jours. MÃŠme 30 minutes compte pour maintenir ta progression.'
      );
      db._lastMissedNotif = Date.now();
      saveDB();
    }
  }

  // Trigger percentile rÃĐgularitÃĐ + ghost record â max 1x par semaine chacun
  checkDisciplinePercentile();
  checkPersonalRecord();

  // Push notifications (background) â ACWR optimal + streak danger
  checkPushTriggers();
}

// ============================================================
// CALORIC CYCLING
// ============================================================
function getTodayWorkoutPlan() {
  if (!db.weeklyPlan || !db.weeklyPlan.days) return null;
  var dayNames = ['Dimanche', 'Lundi', 'Mardi', 'Mercredi', 'Jeudi', 'Vendredi', 'Samedi'];
  var today = dayNames[new Date().getDay()];
  return db.weeklyPlan.days.find(function(d) { return d.day === today; }) || null;
}

function getDailyCaloricTarget() {
  var bw = (db.user && db.user.bw) || 75;
  var tonnage7 = (db.logs || [])
    .filter(function(l) { return (l.timestamp || 0) > Date.now() - 7 * 86400000; })
    .reduce(function(s, l) { return s + (l.volume || 0); }, 0);
  var tdee = typeof calcTDEE === 'function' ? calcTDEE(bw, tonnage7) : (db.user.tdee || 0);
  if (!tdee || tdee < 1000) return null;

  var todayPlan = getTodayWorkoutPlan();
  var isRestDay = !todayPlan || todayPlan.rest === true
    || !todayPlan.exercises || todayPlan.exercises.length === 0;
  var isSBDDay = !isRestDay && (todayPlan.exercises || []).some(function(e) {
    return e.isPrimary;
  });

  var multiplier = isSBDDay ? 1.10 : isRestDay ? 0.90 : 1.00;
  var targetCalories = Math.round(tdee * multiplier);
  var targetProteins = Math.round(bw * 2.0);
  var targetCarbs = Math.round(targetCalories * (isSBDDay ? 0.50 : 0.30) / 4);
  var targetFats = Math.max(40,
    Math.round((targetCalories - targetProteins * 4 - targetCarbs * 4) / 9));

  return {
    calories: targetCalories,
    carbs: targetCarbs,
    proteins: targetProteins,
    fats: targetFats,
    type: isSBDDay ? 'high' : isRestDay ? 'low' : 'moderate',
    label: isSBDDay ? 'Jour de sÃĐance lourde' : isRestDay ? 'Jour de repos' : 'Jour modÃĐrÃĐ'
  };
}

// ============================================================
// ONGLET CORPS
// ============================================================
function calcIPFGL(lift, bw) {
  const a=1236.25115, b=1449.21864, c=0.01644, d=2.12345;
  const denom = a - b * Math.exp(-c * Math.pow(bw, d));
  if (!denom || denom <= 0) return 0;
  return Math.round((600 / denom) * lift * 100) / 100;
}


// ââ RÃĐcupÃĐration musculaire ââââââââââââââââââââââââââââââââââ
function getMuscleRecoveryStatus() {
  const RECOVERY_HOURS = {
    'Jambes':72,'Quadriceps':72,'Ischio-jambiers':72,'Fessiers':72,
    'Dos':72,'Grand dorsal':72,'Haut du dos':72,
    'Pecs':48,'Pecs (haut)':48,'Pecs (bas)':48,
    'Ãpaules':48,'Ãpaules (latÃĐral)':48,'Ãpaules (antÃĐrieur)':48,'Ãpaules (postÃĐrieur)':48,
    'Biceps':48,'Triceps':48,'Bras':48,
    'Abdos (frontal)':24,'Obliques':24,'Mollets':24,'Avant-bras':24,'TrapÃĻzes':48,'Lombaires':72
  };
  const now = Date.now();
  const status = {};
  const recentLogs = db.logs.filter(l => l.timestamp > now - 7*86400000).sort((a,b) => b.timestamp - a.timestamp);
  const muscleLastTrained = {};
  const muscleLastVolume = {};

  recentLogs.forEach(log => {
    log.exercises.forEach(exo => {
      const muscle = getMuscleGroup(exo.name);
      const parent = getMuscleGroupParent(muscle);
      [muscle, parent].forEach(m => {
        if (!muscleLastTrained[m]) {
          muscleLastTrained[m] = log.timestamp;
          muscleLastVolume[m] = exo.sets || 0;
        }
      });
    });
  });

  Object.keys(RECOVERY_HOURS).forEach(muscle => {
    const lastTs = muscleLastTrained[muscle];
    if (!lastTs) { status[muscle] = { hoursSince:999, recoveryPct:100, isRecovered:true }; return; }
    const hoursSince = (now - lastTs) / 3600000;
    const baseRec = RECOVERY_HOURS[muscle] || 48;
    const vol = muscleLastVolume[muscle] || 0;
    const volMult = vol > 10 ? 1.3 : vol > 6 ? 1.1 : 1.0;
    const recoveryPct = Math.min(100, Math.round((hoursSince / (baseRec * volMult)) * 100));
    status[muscle] = { hoursSince: Math.round(hoursSince), recoveryPct, isRecovered: recoveryPct >= 85 };
  });
  return status;
}

function generateCoachAlgoMessage() {
  const bw=getUserBW(),bench=db.bestPR.bench,squat=db.bestPR.squat,dead=db.bestPR.deadlift;
  const logs7=getLogsInRange(7),tonnage7=logs7.reduce((s,l)=>s+l.volume,0);
  const ipf=calcIPFGLTotal(bench,squat,dead,bw);
  const tdee=calcTDEE(bw,tonnage7);
  const today=new Date().toDateString();
  const todayEntry=(db.body||[]).find(e=>new Date(e.ts).toDateString()===today);
  const kcalAuj=todayEntry?todayEntry.kcal:null,protAuj=todayEntry?todayEntry.prot:null;
  const plateaux=['bench','squat','deadlift'].map(t=>detectPlateau(t)).filter(Boolean);
  const momB=calcMomentum('bench'),momS=calcMomentum('squat'),momD=calcMomentum('deadlift');
  let sections=[];

  // ââ Bloc en cours ââ
  const currentBloc = db.weeklyPlan?.week || null;
  const level = db.user.level || 'intermediaire';
  var blocP = null;
  try { blocP = BLOC_PARAMS && BLOC_PARAMS[level] ? BLOC_PARAMS[level][currentBloc] : null; } catch(e) {}
  if (currentBloc && blocP) {
    let blocHtml = '<div class="ai-section-title">ð BLOC EN COURS</div>';
    blocHtml += `Semaine ${currentBloc} â <span class="ai-highlight blue">${blocP.label || 'Progression linÃĐaire'}</span><br>`;
    blocHtml += `RPE cible : ${blocP.rpe} Â· Charge : ${Math.round(blocP.loadMultiplier * 100)}% e1RM`;
    sections.push(`<div class="ai-section">${blocHtml}</div>`);
  }

  // ââ RÃĐcupÃĐration musculaire ââ
  const recovery = getMuscleRecoveryStatus();
  const fatigued = Object.entries(recovery).filter(([m,r]) => !r.isRecovered && r.hoursSince < 168)
    .sort((a,b) => a[1].recoveryPct - b[1].recoveryPct);
  if (fatigued.length) {
    let recHtml = '<div class="ai-section-title">ðĪ RÃCUPÃRATION</div>';
    fatigued.slice(0,6).forEach(([muscle, r]) => {
      const color = r.recoveryPct < 50 ? 'red' : 'orange';
      recHtml += `<span class="ai-highlight ${color}">${muscle} ${r.recoveryPct}%</span> `;
    });
    // Warning si demain tape un muscle fatiguÃĐ
    const tomorrow = DAYS_FULL[(new Date().getDay() + 1) % 7];
    const tomorrowExos = getProgExosForDay(tomorrow);
    if (tomorrowExos.length) {
      const conflicting = [...new Set(tomorrowExos.map(e => getMuscleGroupParent(getMuscleGroup(e))))].filter(m => {
        const r = recovery[m]; return r && !r.isRecovered;
      });
      if (conflicting.length) {
        recHtml += `<br><span style="color:var(--orange);">â ïļ Demain (${tomorrow}) : ${conflicting.join(', ')} pas encore rÃĐcupÃĐrÃĐ(s)</span>`;
      }
    }
    sections.push(`<div class="ai-section">${recHtml}</div>`);
  }
  // Force section: adapt to mode
  if (modeFeature('showSBDCards')) {
    let analyseForce=`<div class="ai-section-title">ð FORCE</div>`;
    if (modeFeature('showIPF') && ipf>0) {
      const ipfLabel=ipf<300?'dÃĐbutant':ipf<400?'intermÃĐdiaire':ipf<500?'avancÃĐ':'ÃĐlite';
      analyseForce+=`Score IPF GL : <span class="ai-highlight blue">${ipf} pts</span> (niveau ${ipfLabel})<br>`;
    }
    const moms=[momB&&`Bench ${momB>0?'+':''}${momB}kg/sem`,momS&&`Squat ${momS>0?'+':''}${momS}kg/sem`,momD&&`Dead ${momD>0?'+':''}${momD}kg/sem`].filter(Boolean);
    if (moms.length) analyseForce+=`Momentum : <span class="ai-highlight ${moms.some(m=>m.includes('-'))?'orange':'green'}">${moms.join(' Â· ')}</span>`;
    sections.push(`<div class="ai-section">${analyseForce}</div>`);
  } else {
    // Non-SBD mode: show general training stats
    let analyseGeneral=`<div class="ai-section-title">ð ENTRAÃNEMENT</div>`;
    analyseGeneral+=`SÃĐances (7j) : <span class="ai-highlight blue">${logs7.length}</span> Â· Tonnage : <span class="ai-highlight green">${Math.round(tonnage7)}kg</span>`;
    sections.push(`<div class="ai-section">${analyseGeneral}</div>`);
  }
  if (tdee>0) {
    let nutri=`<div class="ai-section-title">ð―ïļ NUTRITION</div>`;
    nutri+=`TDEE estimÃĐ : <span class="ai-highlight blue">${tdee} kcal/jour</span><br>`;
    if (kcalAuj) {
      const delta=kcalAuj-tdee,color=delta>300?'orange':delta<-400?'red':'green';
      nutri+=`Aujourd'hui : <span class="ai-highlight ${color}">${delta>0?'+':''}${delta} kcal vs TDEE</span><br>`;
    }
    if (protAuj&&bw>0) {
      const ppk=Math.round((protAuj/bw)*10)/10;
      nutri+=`ProtÃĐines : <span class="ai-highlight ${ppk>=1.8?'green':'red'}">${protAuj}g (${ppk}g/kg)</span> ${ppk>=1.8?'â':'â cible 2g/kg'}`;
    } else if (!kcalAuj) nutri+=`<span style="color:var(--sub);font-size:12px;">Entre tes macros du jour pour l'analyse.</span>`;
    sections.push(`<div class="ai-section">${nutri}</div>`);
  }
  if (modeFeature('showPlateauDetection') && plateaux.length>0) {
    let alertes=`<div class="ai-section-title">â ïļ ALERTES</div>`;
    const sugg={bench:'Essaie Spoto Bench ou monte le volume',squat:'Variation pause squat ou fentes lestÃĐes',deadlift:'DÃĐficit deadlift ou Romanian'};
    const _sbdNames={bench:'Bench Press (Barbell)',squat:'Squat (Barbell)',deadlift:'Deadlift (Barbell)'};
    plateaux.forEach(p=>{
      alertes+=`<div class="plateau-alert">ð <strong>${p.type.toUpperCase()}</strong> plateau depuis ${p.sessions} sÃĐances`;
      const analysis = analyzePlateauCauses(_sbdNames[p.type]||p.type);
      if (analysis && analysis.causes.length > 0) {
        alertes+=`<div style="margin-top:6px;font-size:11px;">Causes probables :<br>`;
        analysis.causes.forEach(c=>{alertes+=`âĒ ${c}<br>`;});
        if (analysis.suggestions.length > 0) {
          alertes+=`â Ajoute : ${analysis.suggestions.slice(0,2).join(', ')}`;
        }
        alertes+=`</div>`;
      } else {
        alertes+=` â ${sugg[p.type]}`;
      }
      alertes+=`</div>`;
    });
    sections.push(`<div class="ai-section">${alertes}</div>`);
  }
  if (!sections.length) return '<span style="color:var(--sub);font-size:13px;">Importe des sÃĐances pour activer l\'analyse.</span>';
  return `<div class="ai-response-content">${sections.join('')}</div><div class="ai-timestamp">Coach Algo âĒ Calcul instantanÃĐ âĒ Sans IA</div>`;
}


