  natation:          { emoji: 'ð', label: 'Natation',        exoName: 'Natation' },
  course:            { emoji: 'ð', label: 'Course',          exoName: 'Course Ã  pied' },
  trail:             { emoji: 'ðĨū', label: 'Trail',           exoName: 'Trail' },
  randonnee:         { emoji: 'ðïļ', label: 'RandonnÃĐe',      exoName: 'RandonnÃĐe' },
