function renderTierSection() {
  // DÃĐterminer le tier actuel
  var tier = 'member';
  if (db.isFounder || db.godMode) tier = 'founder';
  else if (db.isEarlyAdopter) tier = 'early_adopter';
  else if (db.user && db.user.tier) tier = db.user.tier;

  var isFounder = tier === 'founder' || isCreator();
  var isEA = tier === 'early_adopter' || isFounder;

  // Section bienvenue
  var welcomeEl = document.getElementById('tierWelcomeSection');
  if (welcomeEl) {
    var wh = '';
    if (isFounder) {
      wh = '<div style="text-align:center;padding:12px;background:linear-gradient(135deg,rgba(200,133,10,0.1),rgba(232,184,48,0.05));border-radius:12px;margin-bottom:12px;">';
      wh += '<div style="font-size:28px;margin-bottom:4px;">ð</div>';
      wh += '<div style="font-size:14px;font-weight:700;color:#E8B830;">Founder</div>';
      wh += '<div style="font-size:11px;color:var(--sub);margin-top:4px;">AccÃĻs complet Ã  tous les thÃĻmes et fonctionnalitÃĐs exclusives.</div>';
      wh += '</div>';
    } else if (isEA) {
      wh = '<div style="text-align:center;padding:12px;background:rgba(199,199,204,0.05);border-radius:12px;margin-bottom:12px;">';
      wh += '<div style="font-size:28px;margin-bottom:4px;">â­</div>';
      wh += '<div style="font-size:14px;font-weight:700;color:#C7C7CC;">Early Adopter</div>';
      wh += '<div style="font-size:11px;color:var(--sub);margin-top:4px;">Merci de faire partie des premiers !</div>';
      wh += '</div>';
    } else {
      wh = '<div style="text-align:center;padding:12px;background:rgba(255,255,255,0.03);border-radius:12px;margin-bottom:12px;">';
      wh += '<div style="font-size:14px;color:var(--sub);">Membre</div>';
      wh += '</div>';
    }
    welcomeEl.innerHTML = wh;
  }

  // Section badges tier
  var badgesEl = document.getElementById('tierBadgesSection');
  if (badgesEl) {
    var bh = '<div style="display:flex;gap:8px;flex-wrap:wrap;">';
    bh += '<div style="padding:6px 12px;border-radius:8px;font-size:11px;font-weight:700;' + (isFounder ? 'background:var(--founder-gradient);color:var(--founder-text);' : 'background:rgba(255,255,255,0.05);color:var(--sub);opacity:0.4;') + '">Founder</div>';
    bh += '<div style="padding:6px 12px;border-radius:8px;font-size:11px;font-weight:700;' + (isEA ? 'background:rgba(199,199,204,0.15);color:#C7C7CC;' : 'background:rgba(255,255,255,0.05);color:var(--sub);opacity:0.4;') + '">Early Adopter</div>';
    bh += '</div>';
    badgesEl.innerHTML = bh;
  }

  // Section thÃĻmes
  var themeEl = document.getElementById('themeSelector');
  if (themeEl) {
    var saved = localStorage.getItem('selectedTheme') || 'default';
    var themes = [
      { id: 'default', name: 'Bleu iOS', color: '#0A84FF', locked: false },
      { id: 'silver', name: 'Silver', color: '#C7C7CC', locked: !isEA },
      { id: 'gold', name: 'Gold', color: '#E8B830', locked: !isFounder }
    ];
    var th = '<div style="display:flex;gap:8px;flex-wrap:wrap;">';
    themes.forEach(function(t) {
      var isActive = saved === t.id;
      var clickable = !t.locked;
      var style = 'display:flex;align-items:center;gap:8px;padding:10px 14px;border-radius:10px;cursor:' + (clickable ? 'pointer' : 'default') + ';';
      style += 'background:' + (isActive ? 'rgba(255,255,255,0.08)' : 'rgba(255,255,255,0.03)') + ';';
      style += 'border:1px solid ' + (isActive ? t.color : 'rgba(255,255,255,0.06)') + ';';
      style += t.locked ? 'opacity:0.35;' : '';
      var onclick = clickable ? 'applyThemeWithCheck(\'' + t.id + '\');setTimeout(renderTierSection,200);' : '';
      th += '<div style="' + style + '" onclick="' + onclick + '">';
      th += '<div style="width:20px;height:20px;border-radius:50%;background:' + t.color + ';flex-shrink:0;"></div>';
      th += '<div><div style="font-size:12px;font-weight:600;color:var(--text);">' + t.name + '</div>';
      if (t.locked) th += '<div style="font-size:10px;color:var(--sub);">ð ' + (t.id === 'gold' ? 'Founder' : 'Early Adopter') + '</div>';
      th += '</div></div>';
    });
    th += '</div>';
    themeEl.innerHTML = th;
  }
}

// ââ Settings Profile Editor ââââââââââââââââââââââââââââââââââ
// Debounced save for rapid toggle interactions (avoids clearCaches + JSON.stringify on each click)
let _saveSettingsTimer = null;
function _debouncedSaveSettings() {
  if (_saveSettingsTimer) clearTimeout(_saveSettingsTimer);
  _saveSettingsTimer = setTimeout(() => { saveDB(); _saveSettingsTimer = null; }, 300);
}

function updateProfileField(field, value) {
  if (!db.user.programParams) db.user.programParams = {};
  if (field === 'level') {
    db.user.level = value;
    db.user.programParams.level = value;
  } else if (field === 'trainingMode') {
    db.user.trainingMode = value;
  } else if (field === 'height' || field === 'age' || field === 'targetBW') {
    db.user[field] = value;
  } else {
    db.user.programParams[field] = value;
  }
  _debouncedSaveSettings();
  showToast('â Profil mis Ã  jour');
  if (field === 'level' || field === 'trainingMode') _notifyProgramOutdated();
}

// ââ Cycle menstruel handlers âââââââââââââââââââââââââââââââââ
function toggleCycleTracking(enabled) {
  if (!db.user.cycleTracking) db.user.cycleTracking = { enabled: false, lastPeriodDate: null, cycleLength: 28 };
  db.user.cycleTracking.enabled = !!enabled;
  var details = document.getElementById('settingsCycleDetails');
  if (details) details.style.display = enabled ? 'block' : 'none';
  _debouncedSaveSettings();
  showToast(enabled ? 'ð Cycle activÃĐ' : 'â Cycle dÃĐsactivÃĐ');
}

function updateCycleField(field, value) {
  if (!db.user.cycleTracking) db.user.cycleTracking = { enabled: false, lastPeriodDate: null, cycleLength: 28 };
  db.user.cycleTracking[field] = value;
  _debouncedSaveSettings();
}

// ââ Injuries: zone-by-zone editor ââââââââââââââââââââââââââââ
var INJURY_ZONES = [
  { key: 'genou',    label: 'ðĶĩ Genoux' },
  { key: 'epaule',   label: 'ðĪ Ãpaules' },
  { key: 'dos',      label: 'ðĶī Dos' },
  { key: 'hanche',   label: 'ðĶī Hanches' },
  { key: 'poignet',  label: 'â Poignets' },
  { key: 'coude',    label: 'ðŠ Coudes' },
  { key: 'nuque',    label: 'ðĪ Nuque' },
];

function renderInjuriesEditor() {
  var container = document.getElementById('settingsInjuriesList');
  if (!container) return;
  var injuries = db.user.injuries || [];
  var byZone = {};
  injuries.forEach(function(inj) { if (inj && inj.zone) byZone[inj.zone] = inj; });

  container.innerHTML = INJURY_ZONES.map(function(z) {
    var inj = byZone[z.key];
    var level = inj && inj.active ? inj.level : 0; // 0 = aucune
    return '<div style="display:flex;align-items:center;justify-content:space-between;gap:10px;padding:10px 12px;background:var(--surface);border:1px solid var(--border);border-radius:10px;">'+
      '<div style="font-size:13px;font-weight:600;flex-shrink:0;">' + z.label + '</div>'+
      '<select onchange="setInjuryLevel(\''+z.key+'\', parseInt(this.value))" style="padding:6px 8px;background:var(--bg);color:var(--text);border:1px solid var(--border);border-radius:8px;font-size:12px;">'+
        '<option value="0"' + (level===0?' selected':'') + '>Aucune</option>'+
        '<option value="1"' + (level===1?' selected':'') + '>Niveau 1 â GÃŠne lÃĐgÃĻre</option>'+
        '<option value="2"' + (level===2?' selected':'') + '>Niveau 2 â Blessure active</option>'+
        '<option value="3"' + (level===3?' selected':'') + '>Niveau 3 â Post-chirurgie</option>'+
      '</select>'+
    '</div>';
  }).join('');
}

function setInjuryLevel(zone, level) {
  if (!Array.isArray(db.user.injuries)) db.user.injuries = [];
  var idx = db.user.injuries.findIndex(function(i) { return i && i.zone === zone; });
  if (level === 0) {
    if (idx >= 0) db.user.injuries.splice(idx, 1);
  } else {
    var entry = { zone: zone, level: level, active: true, since: new Date().toISOString().slice(0,10) };
    if (idx >= 0) db.user.injuries[idx] = Object.assign({}, db.user.injuries[idx], entry);
    else db.user.injuries.push(entry);
  }
  _debouncedSaveSettings();
  showToast(level === 0 ? 'â Zone retirÃĐe' : 'âïļ Niveau ' + level + ' enregistrÃĐ');
}

