function upsertReport(type, html, sessionId, weekKey) {
  if (!db.reports) db.reports = [];
  if (weekKey) {
    db.reports = db.reports.filter(function(r) { return !(r.type === type && r.weekKey === weekKey); });
  }
  db.reports.push({
    id: generateId(),
    type: type,
    weekKey: weekKey || null,
    sessionId: sessionId || null,
    html: '<div class="ai-response-content">' + html + '</div>',
    created_at: Date.now(),
    expires_at: Date.now() + 14 * 86400000,
    read: false
  });
  saveDBNow();
}

function generateWeeklyReport() {
  var weekKey = _getWeekKey();
  if ((db.reports||[]).some(function(r) { return r.type === 'weekly' && r.weekKey === weekKey; })) return;

  var prevWeekStart = new Date(weekKey).getTime() - 7 * 86400000;
  var prevWeekEnd = new Date(weekKey).getTime();
  var weekLogs = (db.logs || []).filter(function(l) { return l.timestamp >= prevWeekStart && l.timestamp < prevWeekEnd; });
  if (weekLogs.length === 0) return;

  var planned = getTrainingDaysCount();
  var compliance = Math.min(100, Math.round((weekLogs.length / Math.max(1, planned)) * 100));
  var phase = typeof wpDetectPhase === 'function' ? wpDetectPhase() : 'accumulation';

  var totalVol = weekLogs.reduce(function(s, l) { return s + (l.volume || 0); }, 0);
  var totalSets = 0;
  weekLogs.forEach(function(l) { (l.exercises || []).forEach(function(e) { totalSets += (e.sets || 0); }); });

  var h = '<div class="ai-section-title">ð BILAN SEMAINE</div>';
  h += '<strong>' + weekLogs.length + '</strong> sÃĐances sur ' + planned + ' prÃĐvues (' + compliance + '% compliance)<br>';
  h += 'Volume total : <span class="ai-highlight blue">' + (totalVol / 1000).toFixed(1) + 't</span> Â· ' + totalSets + ' sÃĐries<br>';

  // e1RM delta vs prior week (Top Set method)
  var priorWeekStart = prevWeekStart - 7 * 86400000;
  var priorLogs = (db.logs || []).filter(function(l) { return l.timestamp >= priorWeekStart && l.timestamp < prevWeekStart; });
  var e1rmDeltas = [];
  ['squat', 'bench', 'deadlift'].forEach(function(type) {
    var getBestE1RM = function(logs) {
      var best = 0;
      logs.forEach(function(log) {
        (log.exercises || []).forEach(function(exo) {
          if ((exo.maxRM || 0) > best && typeof matchExoName === 'function' && matchExoName(exo.name, type)) best = exo.maxRM;
        });
      });
      return best;
    };
    var curBest = getBestE1RM(weekLogs);
    var prevBest = getBestE1RM(priorLogs);
    if (curBest > 0 && prevBest > 0) {
      var delta = Math.round((curBest - prevBest) * 10) / 10;
      var lbl = type === 'bench' ? 'Bench' : type === 'squat' ? 'Squat' : 'Deadlift';
      e1rmDeltas.push(lbl + ' e1RM : ' + curBest + 'kg (' + (delta >= 0 ? '+' : '') + delta + 'kg vs sem. prÃĐc.)');
    }
  });

  if (e1rmDeltas.length) {
    h += '<div class="ai-section-title">ð e1RM CETTE SEMAINE</div>';
    h += e1rmDeltas.join('<br>') + '<br>';
  } else {
    // Fallback: momentum trends
    var trends = [];
    ['squat', 'bench', 'deadlift'].forEach(function(type) {
      var mom = typeof calcMomentum === 'function' ? calcMomentum(type) : null;
      if (mom !== null) trends.push(type.charAt(0).toUpperCase() + type.slice(1) + ' : ' + (mom > 0 ? '+' : '') + mom + 'kg/sem');
    });
    if (trends.length) {
      h += '<div class="ai-section-title">ð TENDANCES SBD</div>';
      h += trends.join('<br>') + '<br>';
    }
  }

  // Push/Pull volume ratio
  var ratios = typeof computeStrengthRatios === 'function' ? computeStrengthRatios() : null;
  if (ratios && ratios.push_pull) {
    var ppVal = ratios.push_pull.value.toFixed(2);
    var ppStatus = ratios.push_pull.value >= ratios.push_pull.ideal[0] && ratios.push_pull.value <= ratios.push_pull.ideal[1]
      ? 'â' : (ratios.push_pull.value < ratios.push_pull.ideal[0] ? 'â ïļ trop de pull' : 'â ïļ trop de push');
    h += '<div class="ai-section-title">âïļ RATIO PUSH/PULL</div>';
    h += ppVal + ' ' + ppStatus + ' (cible 0.80â1.10)<br>';
  }

  // SRS score + ACWR
  var srs = typeof computeSRS === 'function' ? computeSRS() : null;
  if (srs) {
    h += '<div class="ai-section-title">âĄ CHARGE (' + labelFor('srs','SRS') + ' / ' + labelFor('acwr','ACWR') + ')</div>';
    h += labelFor('srs','SRS') + ' : <strong>' + srs.score + '/100</strong>';
    if (srs.label) h += ' â ' + srs.label;
    if (srs.acwr !== undefined) {
      var acwrRounded = Math.round(srs.acwr * 100) / 100;
      var acwrAlert = (srs.acwr < 0.8 || srs.acwr > 1.3) ? ' â ïļ ' + labelFor('acwr','ACWR') + ' hors zone !' : '';
      h += '<br>' + labelFor('acwr','ACWR') + ' : ' + acwrRounded + acwrAlert;
    }
    h += '<br>';
  }

  // Readiness
  var weekReadiness = getCheckinHistory().filter(function(r) { // READY-C2-c
    var ts = new Date(r.date).getTime();
    return ts >= prevWeekStart && ts < prevWeekEnd;
  });
  if (weekReadiness.length) {
    var avgR = Math.round(weekReadiness.reduce(function(s, r) { return s + r.score; }, 0) / weekReadiness.length);
    h += '<div class="ai-section-title">ðī READINESS MOYENNE</div>';
    h += avgR + '/100 ' + (avgR >= 70 ? 'â' : avgR >= 40 ? 'â ïļ' : 'ðī') + '<br>';
  }

  // Compliance-based encouragement (adaptive by phase)
  h += '<div class="ai-section-title">ðĄ RECOMMANDATION</div>';
  var phaseLabels = { hypertrophie: 'hypertrophie', force: 'force', peak: 'peak', deload: 'deload', accumulation: 'accumulation', intensification: 'intensification', intro: 'intro' };
  var phaseLabel = phaseLabels[phase] || phase;
  if (compliance < 50) {
    h += 'â ïļ Compliance faible (' + compliance + '%). Vise au moins ' + Math.ceil(planned * 0.75) + ' sÃĐances cette semaine â la rÃĐgularitÃĐ prime sur l\'intensitÃĐ.';
  } else if (compliance < 80) {
    h += 'Bonne semaine, quelques manques. En phase ' + phaseLabel + ', essaie de ne pas zapper les sÃĐances SBD â elles structurent la progression.';
  } else if (compliance >= 100) {
    if (weekReadiness.length && weekReadiness[weekReadiness.length - 1].score < 50) {
      h += 'ðŠ Semaine complÃĻte, mais ta readiness chute. En phase ' + phaseLabel + ', la rÃĐcup compte autant que le volume â planifie un jour off.';
    } else if (phase === 'peak') {
      h += 'ðŊ Semaine complÃĻte en ' + phaseLabel + '. Conserve l\'ÃĐnergie nerveuse â prioritÃĐ aux levÃĐs compÃĐtitifs, rÃĐduis les accessoires.';
    } else {
      h += 'ðĨ Semaine parfaite ! Continue sur cette lancÃĐe â en ' + phaseLabel + ', la rÃĐgularitÃĐ est la clÃĐ.';
    }
  } else {
    h += 'Continue comme Ã§a. RÃĐgularitÃĐ = progression.';
  }

  upsertReport('weekly', h, null, weekKey);
}

// ââ DÃĐbrief post-sÃĐance v206 â Bottom Sheet (Expert / DÃĐbutant) âââââââââ
// Format Gemini : 3 lignes Expert (tonnage + e1RM + SNC) OU DÃĐbutant
// (record + streak + encouragement). Bottom Sheet iOS, auto-fermeture 15s.

var _ENCOURAGE_MSGS = [
  'Tes muscles te diront merci demain.',
  'La rÃĐgularitÃĐ bat l\'intensitÃĐ sur le long terme.',
  'Chaque sÃĐance compte. Continue.',
  'Tu es plus rÃĐgulier que 80% des gens qui commencent.',
  'Le progrÃĻs, c\'est la somme de petits efforts rÃĐpÃĐtÃĐs.',
  'Ton futur toi te remercie.',
  'Un jour Ã  la fois. Tu y es.',
  'La discipline forge le caractÃĻre.',
  'Ce que tu fais aujourd\'hui, tu le ressentiras dans 3 mois.',
  'Pas besoin d\'ÃŠtre parfait, juste rÃĐgulier.'
];

function saveAlgoDebrief(session) {
  if (!session) return;

  var _vocabLevel = (db.user && db.user.vocabLevel) || 2;
  var _isExpert = _vocabLevel >= 3;

  // 1. Tonnage vs sÃĐance similaire prÃĐcÃĐdente
  var _sessionVolume = session.volume || 0;
  var _lastSimilar = (db.logs || [])
    .filter(function(l) { return l.id !== session.id && l.title === session.title && (l.volume||0) > 0; })
    .sort(function(a,b) { return (b.timestamp||0) - (a.timestamp||0); })[0];
  var _prevVolume = _lastSimilar ? (_lastSimilar.volume || 0) : 0;
  var _volumePct = _prevVolume > 0 ? Math.round((_sessionVolume - _prevVolume) / _prevVolume * 100) : null;

  // 2. Meilleur e1RM de la sÃĐance
  var _bestE1RM = null, _bestE1RMPrev = null, _bestE1RMName = null;
  try {
    var _olderLogs = (db.logs || []).filter(function(l) { return l.id !== session.id; });
    (session.exercises || []).forEach(function(exo) {
      if (!exo.maxRM || exo.maxRM <= 0) return;
      var _prevBest = 0;
      _olderLogs.forEach(function(ol) {
        (ol.exercises || []).forEach(function(oe) {
          if (oe.name === exo.name && oe.maxRM > _prevBest) _prevBest = oe.maxRM;
        });
      });
      if (!_bestE1RM || exo.maxRM > _bestE1RM) {
        _bestE1RM = Math.round(exo.maxRM);
        _bestE1RMPrev = _prevBest > 0 ? Math.round(_prevBest) : null;
        _bestE1RMName = exo.name;
      }
    });
  } catch(e) {}

  // 3. Streak sÃĐances (semaine en cours, lundi-dimanche)
  var _streak = 0;
  var _weekStart = new Date();
  _weekStart.setDate(_weekStart.getDate() - _weekStart.getDay() + 1);
  _weekStart.setHours(0, 0, 0, 0);
  var _weekLogs = (db.logs || []).filter(function(l) {
    return (l.timestamp || 0) >= _weekStart.getTime() && (l.volume || 0) > 0;
  });
  _streak = _weekLogs.length;

  // 4. Alerte SNC (fatigueType=neural & confidence âĨ 0.75)
  var _hasSNCAlert = false;
  (session.exercises || []).forEach(function(exo) {
    (exo.allSets || []).forEach(function(s) {
      if (s.fatigueType === 'neural' && (s.fatigueConfidence || 0) >= 0.75) _hasSNCAlert = true;
    });
  });

  // 5. Record charge brute (dÃĐbutant)
  var _newMaxWeight = null, _newMaxExo = null;
  try {
    (session.exercises || []).forEach(function(exo) {
      var _sets = (exo.allSets || []).filter(function(s) { return !s.isWarmup && (s.weight || 0) > 0; });
      var _maxW = _sets.length ? Math.max.apply(null, _sets.map(function(s) { return parseFloat(s.weight) || 0; })) : 0;
      if (_maxW <= 0) return;
      var _prevMax = 0;
      (db.logs || []).filter(function(l) { return l.id !== session.id; }).forEach(function(ol) {
        (ol.exercises || []).forEach(function(oe) {
          if (oe.name === exo.name) {
            (oe.allSets || []).forEach(function(s) { if ((s.weight || 0) > _prevMax) _prevMax = s.weight; });
          }
        });
      });
      if (_maxW > _prevMax && _prevMax > 0) {
        _newMaxWeight = _maxW;
        _newMaxExo = exo.name;
      }
    });
  } catch(e) {}

  // Construire les lignes
  var _lines = [];
  if (_isExpert) {
    if (_volumePct !== null) {
      var _sign = _volumePct >= 0 ? '+' : '';
      _lines.push('ðŠ ' + _sessionVolume.toLocaleString('fr-FR') + ' kg ('
        + _sign + _volumePct + '% vs sÃĐance prÃĐcÃĐdente)');
    } else {
      _lines.push('ðŠ Volume de rÃĐfÃĐrence ÃĐtabli : ' + _sessionVolume.toLocaleString('fr-FR') + ' kg');
    }
    if (_bestE1RM && _bestE1RMName) {
      var _delta = _bestE1RMPrev ? ' (+' + (_bestE1RM - _bestE1RMPrev) + ' kg)' : '';
      _lines.push('ð Estimation Force : ' + _bestE1RM + ' kg au ' + _bestE1RMName + _delta);
    }
    _lines.push(_hasSNCAlert
      ? 'ð  SNC : RÃĐcupÃĐration requise â priorise le sommeil ce soir'
      : 'ðĒ SNC : Optimal');
  } else {
    if (_newMaxWeight && _newMaxExo) {
      _lines.push('ð Nouveau record : ' + _newMaxWeight + ' kg au ' + _newMaxExo + ' !');
    } else if (_sessionVolume > 0) {
      _lines.push('â SÃĐance complÃĐtÃĐe â beau travail !');
    }
    if (_streak >= 2) {
      _lines.push('ðĨ ' + _streak + 'ÃĻme sÃĐance cette semaine. Tu tiens le rythme !');
    }
    _lines.push('ðŽ ' + _ENCOURAGE_MSGS[Math.floor(Math.random() * _ENCOURAGE_MSGS.length)]);
  }

  var _next = _getNextSessionTitle();
  if (_next) _lines.push('ð Prochaine : ' + _next);

  session.debrief = { lines: _lines, generatedAt: Date.now(), isExpert: _isExpert };
  _showDebriefSheet(_lines);
  saveDBNow();
}

// Chantier A vague 2 â vraie sheet unifiÃĐe (avant : .modal-overlay hackÃĐe en
// align-items:flex-end + box inline). Auto-dismiss 15s conservÃĐ, dÃĐsormais
// avec la sortie animÃĐe du systÃĻme (via showSheet autoDismiss â _uiClose).
function _showDebriefSheet(lines) {
  if (!lines || !lines.length) return;
  var body = '<div style="font-size:17px;font-weight:800;margin-bottom:14px;">SÃĐance terminÃĐe ðŊ</div>';
  lines.forEach(function(line) {
    body += '<div style="font-size:13px;line-height:1.5;padding:9px 0;'
      + 'border-bottom:0.5px solid var(--border);">' + line + '</div>';
  });
  body += '<button onclick="closeModalEl(this.closest(\'.go-bottom-sheet\'))" '
    + 'style="width:100%;margin-top:16px;padding:14px;border-radius:14px;'
    + 'background:var(--accent);border:none;color:#fff;font-weight:700;'
    + 'font-size:15px;cursor:pointer;">Continuer ð</button>';
  showSheet({ body: body, autoDismiss: 15000 });
}

function _getNextSessionTitle() {
  if (!db.weeklyPlan || !db.weeklyPlan.days) return null;
  var _dayNames = ['Dimanche','Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi'];
  var _today = new Date().getDay();
  for (var i = 1; i <= 7; i++) {
    var _nextDayName = _dayNames[(_today + i) % 7];
    var _nextPlan = (db.weeklyPlan.days || []).find(function(d) {
      return d.day === _nextDayName && d.exercises && d.exercises.length > 0 && !d.isRest;
    });
    if (_nextPlan) {
      return _nextDayName + ' â ' + (_nextPlan.title || '').split(' Â· ')[0];
    }
  }
  return null;
}


// ============================================================
// WEEKLY PLAN â gÃĐnÃĐration locale (sans IA)
// ============================================================
let wpSelectedDay = DAYS_FULL[new Date().getDay()] === 'Dimanche' ? 'Lundi' : DAYS_FULL[new Date().getDay()];

// Arrondi au 0.5kg
function round05(v) { return Math.round(v * 2) / 2; }

// ââ CatÃĐgorie d'exercice (global) âââââââââââââââââââââââââââ
function getExoCategory(name) {
  const n = name.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');
  if (/squat|deadlift|souleve|bench\s*(press|barre|couche)?|developpe\s*couche/.test(n)) return 'big';
  if (/overhead|militaire|\bohp\b|rowing\b|tirage|row\b|traction|pull.?up|chin.?up|\bdips?\b|rdl|roumain|hip\s*thrust|pouss[ÃĐe]e\s*de\s*hanche|leg\s*press|presse\s*(a\s*)?cuisses|fentes?|\blunge|good\s*morning|inclin[eÃĐ]|d[eÃĐ]clin[eÃĐ]/.test(n)) return 'compound';
  return 'isolation';
}

// ââ Estimation durÃĐe sÃĐance scientifique ââââââââââââââââââââ
function estimateSessionDuration(exercises) {
  if (!exercises || !exercises.length) return 0;
  let totalSec = 600; // 10min : ÃĐchauffement articulaire + rangement final

  exercises.forEach(function(exo) {
    if (!exo || !exo.name) return; // guard anti-null
    var meta = wpGetExoMeta(exo.name) || {};
    var isHeavy = meta.mechanic === 'compound';

    // Transition + installation (rack vs machine)
    totalSec += isHeavy ? 120 : 60;

    // Coach weeklyPlan peut stocker exo.sets comme entier (ex: 4) â dÃĐtecter et traiter sÃĐparÃĐment.
    var setsData = exo.allSets;
    if (!setsData || !setsData.length) {
      var setsCount = typeof exo.sets === 'number'
        ? exo.sets
        : (Array.isArray(exo.sets) ? exo.sets.length : 3);
      var repsVal = exo.reps
        ? (parseInt(String(exo.reps).split('-')[1] || exo.reps) || 10)
        : 10;
      var restVal = exo.restSeconds || (isHeavy ? 180 : 90);
      for (var i = 0; i < setsCount; i++) {
        totalSec += repsVal * (repsVal <= 5 ? 4.5 : 3.5);
        totalSec += restVal + (isHeavy ? 45 : 15);
      }
    } else {
      setsData.forEach(function(set) {
        // TUT
        var repSpeed = (set.reps || 0) <= 5 ? 4.5 : 3.5;
        totalSec += (set.reps || 0) * repSpeed;

        // Repos rÃĐel + manipulation des poids
        var rest = set.restSeconds || exo.restSeconds || (isHeavy ? 180 : 90);
        var logistics = (isHeavy || (set.weight || 0) > 100) ? 45 : 15;
        totalSec += rest + logistics;
      });
    }
  });

  // Facteur de fatigue : 10% plus lent en fin de sÃĐance
  return Math.round((totalSec * 1.10) / 60);
}

// Adapter la sÃĐance si elle dÃĐpasse la durÃĐe configurÃĐe
// ââ Matrice cardio dynamique (Gemini â effet d'interfÃĐrence) âââââââââââââ
// Plus l'objectif est force/explosion, plus le cardio long est contre-productif.
// Valeurs en minutes (durÃĐe plafond du cardio en fin de sÃĐance).
var CARDIO_MAX_MATRIX = {
  powerbuilding: { hypertrophie:20, accumulation:20, force:10, intensification:10, peak:5,  deload:30 },
  powerlifting:  { hypertrophie:20, accumulation:20, force:10, intensification:10, peak:5,  deload:30 },
  musculation:   { hypertrophie:25, accumulation:25, force:15, intensification:15, peak:10, deload:30 },
  seche:         { hypertrophie:45, accumulation:45, force:30, intensification:30, peak:15, deload:45 },
  bien_etre:     { hypertrophie:45, accumulation:45, force:45, intensification:45, peak:45 },
  crossfit:      { hypertrophie:30, accumulation:30, force:20, intensification:20, peak:15, deload:45 }
};

function getCardioDuration(trainingMode, macroPhase, goals, remainingMin) {
  // PRIORITÃ 1 : rÃĐglage utilisateur
  var cardioSetting = db.user && db.user.programParams && db.user.programParams.cardio;
  if (cardioSetting === 'aucun') return 0;
  if (cardioSetting === 'dedie') return 0;
  // 'integre' (ou null/undefined) â matrice
  var isCutting = goals && (goals.indexOf('seche') >= 0 || goals.indexOf('perte_de_poids') >= 0);
  var mode = isCutting ? 'seche' : (trainingMode || 'musculation');
  var phase = macroPhase || 'hypertrophie';
  var matrix = CARDIO_MAX_MATRIX[mode] || CARDIO_MAX_MATRIX.musculation;
  var baseMax = matrix[phase] || matrix.hypertrophie || 20;
  var userPref = db.user && db.user.programParams && db.user.programParams.cardioDuration;
  var target = userPref || baseMax;
  var finalDuration = Math.min(target, remainingMin || baseMax);
  if (finalDuration < 5) return 0;
  return Math.round(finalDuration);
}
// âââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ

function adaptSessionForDuration(exercises, targetMinutes, goal) {
  if (!targetMinutes || targetMinutes <= 0) return { exercises, adaptations: [] };
  const est = estimateSessionDuration(exercises);
  if (est <= targetMinutes) return { exercises, adaptations: [] };

  const adaptations = [];
  let adapted = JSON.parse(JSON.stringify(exercises));

  // 1. Supersets sur isolations (gain ~30%)
  const isoExos = adapted.filter(e => getExoCategory(e.name) === 'isolation');
  if (isoExos.length >= 2) {
    for (let i = 0; i < isoExos.length - 1; i += 2) {
      isoExos[i].superset = isoExos[i + 1].name;
      isoExos[i].restSeconds = Math.round((isoExos[i].restSeconds || 60) * 0.5);
    }
    adaptations.push('Supersets sur isolations');
    const est2 = estimateSessionDuration(adapted);
    if (est2 <= targetMinutes) return { exercises: adapted, adaptations };
  }

  // 2. RÃĐduire sÃĐries isolations (max -1, jamais <2)
  adapted.forEach(e => {
    if (getExoCategory(e.name) !== 'isolation') return;
    if (typeof e.sets === 'number') {
      if (e.sets > 2) e.sets = e.sets - 1;
      return;
    }
    const setsArr = Array.isArray(e.sets) ? e.sets
      : Array.isArray(e.allSets) ? e.allSets
      : Array.isArray(e.series) ? e.series : null;
    if (!setsArr) return;
    const work = setsArr.filter(s => !s.isWarmup);
    if (work.length > 2) {
      const idx = setsArr.findIndex(s => !s.isWarmup);
      if (idx >= 0) setsArr.splice(idx, 1);
    }
  });
  adaptations.push('SÃĐries isolations rÃĐduites');
  const est3 = estimateSessionDuration(adapted);
  if (est3 <= targetMinutes) return { exercises: adapted, adaptations };

  // 3. RÃĐduire repos de 15% max
  adapted.forEach(e => { e.restSeconds = Math.round((e.restSeconds || 90) * 0.85); });
  adaptations.push('Repos rÃĐduits (-15%)');
  const est4 = estimateSessionDuration(adapted);
  if (est4 <= targetMinutes) return { exercises: adapted, adaptations };

  // 4. Dernier recours : retirer une isolation (pile d'ÃĐviction Gemini)
  // Ordre : cardio (sauf sÃĻche) â calves â forearms â abs â adductors â secondary â JAMAIS isCorrectivePriority/primary
  var _isCutting = (goal === 'seche' || goal === 'perte_de_poids');
  var EVICTION_ORDER = (_isCutting
    ? ['calves','forearms','abs','adductors','cardio','secondary']
    : ['cardio','calves','forearms','abs','adductors','secondary']);
  for (var _evIdx = 0; _evIdx < EVICTION_ORDER.length; _evIdx++) {
    if (estimateSessionDuration(adapted) <= targetMinutes) break;
    var cat = EVICTION_ORDER[_evIdx];
    var removeIdx = adapted.findIndex(function(e) {
      if (e.isPrimary || e.isCorrectivePriority) return false;
      return e.evictionCategory === cat;
    });
    if (removeIdx >= 0) {
      adaptations.push((adapted[removeIdx].name || cat) + ' retirÃĐ');
      adapted.splice(removeIdx, 1);
    }
  }
  // Fallback final : retirer la derniÃĻre isolation non-protÃĐgÃĐe
  if (estimateSessionDuration(adapted) > targetMinutes) {
    var lastIso = adapted.findIndex(function(e) {
      return !e.isPrimary && !e.isCorrectivePriority && getExoCategory(e.name) === 'isolation';
    });
    if (lastIso >= 0) {
      adaptations.push('Isolation retirÃĐe : ' + adapted[lastIso].name);
      adapted.splice(lastIso, 1);
    }
  }

  return { exercises: adapted, adaptations };
}

// ââ SRS Adaptatif + Modificateur Cycle Menstruel (v205) âââââââââââââââââ
// Baseline personnelle : moyenne - 1.5Ï sur les 30 derniÃĻres sessions.
// < 10 sessions â seuil fixe conservateur 45. 10-30 â baseline provisoire.
function computeAdaptiveSRSThreshold() {
  var readiness = getCheckinHistory() // READY-C2-c â logique et arrondis inchangÃĐs (frontiÃĻre 84.5 du harnais)
    .filter(function(r) { return r.score > 0; })
    .sort(function(a, b) { return (b.date || '').localeCompare(a.date || ''); });

  if (readiness.length < 10) {
    return { threshold: 45, mode: 'fixed', sessions: readiness.length };
  }

  var sample = readiness.slice(0, Math.min(30, readiness.length));
  var scores = sample.map(function(r) { return r.score; });
  var mean = scores.reduce(function(s, v) { return s + v; }, 0) / scores.length;
  var variance = scores.reduce(function(s, v) { return s + Math.pow(v - mean, 2); }, 0) / scores.length;
  var sigma = Math.sqrt(variance);
  var threshold = mean - 1.5 * sigma;
  var mode = readiness.length >= 30 ? 'stable' : 'provisional';

  return { threshold: Math.max(30, Math.round(threshold)), mean: Math.round(mean),
           sigma: Math.round(sigma * 10) / 10, mode: mode, sessions: readiness.length };
}

// Modificateur SRS selon la phase du cycle menstruel (LÃĐa et tout user cycleTracking).
// Valeurs Gemini-validÃĐes : lutÃĐale +5, prÃĐ-menstruelle +10, ovulation -5.
function getCyclePhaseModifier() {
  var user = db.user;
  if (!user || !user.cycleTracking || !user.cycleTracking.enabled) return 0;
  var lastPeriod = user.cycleTracking.lastPeriodDate;
  if (!lastPeriod) return 0;
  var cycleLength = user.cycleTracking.cycleLength || 28;
  var daysSince = Math.round((Date.now() - new Date(lastPeriod).getTime()) / 86400000);
  var dayInCycle = ((daysSince % cycleLength) + cycleLength) % cycleLength + 1;
  if (dayInCycle <= 11) return 0;
  if (dayInCycle <= 14) return -5;
  if (dayInCycle <= 24) return 5;
  return 10;
}

// SRS effectif = brut + modificateur cycle
function getEffectiveSRS(rawScore) {
  return (rawScore || 0) + getCyclePhaseModifier();
}

// ââ shouldDeload() â Gemini validation (paramÃĻtres calibrÃĐs) âââââââââââââ
function shouldDeload(logs, trainingMode) {
  // v193 â Bien-ÃŠtre : pas de deload (mode neutre, pas d'accumulation SNC)
  var _mode = trainingMode || (db.user && db.user.trainingMode);
  if (_mode === 'bien_etre') return { needed: false };
  if (!logs || logs.length < 3) return { needed: false };

  var level = (db.user && db.user.level) || 'intermediaire';
  var now = Date.now();
  var DAY = 86400000;
  var WEEK = 7 * DAY;

  // ParamÃĻtres par niveau (Gemini)
  var PARAMS = {
    debutant:      { maxWeeks: 12, rpeThreshold: 9.0,  volumeDrop: 0.20, srsThreshold: 40 },
    intermediaire: { maxWeeks: 8,  rpeThreshold: 8.5,  volumeDrop: 0.15, srsThreshold: 45 },
    avance:        { maxWeeks: 6,  rpeThreshold: 8.5,  volumeDrop: 0.15, srsThreshold: 45 }
  };
  var p = PARAMS[level] || PARAMS.intermediaire;

  // v205 â seuil adaptatif (baseline personnelle), avec modificateur cycle menstruel
  var _adaptThr = computeAdaptiveSRSThreshold();
  var _srsThresholdToUse = _adaptThr.mode === 'fixed' ? p.srsThreshold : _adaptThr.threshold;

  // CRITÃRE 1 â RÃĐcupÃĐration faible (lecture directe todayWellbeing)
  // NE PAS appeler computeSRS() â cycle infini avec wpDetectPhase â stack overflow
  var _ckSd = getTodayCheckin(); // READY-C2-c â mÃŠmes conditions, ÃĐchelle x5 de l'accesseur
  if (_ckSd && _ckSd.sleep5 && _ckSd.motivation5) {
    var _normalized = (_ckSd.sleep5 + _ckSd.motivation5) / 2 / 5 * 100;
    var _effectiveNorm = getEffectiveSRS(_normalized);
    if (_effectiveNorm < _srsThresholdToUse) {
      return {
        needed: true,
        reason: 'RÃĐcupÃĐration insuffisante (sommeil ' + _ckSd.sleep5 + '/5, motivation ' + _ckSd.motivation5 + '/5). Semaine de rÃĐcupÃĐration recommandÃĐe.',
        trigger: 'srs'
      };
    }
  }

  // CRITÃRE 2 â Volume Drop + RPE ÃĐlevÃĐ (signal stagnation ÃĐpuisement)
  var recentLogs = logs.filter(function(l) {
    return (now - (l.timestamp || 0)) <= 3 * WEEK;
  }).sort(function(a, b) { return (b.timestamp||0) - (a.timestamp||0); });

  if (recentLogs.length >= 6) {
    var w1Logs = recentLogs.filter(function(l) { return (now - (l.timestamp||0)) <= WEEK; });
    var w3Logs = recentLogs.filter(function(l) {
      var age = now - (l.timestamp||0);
      return age >= 2*WEEK && age <= 3*WEEK;
    });
    var w1Vol = w1Logs.reduce(function(s, l) { return s + (l.volume||0); }, 0);
    var w3Vol = w3Logs.reduce(function(s, l) { return s + (l.volume||0); }, 0);
    var volumeDropped = w3Vol > 0 && w1Vol < w3Vol * (1 - p.volumeDrop);

    var rpeValues = [];
    w1Logs.forEach(function(l) {
      (l.exercises||[]).forEach(function(e) {
        (e.allSets||[]).forEach(function(s) {
          if (!s.isWarmup && parseFloat(s.rpe) > 0) rpeValues.push(parseFloat(s.rpe));
        });
      });
    });
    var avgRpe = rpeValues.length > 0
      ? rpeValues.reduce(function(s, r) { return s + r; }, 0) / rpeValues.length
      : null;
    var rpeHigh = avgRpe && avgRpe > p.rpeThreshold;

    if (volumeDropped && rpeHigh) {
      return {
        needed: true,
        reason: 'Volume en baisse (' + Math.round((1 - w1Vol/w3Vol)*100) + '%) et RPE moyen ÃĐlevÃĐ (' + avgRpe.toFixed(1) + '). Surmenage dÃĐtectÃĐ.',
        trigger: 'volume_rpe'
      };
    }
  }

  // CRITÃRE 3 â Max semaines sans deload (dÃĐclenchement auto prÃĐventif)
  var lastDeloadLog = (db.weeklyPlan && db.weeklyPlan.lastDeloadDate)
    ? new Date(db.weeklyPlan.lastDeloadDate).getTime()
    : null;
  var weeksSinceDeload = lastDeloadLog
    ? Math.round((now - lastDeloadLog) / WEEK)
    : null;

  // Fallback : estimer depuis les logs si lastDeloadDate absent
  if (!weeksSinceDeload) {
    var sortedLogs = logs.slice().sort(function(a, b) { return (a.timestamp||0) - (b.timestamp||0); });
    var firstLog = sortedLogs[0];
    if (firstLog && firstLog.timestamp) {
      weeksSinceDeload = Math.round((now - firstLog.timestamp) / WEEK);
    }
  }

  if (weeksSinceDeload && weeksSinceDeload >= p.maxWeeks) {
    return {
      needed: true,
      reason: weeksSinceDeload + ' semaines d\'entraÃŪnement consÃĐcutives. Deload prÃĐventif recommandÃĐ mÃŠme si tu te sens bien.',
      trigger: 'max_weeks'
    };
  }

  return { needed: false };
}

