// ââ FONCTIONS UTILITAIRES ââââââââââââââââââââââââââââââââââââ

function wpRound25(v) { return Math.round(v / 2.5) * 2.5; }
function wpRound125(v) { return Math.round(v / 1.25) * 1.25; }
// v235 â Charge haltÃĻres : la valeur calculÃĐe reprÃĐsente le poids PAR haltÃĻre.
// Les estimations dÃĐrivÃĐes d'un e1RM barre (Bench/Squat) sont des charges
// totales â diviser par 2 pour les exercices avec haltÃĻres.
function wpIsDumbbellExo(name) {
  return /halt[eÃĻ]res?|halt\.|dumbbell|\bDB\b/i.test(name || '');
}
function wpDumbbellAdjust(weight, name) {
  if (wpIsDumbbellExo(name) && weight > 0) {
    // Ratio 0.37 par haltÃĻre (littÃĐrature de force â Gemini validation 2026)
    // W_haltÃĻre = W_barre Ã 0.37 â plus prÃĐcis que Ã·2 pour les profils avancÃĐs
    return Math.max(2.5, wpRound25(weight * 0.37));
  }
  return weight;
}
// ââ NORMALISATION NOM EXERCICE âââââââââââââââââââââââââââââââ
function wpNormalizeName(name) {
  if (!name) return '';
  return name
    .toLowerCase()
    .replace(/[Ã ÃĄÃĒÃĢÃĪÃĨ]/g, 'a').replace(/[ÃĻÃĐÃŠÃŦ]/g, 'e')
    .replace(/[ÃŽÃ­ÃŪÃŊ]/g, 'i').replace(/[ÃēÃģÃīÃĩÃķ]/g, 'o')
    .replace(/[ÃđÃšÃŧÃž]/g, 'u').replace(/[Ã§]/g, 'c').replace(/[Ãą]/g, 'n')
    .replace(/[()[\]]/g, ' ')
    .replace(/[-ââ]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

