function wpRepsForPhase(phase, slot) {
  if (slot === 'isolation') return 15;
  if (slot === 'accessory') {
    return { hypertrophie: 10, accumulation: 10, force: 8, intensification: 6,
             peak: 6, deload: 10, intro: 12, recuperation: 12 }[phase] || 10;
  }
  return { hypertrophie: 8, accumulation: 6, force: 4, intensification: 3,
           peak: 2, deload: 6, intro: 8, recuperation: 8 }[phase] || 5;
}
function getDLSetsReps(weekInPhase) {
  var w = parseInt(weekInPhase) || 1;
  var level = (db && db.user && db.user.level) || 'intermediaire';
  var isDebutant = level === 'debutant';
  if (w <= 1) return { sets: 5, reps: 5, rpe: 7.5, restSeconds: 300 };
  // S2 : 6 reps pour intermÃĐdiaire+ (volume), RPE 7.5 compensatoire (â3% charge)
  // S2 : 5 reps pour dÃĐbutant (technique prioritaire)
  if (w === 2) return { sets: 4, reps: isDebutant ? 5 : 6, rpe: 7.5, restSeconds: 300 };
  return             { sets: 4, reps: 3, rpe: 8.5, restSeconds: 360 };
}

function wpSetsForPhase(phase, slot) {
  if (slot === 'isolation') return 3;
  return { hypertrophie: 4, accumulation: 4, force: 4, intensification: 4,
           peak: 3, deload: 2, intro: 3, recuperation: 2 }[phase] || 3;
}
function wpRpeForPhase(phase, slot) {
  if (slot === 'isolation') return 7;
  if (slot === 'accessory') return phase === 'deload' ? 6 : 7.5;
  return { hypertrophie: 7.5, accumulation: 8, force: 8.5, intensification: 8.5,
           peak: 9, deload: 6, intro: 7, recuperation: 6 }[phase] || 8;
}

function wpBuildMainSets(weight, reps, setsCount, rpe) {
  return Array.from({ length: setsCount }, function() {
    return { weight: weight, reps: reps, rpe: rpe, isWarmup: false };
  });
}

function wpCheckActivityConflicts(dayData, dayName) {
  if (!dayData || dayData.rest) return dayData;
  var orderedDays = ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi','Dimanche'];
  var dayIdx = orderedDays.indexOf(dayName);
  var prevDayName = dayIdx > 0 ? orderedDays[dayIdx - 1] : null;

  var yesterday = null;
  if (prevDayName) {
    var weeklyActs = db.weeklyActivities || [];
    yesterday = weeklyActs.find(function(a) { return a.day === prevDayName; }) || null;
    if (!yesterday) {
      var fixedActs = (db.user && db.user.activities) || [];
      var fixedY = fixedActs.find(function(a) { return a.fixed && a.days && a.days.indexOf(prevDayName) >= 0; });
      if (fixedY) yesterday = fixedY;
    }
  }
  if (!yesterday) return dayData;

  var score = typeof computeActivityScore === 'function' ? computeActivityScore(yesterday) : 0;
  var actMuscles = (typeof ACTIVITY_MUSCLES !== 'undefined' && ACTIVITY_MUSCLES[yesterday.type]) || [];
  var injuries = (db.user && db.user.injuries) || [];

  // RÃĻgle cumul : score âĨ 200 + blessure sur mÃŠme groupe â rÃĐcupÃĐration active forcÃĐe
  var INJURY_MUSCLE_MAP = {
    genou:    ['Quadriceps', 'Ischio', 'Fessiers', 'Mollets'],
    epaule:   ['Ãpaules', 'Pectoraux', 'Dos', 'Triceps'],
    dos:      ['Lombaires', 'Dos'],
    hanches:  ['Fessiers', 'Ischio', 'Adducteurs'],
    poignets: ['Avant-bras'],
    coudes:   ['Triceps', 'Biceps'],
    nuque:    ['Dos', 'Ãpaules']
  };
  var injuryOnSameGroup = injuries.some(function(injury) {
    if (!injury.active) return false;
    var injMuscles = INJURY_MUSCLE_MAP[injury.zone] || [];
    return actMuscles.some(function(m) {
      return injMuscles.some(function(im) {
        return m.toLowerCase().includes(im.toLowerCase()) || im.toLowerCase().includes(m.toLowerCase());
      });
    });
  });

  if (score >= 200 && injuryOnSameGroup) {
    dayData.status = 'RECOVERY_ONLY';
    dayData.coachNote = (dayData.coachNote || '') +
      ' ð Cumul dÃĐtectÃĐ : ' + yesterday.type + ' (score ' + score + ') + blessure ' +
      injuries.filter(function(i) { return i.active; }).map(function(i) { return i.zone; }).join('/') +
      '. SÃĐance convertie en rÃĐcupÃĐration active (RPE max 5, machines uniquement).';
    dayData.exercises = (dayData.exercises || []).map(function(exo) {
      return Object.assign({}, exo, {
        sets: (exo.sets || []).map(function(s) {
          return Object.assign({}, s, { rpe: Math.min(s.rpe || 5, 5) });
        })
      });
    });
    return dayData;
  }

  // Contre-indications activitÃĐ Ã blessure
  var actConflict = typeof checkActivityInjuryConflict === 'function'
    ? checkActivityInjuryConflict(yesterday.type, injuries)
    : null;
  if (actConflict) {
    dayData.coachNote = (dayData.coachNote || '') +
      ' â ïļ ' + actConflict.alert + ' ' + actConflict.suggestion;
  }

  if (score < 50) return dayData;

  if (score >= 50 && score < 120) {
    dayData.exercises = dayData.exercises.map(function(exo) {
      var meta = typeof wpGetExoMeta === 'function' ? wpGetExoMeta(exo.name) : null;
      var exoMuscle = meta ? (meta.muscleGroup || '') : '';
      var isAffected = actMuscles.some(function(m) {
        return m === 'Full Body' || (exoMuscle && exoMuscle.toLowerCase().indexOf(m.toLowerCase()) >= 0);
      });
      if (!isAffected || exo.isPrimary) return exo;
      var reduced = JSON.parse(JSON.stringify(exo));
      var workSets = (reduced.sets || []).filter(function(s) { return !s.isWarmup; });
      if (workSets.length > 2) {
        var lastWorkIdx = -1;
        for (var i = reduced.sets.length - 1; i >= 0; i--) {
          if (!reduced.sets[i].isWarmup) { lastWorkIdx = i; break; }
        }
        if (lastWorkIdx >= 0) reduced.sets.splice(lastWorkIdx, 1);
      }
      return reduced;
    });
    dayData.coachNote = (dayData.coachNote || '') +
      ' ðĪ ' + yesterday.type + ' hier (score ' + score + ') â volume accessoires ajustÃĐ.';
  } else if (score >= 120 && score < 200) {
    dayData.exercises = dayData.exercises.filter(function(exo) {
      return exo.isPrimary || exo.isPrimary === undefined;
    });
    dayData.coachNote = (dayData.coachNote || '') +
      ' â ïļ Charge externe ÃĐlevÃĐe hier â accessoires supprimÃĐs, focus composÃĐs.';
  } else if (score >= 200) {
    dayData.coachNote = (dayData.coachNote || '') +
      ' ðī ActivitÃĐ trÃĻs intense hier (score ' + score + '). ConsidÃĻre de dÃĐcaler cette sÃĐance de 24h ou de la passer en rÃĐcupÃĐration active.';
  }

  return dayData;
}

function wpApplyImbalanceCorrections(exercises, dayKey, ratios, phase) {
  if (!ratios) return exercises;
  // Seuils lus depuis STRENGTH_RATIO_TARGETS â cohÃĐrence diagnostic Coach = prescription programme
  var _t = typeof STRENGTH_RATIO_TARGETS !== 'undefined' ? STRENGTH_RATIO_TARGETS : {};

  // Rule 1 : Row/Bench < seuil alert (STRENGTH_RATIO_TARGETS.row_bench.alert = 0.85)
  // ReÃ§oit _accDayKey : bench2 (VEN) ne dÃĐclenche jamais l'injection (pool VEN a dÃĐjÃ  du tirage).
  // Guard _hasRow ÃĐvite le doublon sur MAR quand le pool accessoires inclut dÃĐjÃ  un Rowing.
  if (dayKey === 'bench' && ratios.row_bench &&
      ratios.row_bench.value < ((_t.row_bench && _t.row_bench.alert) || 0.90)) {
    var _hasRow = exercises.some(function(e) {
      return /rowing|tirage|pull/i.test(e.name || '');
    });
    if (!_hasRow) {
      exercises.splice(Math.min(2, exercises.length), 0, {
        name: 'Rowing Poulie Assis (Prise Large)', type: 'weight', restSeconds: 120, isPrimary: false,
        coachNote: 'âïļ Ratio Row/Bench bas (' + ratios.row_bench.value.toFixed(2) + ') â Rowing ajoutÃĐ.',
        sets: Array.from({ length: 3 }, function() { return { reps: 9, rpe: 8, weight: null, isWarmup: false }; })
      });
    }
  }

  // Rule 2 : Bench/Squat > 1/squat_bench.alert (STRENGTH_RATIO_TARGETS.squat_bench.alert = 1.20 â 0.833)
  // v223 â AlignÃĐ Gemini : Presse Ã  Cuisses (charge axiale rÃĐduite vs Hack Squat) pour
  // prioritÃĐ quad sans aggraver la fatigue post-Squat lourd.
  var _sqBenchAlert = (_t.squat_bench && _t.squat_bench.alert) || 1.20;
  if (dayKey === 'squat' && ratios.bench_squat && ratios.bench_squat.value > (1 / _sqBenchAlert)) {
    var accIdx = -1;
    var accCount = 0;
    for (var i = 0; i < exercises.length; i++) {
      if (!exercises[i].isPrimary && !exercises[i].isWarmup) { accCount++; if (accCount === 2) { accIdx = i; break; } }
    }
    if (accIdx >= 0) {
      // Ne pas ÃĐcraser si Presse Ã  Cuisses dÃĐjÃ  prÃĐsente AILLEURS dans le plan
      var _presseAlreadyInPlan = exercises.some(function(e) {
        return /presse Ã  cuisses/i.test(e.name || '');
      });
      if (!_presseAlreadyInPlan) {
        exercises[accIdx] = {
          name: 'Presse Ã  Cuisses', type: 'weight', restSeconds: 180, isPrimary: false,
          coachNote: 'âïļ Ratio Squat/Bench bas â Presse Ã  Cuisses prioritÃĐ quad (low-stress axial).',
          sets: Array.from({ length: 4 }, function() { return { reps: 8, rpe: 8, weight: null, isWarmup: false }; })
        };
      }
    }
  }

  // Rule 3 : Squat/Deadlift < seuil danger (STRENGTH_RATIO_TARGETS.squat_dead.danger = 0.78)
  // Seuil danger (pas alert) car la correction est agressive (Squat Pause en plus du DL)
  if (dayKey === 'deadlift' && ratios.squat_deadlift &&
      ratios.squat_deadlift.value < ((_t.squat_dead && _t.squat_dead.danger) || 0.80)) {
    var _alreadyHasSquatPause = exercises.some(function(e) {
      return /squat\s*pause/i.test(e.name || '');
    });
    if (!_alreadyHasSquatPause) {
      var _sqPause = {
        name: 'Squat Pause', type: 'weight', restSeconds: 240, isPrimary: false,
        coachNote: 'âïļ Ratio Squat/Deadlift bas (' + ratios.squat_deadlift.value.toFixed(2) + ') â Squat Pause ajoutÃĐ.',
        sets: Array.from({ length: 3 }, function() { return { reps: 4, rpe: 7.5, weight: null, isWarmup: false }; })
      };
      // Bloc Force : maintenir la correction mais intensitÃĐ technique (Gemini Q4)
      // â charge âĪ 70% e1RM squat, RPE âĪ 7 (technique sous fatigue, pas surcharge)
      if (phase === 'force') {
        var _sqE1rm = typeof getSmoothedE1RM === 'function'
          ? (getSmoothedE1RM('squat') || 0) : 0;
        var _cap70 = _sqE1rm > 0 ? Math.round(_sqE1rm * 0.70 / 2.5) * 2.5 : null;
        _sqPause.coachNote = 'âïļ Ratio Squat/Deadlift bas â Squat Pause technique (âĪ70% e1RM, RPE 7).';
        _sqPause.sets = _sqPause.sets.map(function(s) {
          return Object.assign({}, s, {
            weight: _cap70,
            rpe: Math.min(s.rpe || 7, 7)
          });
        });
      }
      exercises.push(_sqPause);
    }
  }

  // Rule 4 : OHP/Bench < seuil alert (STRENGTH_RATIO_TARGETS.ohp_bench.alert = 0.58)
  // MÃŠme seuil que le diagnostic Coach â correction visible = alerte visible
  if (dayKey === 'weakpoints' && ratios.ohp_bench &&
      ratios.ohp_bench.value < ((_t.ohp_bench && _t.ohp_bench.alert) || 0.60)) {
    exercises.unshift({
      name: 'DÃĐveloppÃĐ Militaire', type: 'weight', restSeconds: 180, isPrimary: true,
      coachNote: 'âïļ Ratio OHP/Bench bas (' + ratios.ohp_bench.value.toFixed(2) + ') â OHP en prioritÃĐ.',
      sets: Array.from({ length: 4 }, function() { return { reps: 6, rpe: 8, weight: null, isWarmup: false }; })
    });
  }

  return exercises;
}

var NEVER_SUPERSET = /squat|bench|deadlift|dÃĐveloppÃĐ couchÃĐ|soulevÃĐ|high bar|larsen|paused squat|rack pull|good morning/i;

function wpApplySupersets(exercises, pref) {
  var _pref = pref || (db.user && db.user.supersetPreference) || 'auto';
  if (_pref === 'standard') return exercises;
  var result = [];
  var i = 0;
  while (i < exercises.length) {
    var exo = exercises[i];
    var isHeavy = exo.isPrimary || NEVER_SUPERSET.test(exo.name || '');
    if (!isHeavy && i + 1 < exercises.length) {
      var next = exercises[i + 1];
      var nextIsHeavy = next.isPrimary || NEVER_SUPERSET.test(next.name || '');
      if (!nextIsHeavy) {
        exo.superset = true;
        exo.supersetWith = next.name;
        next.isSecondInSuperset = true;
        // v212 â null (et non 0) pour que l'UI affiche "EnchaÃŪner â" au lieu de "0s"
        next.restSeconds = null;
        result.push(exo);
        result.push(next);
        i += 2;
        continue;
      }
    }
    result.push(exo);
    i++;
  }
  return result;
}

function wpCoachNote(liftType, phase, weight, history) {
  var notes = [];
  var plateau = liftType ? wpDetectPlateau(liftType) : null;
  if (plateau) notes.push('â ïļ Plateau dÃĐtectÃĐ sur ' + liftType + ' â ' + plateau.correction.reason + '. Cette semaine : ' + plateau.correction.variation + '.');
  if (phase === 'peak') notes.push('Semaine Peak â gros efforts, rÃĐcupÃĐration maximale entre sÃĐances. RPE 9 tolÃĐrÃĐ.');
  if (phase === 'deload') notes.push('Deload â charges -20%, volume Ã·2. On recharge le SNC.');
  if (phase === 'accumulation') notes.push('Phase d\'accumulation â construire le volume, valider les paliers.');
  if (history && history.length > 0) {
    if (history[0].rpe >= 9.5) notes.push('RPE trÃĻs ÃĐlevÃĐ la semaine passÃĐe â charges ajustÃĐes Ã  la baisse.');
    else if (history[0].rpe < 7) notes.push('RPE faible â charges augmentÃĐes cette semaine.');
  }
  return notes.slice(0, 2).join(' ');
}

// Addendum H: Cardio adaptÃĐ blessures
function wpGetCardioForProfile(injuries, baseDuration, isCutting) {
  // PRIORITÃ 1 : rÃĐglage utilisateur
  var cardioSetting = db.user && db.user.programParams && db.user.programParams.cardio;
  if (cardioSetting === 'aucun' || cardioSetting === 'dedie') return null;

  // PRIORITÃ 2 : matrice mode Ã phase (getCardioDuration) â remplace la logique
  // progressive qui produisait 34 min aprÃĻs ~14 semaines d'entraÃŪnement.
  var _mode  = (db.user && db.user.trainingMode) || 'musculation';
  var _phase = (db.weeklyPlan && db.weeklyPlan.currentBlock && db.weeklyPlan.currentBlock.phase) || 'hypertrophie';
  var _goals = (db.user && db.user.programParams && db.user.programParams.goals) || (isCutting ? ['seche'] : []);
  // Pas de contrainte de temps restant ici â laisse la matrice retourner sa
  // valeur cible (powerbuilding Ã hypertrophie = 20, peak = 5, etc.).
  var _dur = (typeof getCardioDuration === 'function')
    ? getCardioDuration(_mode, _phase, _goals)
    : (baseDuration || 20);
  if (!_dur || _dur < 5) return null;

  // Ãquipement cardio selon mat
  var mat = (db.user && db.user.programParams && db.user.programParams.mat) || 'salle';
  var cardioName = mat === 'maison' ? 'Marche rapide'
    : mat === 'halteres' ? 'VÃĐlo stationnaire'
    : 'Tapis roulant';

  return {
    name: cardioName,
    type: 'cardio',
    restSeconds: 0,
    evictionCategory: 'cardio',
    sets: [{ durationMin: _dur, isWarmup: false, rpe: 5 }],
    coachNote: 'Cardio Z2 lÃĐger (' + _dur + 'min) â santÃĐ mitochondriale, prÃĐserver les gains'
  };
}

function getProgressiveCardioDuration(baseDuration) {
  var freq = (db.user && db.user.programParams && db.user.programParams.freq) || 4;
  var logsCount = (db.logs || []).length;
  var weeksOfTraining = Math.floor(logsCount / Math.max(1, freq));
  var increase = Math.floor(weeksOfTraining / 2) * 5;
  return Math.min(baseDuration * 2, baseDuration + increase);
}

// Addendum F: Pain Tracker
// Addendum D: SÃĐances manquÃĐes
function wpCountMissedSessions() {
  var routine = getRoutine();
  var now = Date.now();
  var weekStart = now - (new Date().getDay() || 7) * 86400000;
  weekStart = new Date(weekStart).setHours(0, 0, 0, 0);
  var todayStart = new Date().setHours(0, 0, 0, 0);
  var plannedDays = 0, doneDays = 0;
  var allDays = ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi','Dimanche'];
  allDays.forEach(function(day, idx) {
    var dayTs = weekStart + idx * 86400000;
    if (dayTs >= todayStart) return; // aujourd'hui et futur â pas encore manquÃĐ
    var label = routine[day] || '';
    if (!label || /repos/i.test(label)) return;
    plannedDays++;
    var done = (db.logs || []).some(function(l) { return l.timestamp >= dayTs && l.timestamp < dayTs + 86400000; });
    if (done) doneDays++;
  });
  return plannedDays - doneDays;
}

function wpAdjustForMissedSessions(plan, missed) {
  if (missed === 0) return plan;
  if (missed === 1) { plan.missedNote = '1 sÃĐance manquÃĐe â dÃĐcalage sur le lendemain possible.'; return plan; }
  if (missed === 2) {
    plan.days = plan.days.map(function(d) {
      if (d.rest) return d;
      // v195 â match base title only (before ' Â· DUP label') to avoid the
      // dynamic DUP label tripping the eviction regex (e.g. "Squat 2 Â·
      // Technique & Vitesse" was being compressed because 'Technique' matched).
      var baseTitle = String(d.title || '').split(' Â· ')[0];
      if (/point|faible|technique|accessoire/i.test(baseTitle)) {
        return { day: d.day, rest: true, title: 'ðī Repos (sÃĐance compressÃĐe)', exercises: [] };
      }
      return d;
    });
    plan.missedNote = '2 sÃĐances manquÃĐes â programme compressÃĐ sur les lifts principaux.';
    return plan;
  }
  plan.isRepeatWeek = true;
  plan.missedNote = 'Plus de 2 sÃĐances manquÃĐes â semaine rÃĐpÃĐtÃĐe. MÃŠmes charges qu\'avant.';
  var lastLog = (db.logs || []).slice().sort(function(a, b) { return (b.timestamp||0) - (a.timestamp||0); })[0];
  var daysSinceLastLog = lastLog ? Math.round((Date.now() - lastLog.timestamp) / 86400000) : 0;
  if (daysSinceLastLog > 10) {
    plan.days.forEach(function(d) {
      if (d.rest) return;
      d.exercises.forEach(function(exo) {
        exo.sets = (exo.sets || []).map(function(s) {
          if (s.isWarmup || !s.weight) return s;
          return Object.assign({}, s, { weight: wpRound25(s.weight * 0.95) });
        });
      });
    });
    plan.missedNote += ' Gap > 10 jours â charges rÃĐduites de 5%.';
  }
  return plan;
}

