// Ouvre une question coach pour un exercice de la sÃĐance active.
window.openCoachQuestion = function(exoIdx, btn) {
  var access = typeof canUseAI === 'function' ? canUseAI() : { allowed: true, unlimited: true };
  if (!access.allowed) {
    if (typeof showPaywall === 'function') showPaywall();
    return;
  }

  if (!activeWorkout || !activeWorkout.exercises || !activeWorkout.exercises[exoIdx]) return;
  var exo = activeWorkout.exercises[exoIdx];

  // Snapshot enrichi : nom, sets, reps, RPE, weight, raison algo, phase, dernier poids
  var workSets = (exo.sets || []).filter(function(s) { return s && !s.isWarmup && s.type !== 'warmup'; });
  var firstWork = workSets[0] || {};
  var shadowW = (db.exercises && db.exercises[exo.name]) ? (db.exercises[exo.name].shadowWeight || 0) : 0;
  var suggestedW = firstWork.weight || 0;
  var chargeExp = (typeof buildChargeExplanation === 'function')
    ? buildChargeExplanation(exo.name, suggestedW, shadowW)
    : null;
  var completedCount = workSets.filter(function(s) { return s.completed; }).length;
  var phase = (db.weeklyPlan && db.weeklyPlan.currentBlock && db.weeklyPlan.currentBlock.phase) || 'hypertrophie';
  var setsCount = workSets.length || (exo.sets || []).length;
  var repsVal = firstWork.reps || (exo.sets && exo.sets[0] && exo.sets[0].reps) || 'â';

  // Raison par dÃĐfaut si aucune explication algo : dÃĐduire depuis la phase
  var reason = chargeExp ? chargeExp.text : null;
  if (!reason && setsCount && repsVal !== 'â') {
    var setsStr = setsCount + 'x' + repsVal;
    reason = phase === 'hypertrophie'
      ? setsStr + ' pour maximiser le temps sous tension en phase volume'
      : phase === 'force'
      ? setsStr + ' pour dÃĐvelopper la force maximale en phase intensitÃĐ'
      : phase === 'deload'
      ? setsStr + ' en deload pour rÃĐcupÃĐrer sans perdre les acquis'
      : setsStr + ' selon le protocole ' + phase;
  }

  var exoContext = {
    name: exo.name,
    sets: setsCount,
    reps: repsVal,
    rpe: firstWork.rpe || (exo.sets && exo.sets[0] && exo.sets[0].rpe) || 'â',
    weight: suggestedW || 'â',
    reason: reason,
    phase: phase,
    lastWeight: shadowW || null,
    setsCompleted: completedCount + '/' + (workSets.length || setsCount)
  };

  var exoId = (exo.name || 'exo').replace(/[^a-z0-9]+/gi, '_').toLowerCase();
  var answerDiv = document.getElementById('why-answer-' + exoId);
  var btnEl = document.getElementById('why-btn-' + exoId) || btn;
  if (!answerDiv) return;

  // Toggle si dÃĐjÃ  ouvert
  if (answerDiv.style.display !== 'none') {
    answerDiv.style.display = 'none';
    return;
  }

  answerDiv.style.display = 'block';
  answerDiv.innerHTML = '<span style="color:#7c6bff;font-family:monospace;">âģ Coach en train de rÃĐflÃĐchir...</span>';
  if (btnEl) btnEl.disabled = true;

  var question = 'Pourquoi cet exercice dans ma sÃĐance aujourd\'hui ?';

  askCoachAI(
    question,
    exoContext,
    function(answer) {
      answerDiv.innerHTML = '<span style="color:#7c6bff;font-size:8px;font-family:monospace;letter-spacing:1px;">COACH IA</span><br>'
        + String(answer).replace(/[<>]/g, function(c) { return c === '<' ? '&lt;' : '&gt;'; });
      if (btnEl) { btnEl.disabled = false; btnEl.textContent = 'â RÃĐponse'; }
    },
    function(errType, waitSec) {
      var msg = errType === 'cooldown'
        ? 'âģ Attends encore ' + waitSec + 's...'
        : errType === 'queue'
        ? 'âģ File d\'attente... rÃĐessai dans ' + waitSec + 's'
        : 'â  Coach indisponible. RÃĐessaie demain.';
      answerDiv.innerHTML = '<span style="color:#f97316;font-size:10px;">' + msg + '</span>';
      if (btnEl) btnEl.disabled = false;
    }
  );
};

// Paywall affichÃĐ quand un user free a ÃĐpuisÃĐ son crÃĐdit hebdo.
function showPaywall() {
  if (document.getElementById('ai-paywall')) return;
  var now = new Date();
  var nextMonday = new Date(now);
  var dow = now.getDay(); // 0=dim, 1=lun
  var daysUntil = ((8 - dow) % 7) || 7;
  nextMonday.setDate(now.getDate() + daysUntil);
  var dayLabel = daysUntil > 1 ? 's' : '';

  document.body.insertAdjacentHTML('beforeend',
    '<div id="ai-paywall" style="position:fixed;top:0;left:0;width:100%;height:100%;' +
    'background:rgba(5,5,9,.97);z-index:var(--z-overlay);display:flex;flex-direction:column;' +
    'align-items:center;justify-content:center;padding:24px;">' +
    '<div style="max-width:300px;text-align:center;">' +
      '<div style="font-size:9px;color:#7c6bff;font-family:monospace;letter-spacing:3px;margin-bottom:16px;">COACH IA</div>' +
      '<div style="font-size:22px;font-weight:800;margin-bottom:10px;">Question utilisÃĐe ðŽ</div>' +
      '<div style="font-size:12px;color:#9999bb;line-height:1.7;margin-bottom:24px;">' +
        'Tu as utilisÃĐ ta question gratuite cette semaine.<br>' +
        'Prochaine disponible dans <strong style="color:#fff">' + daysUntil + ' jour' + dayLabel + '</strong>.' +
      '</div>' +
      '<button style="width:100%;padding:13px;background:#7c6bff;border:none;border-radius:12px;' +
        'color:#fff;font-size:13px;font-weight:700;cursor:pointer;margin-bottom:8px;">' +
        'Passer Premium Â· IllimitÃĐ â' +
      '</button>' +
      '<button onclick="document.getElementById(\'ai-paywall\').remove()" ' +
        'style="width:100%;padding:10px;background:transparent;border:1px solid #2a2a45;' +
        'border-radius:12px;color:#6a6a8a;font-size:12px;cursor:pointer;">' +
        'Continuer en gratuit' +
      '</button>' +
    '</div></div>'
  );
}

// ââ Render a single exercise card ââ
// Audit Trail â explique pourquoi la charge proposÃĐe diffÃĻre de la shadowWeight.
// Retourne null si la variation est nÃĐgligeable ou si aucune raison active n'a ÃĐtÃĐ dÃĐtectÃĐe.
function buildChargeExplanation(exoName, calculatedWeight, shadowWeight) {
  if (!shadowWeight || shadowWeight <= 0 || !calculatedWeight) return null;
  var diff = calculatedWeight - shadowWeight;
  var pct = Math.round(Math.abs(diff) / shadowWeight * 100);
  if (pct < 3) return null; // Variation nÃĐgligeable

  var reasons = [];

  if (db._killSwitchActive) reasons.push('Mode CompÃĐtition actif');

  var srs = typeof computeSRS === 'function' ? computeSRS() : null;
  if (srs && typeof srs.score === 'number' && srs.score < 50) {
    reasons.push('RÃĐcupÃĐration basse (SRS ' + srs.score + ')');
  }

  var acwr = typeof computeACWR === 'function' ? computeACWR() : null;
  if (acwr && acwr > 1.3) reasons.push('Charge hebdo ÃĐlevÃĐe (ACWR ' + acwr + ')');

  var _ckBce = getTodayCheckin(); // READY-C2-c â contrÃīle de date portÃĐ par l'accesseur
  var todayStr = new Date().toISOString().split('T')[0];
  if (_ckBce && _ckBce.sleep5 && _ckBce.sleep5 <= 2) {
    reasons.push('Sommeil insuffisant (' + _ckBce.sleep5 + '/5)');
  }

  if (db.user && db.user.menstrualEnabled && typeof getCurrentMenstrualPhase === 'function') {
    var phase = getCurrentMenstrualPhase();
    if (phase === 'luteale') reasons.push('Phase lutÃĐale (-12 %)');
    else if (phase === 'folliculaire_precoce') reasons.push('Phase folliculaire prÃĐcoce (-8 %)');
  }

  if (db.user && db.user.weightCut && db.user.weightCut.active) {
    reasons.push('Weight Cut actif');
  }

  if (db.garminHealth && db.garminHealth.date === todayStr && db.garminHealth.rhrAlert) { // READY-C2-c
    var lvl = db.garminHealth.rhrAlert.level;
    if (lvl === 'danger' || lvl === 'warning') reasons.push('FC repos ÃĐlevÃĐe');
  }

  if (typeof getAbsencePenalty === 'function') {
    var abs = getAbsencePenalty();
    if (abs && abs.factor < 1.0) reasons.push('Reprise (' + (abs.days || '?') + 'j absence)');
  }

  if (reasons.length === 0) return null;

  var direction = diff < 0 ? 'rÃĐduite' : 'augmentÃĐe';
  return {
    text: 'Charge ' + direction + ' de ' + pct + ' % Â· ' + reasons.join(' Â· '),
    color: diff < 0 ? 'var(--orange)' : 'var(--green)'
  };
}

// ââ Sparkline de progression par exercice (carte GO) â LECTURE SEULE ââââââââ
// Un point = une sÃĐance passÃĐe contenant l'exercice ; valeur = meilleur e1RM
// (Brzycki, calcE1RM) des work sets. Source primaire : exercise.series, qui ne
// contient QUE les sets 'normal' complÃĐtÃĐs non abandonnÃĐs (convertWorkoutToSession) ;
// fallback allSets filtrÃĐ setType==='normal' pour les formes legacy/import.
// Cache mÃĐmoire pur (invalidÃĐ quand db.logs change de longueur) â AUCUNE ÃĐcriture db.
var _sparkCache = {};

function computeExoSparklineData(exoName, maxPoints) {
  if (!exoName || typeof db === 'undefined' || !db || !Array.isArray(db.logs) || db.logs.length < 2) return null;
  maxPoints = maxPoints || 10;
  var _cached = _sparkCache[exoName];
  if (_cached && _cached.logsLen === db.logs.length) return _cached.points;

  var targetNorm = wpNormalizeName(exoName);
  var resolved = typeof wpFindBestMatch === 'function' ? wpFindBestMatch(exoName, db.logs) : null;
  var resolvedNorm = resolved ? wpNormalizeName(resolved) : null;

  var points = [];
  // db.logs : plus rÃĐcent en premier (index 0)
  for (var i = 0; i < db.logs.length && points.length < maxPoints; i++) {
    var exos = db.logs[i].exercises || [];
    var best = 0;
    for (var j = 0; j < exos.length; j++) {
      var n = wpNormalizeName(exos[j].name);
      if (n !== targetNorm && n !== resolvedNorm) continue;
      var sets = (exos[j].series && exos[j].series.length)
        ? exos[j].series
        : (exos[j].allSets || []).filter(function(s) { return (s.setType || 'normal') === 'normal'; });
      for (var k = 0; k < sets.length; k++) {
        var w = parseFloat(sets[k].weight) || 0;
        var r = parseInt(sets[k].reps) || 0;
        if (w <= 0 || r <= 0) continue;
        var e = calcE1RM(w, r);
        if (e > best) best = e;
      }
    }
    if (best > 0) points.push({ t: db.logs[i].timestamp || 0, e1rm: best });
  }

  var result = points.length >= 2 ? points.reverse() : null; // chronologique gauche â droite
  _sparkCache[exoName] = { logsLen: db.logs.length, points: result };
  return result;
}

