    + '<div style="font-size:32px;margin-bottom:8px;">ð</div>'
    + '<div style="font-size:16px;font-weight:800;margin-bottom:4px;">Nouveau record dÃĐtectÃĐ !</div>'
    + '<div style="font-size:13px;color:var(--sub);margin-bottom:16px;">'
    + '<strong>' + prData.weight + 'kg Ã ' + prData.reps + '</strong> au '
    + (liftLabels[prData.liftKey] || prData.liftKey)
    + ' â nouvelle meilleure barre (prÃĐcÃĐdent : ' + prData.currentPR + 'kg)</div>'
    + '<button onclick="confirmNewPR(\'' + prData.liftKey + '\',' + prData.weight + ')" '
    + 'style="width:100%;padding:12px;border-radius:10px;background:var(--accent);'
    + 'border:none;color:#fff;font-weight:700;cursor:pointer;margin-bottom:8px;">'
    + 'Valider ' + prData.weight + 'kg comme nouveau PR ð</button>'
