// ============================================================
// GO TAB â Exercise Search Overlay
// ============================================================
// Filtre picker multi-select (faÃ§on Hevy) : deux Set de sÃĐlections, un seul
// panneau dÃĐroulant ouvert Ã  la fois. Le filtrage est routÃĐ via goRenderSearchResults
// (prÃĐserve le fix remplacement v320 + le cap/scroll Phase 2a).
var _goEquipSel = new Set();
var _goMuscleSel = new Set();
var _goOpenPanel = null; // 'equip' | 'muscle' | null
// Chips ÃĐquipement (8) : [displayEquip, label]. Ordre = du plus frÃĐquent au moins.
var _GO_EQUIP_CHIPS = [
  ['barbell', 'Barre'], ['bodyweight', 'Poids du corps'], ['dumbbell', 'HaltÃĻre'],
  ['cable', 'Poulie'], ['machine', 'Machine'], ['kettlebell', 'Kettlebell'],
  ['band', 'Ãlastique'], ['other', 'Autre']
];
// Chips muscle (7) = clÃĐs de _goMuscleMap (le val EST le label).
var _GO_MUSCLE_CHIPS = ['Pecs', 'Dos', 'Ãpaules', 'Jambes', 'Bras', 'Abdos', 'Cardio'];
// Polish E 2a â ÃĐtat du rendu progressif du picker (cap + append au scroll).
var _goRenderState = null;
var _goResultsObserver = null;
var _goMuscleMap = {
  'Pecs': ['Pecs','Pecs (haut)','Pecs (bas)'],
  'Dos': ['Grand dorsal','Haut du dos','TrapÃĻzes','Lombaires'],
  'Ãpaules': ['Ãpaules','Ãpaules (antÃĐrieur)','Ãpaules (latÃĐral)','Ãpaules (postÃĐrieur)'],
  'Jambes': ['Quadriceps','Ischio-jambiers','Fessiers','Mollets','Adducteurs','Abducteurs'],
  'Bras': ['Biceps','Triceps','Avant-bras'],
  'Abdos': ['Abdos (frontal)','Obliques'],
  'Cardio': ['Cardio']
};

// CatÃĐgorie d'ÃĐquipement d'AFFICHAGE : affine le fourre-tout 'other' vers
// kettlebell/band par marqueur de nom. DÃĐrivation Ã  la volÃĐe (0 mutation d'EXO_DATABASE).
function _goDeriveEquip(exo) {
  var eq = exo.equipment;
  if (eq && eq !== 'other') return eq; // barbell/dumbbell/machine/cable/bodyweight/band
  var n = (exo.name || '').toLowerCase();
  if (/kettlebell|kb\b/i.test(n)) return 'kettlebell';
  if (/bande|ÃĐlastique|band pull|pull-apart|monster walk|clamshell|with bands/i.test(n)) return 'band';
  return 'other'; // anneaux/sled/cardio/strongman/plyo restent ÂŦ Autre Âŧ
}

// Groupes musculaires canoniques (via _goMuscleMap) portÃĐs par un exo, prÃĐcalculÃĐs Ã  l'index.
function _goExoGroups(primaryMuscles) {
  var groups = [];
  var pm = primaryMuscles || [];
  for (var g in _goMuscleMap) {
    for (var i = 0; i < pm.length; i++) {
      if (_goMuscleMap[g].indexOf(pm[i]) >= 0) { groups.push(g); break; }
    }
  }
  return groups;
}

function goOpenSearch() {
  _goEquipSel = new Set();
  _goMuscleSel = new Set();
  _goOpenPanel = null;
  var overlay = document.createElement('div');
  overlay.className = 'go-search-overlay';
  overlay.id = 'goSearchOverlay';

  var h = '<div class="go-search-header">';
  h += '<button class="go-search-back" onclick="goCloseSearch()">â Retour</button>';
  h += '<input class="go-search-input" id="goSearchInput" type="text" placeholder="ð Rechercher un exercice..." autofocus>';
  h += '</div>';
  // Barre de filtres : 2 boutons (ÃĐquipement / muscle) + panneaux dÃĐroulants compacts.
  h += '<div class="go-filter-bar">';
  h += '<button class="go-filter-btn" id="goEquipBtn" onclick="goTogglePanel(\'equip\')"><span id="goEquipBtnLabel">Tous les ÃĐquipements</span><span class="go-filter-chev">âū</span></button>';
  h += '<button class="go-filter-btn" id="goMuscleBtn" onclick="goTogglePanel(\'muscle\')"><span id="goMuscleBtnLabel">Tous les muscles</span><span class="go-filter-chev">âū</span></button>';
  h += '</div>';
  h += '<div class="go-filter-panel" id="goEquipPanel" style="display:none;"></div>';
  h += '<div class="go-filter-panel" id="goMusclePanel" style="display:none;"></div>';
  h += '<div class="go-search-results" id="goSearchResults"></div>';
  overlay.innerHTML = h;
  document.body.appendChild(overlay);
  goRenderSearchResults('');
  document.getElementById('goSearchInput').addEventListener('input', function() {
    var q = this.value;
    if (_goSearchDebounce) clearTimeout(_goSearchDebounce);
    _goSearchDebounce = setTimeout(function() { goRenderSearchResults(q); }, 200);
  });
}

function goCloseSearch() {
  var el = document.getElementById('goSearchOverlay');
  if (el) el.remove();
  if (_goResultsObserver) { _goResultsObserver.disconnect(); _goResultsObserver = null; }
  _goRenderState = null;
  _goOpenPanel = null;
  window._goReplaceIdx = undefined;
}

// Comptes par chip, calculÃĐs depuis le catalogue (statiques). Construit l'index au besoin.
function _goComputeChipCounts() {
  if (!_exoSearchIndex) buildExoSearchIndex();
  var eqC = {}, muC = {};
  for (var i = 0; i < _exoSearchIndex.length; i++) {
    var e = _exoSearchIndex[i];
    eqC[e.displayEquip] = (eqC[e.displayEquip] || 0) + 1;
    for (var j = 0; j < e.groups.length; j++) muC[e.groups[j]] = (muC[e.groups[j]] || 0) + 1;
  }
  return { equip: eqC, muscle: muC };
}

// Rend les chips d'un panneau (ÃĐquipement ou muscle) avec compte + ÃĐtat actif.
function _goRenderFilterPanel(which) {
  var counts = _goComputeChipCounts();
  var chips = which === 'equip' ? _GO_EQUIP_CHIPS : _GO_MUSCLE_CHIPS.map(function(m) { return [m, m]; });
  var sel = which === 'equip' ? _goEquipSel : _goMuscleSel;
  var cmap = which === 'equip' ? counts.equip : counts.muscle;
  var h = '';
  chips.forEach(function(c) {
    var val = c[0], label = c[1];
    var n = cmap[val] || 0;
    var active = sel.has(val);
    h += '<span class="go-filter-chip' + (active ? ' active' : '') + '" onclick="goToggleFilter(\'' + which + '\',\'' + val.replace(/'/g, "\\'") + '\')">';
    if (active) h += 'â ';
    h += label + ' <span class="go-filter-chip-count">' + n + '</span></span>';
  });
  return h;
}

// Ouvre/ferme un panneau (un seul ouvert Ã  la fois : ouvrir muscle ferme ÃĐquipement).
function goTogglePanel(which) {
  _goOpenPanel = (_goOpenPanel === which) ? null : which;
  var eqP = document.getElementById('goEquipPanel');
  var muP = document.getElementById('goMusclePanel');
  var eqB = document.getElementById('goEquipBtn');
  var muB = document.getElementById('goMuscleBtn');
  if (eqP) { if (_goOpenPanel === 'equip') { eqP.innerHTML = _goRenderFilterPanel('equip'); eqP.style.display = 'flex'; } else { eqP.style.display = 'none'; } }
  if (muP) { if (_goOpenPanel === 'muscle') { muP.innerHTML = _goRenderFilterPanel('muscle'); muP.style.display = 'flex'; } else { muP.style.display = 'none'; } }
  if (eqB) eqB.classList.toggle('open', _goOpenPanel === 'equip');
  if (muB) muB.classList.toggle('open', _goOpenPanel === 'muscle');
}

// Toggle d'une sÃĐlection dans le Set, maj du panneau + libellÃĐs + rÃĐsultats.
function goToggleFilter(which, val) {
  var sel = which === 'equip' ? _goEquipSel : _goMuscleSel;
  if (sel.has(val)) sel.delete(val); else sel.add(val);
  var panel = document.getElementById(which === 'equip' ? 'goEquipPanel' : 'goMusclePanel');
  if (panel) panel.innerHTML = _goRenderFilterPanel(which);
  _goUpdateFilterButtons();
  var q = document.getElementById('goSearchInput') ? document.getElementById('goSearchInput').value : '';
  goRenderSearchResults(q);
}

// LibellÃĐ dynamique + bordure active des 2 boutons selon les Set de sÃĐlection.
function _goUpdateFilterButtons() {
  var eqLabel = document.getElementById('goEquipBtnLabel');
  var muLabel = document.getElementById('goMuscleBtnLabel');
  var eqB = document.getElementById('goEquipBtn');
  var muB = document.getElementById('goMuscleBtn');
  if (eqLabel) {
    if (_goEquipSel.size === 0) eqLabel.textContent = 'Tous les ÃĐquipements';
    else if (_goEquipSel.size === 1) { var v = [].concat(Array.from(_goEquipSel))[0]; var found = _GO_EQUIP_CHIPS.filter(function(c) { return c[0] === v; })[0]; eqLabel.textContent = found ? found[1] : v; }
    else eqLabel.textContent = _goEquipSel.size + ' ÃĐquipements';
  }
  if (muLabel) {
    if (_goMuscleSel.size === 0) muLabel.textContent = 'Tous les muscles';
    else if (_goMuscleSel.size === 1) muLabel.textContent = Array.from(_goMuscleSel)[0];
    else muLabel.textContent = _goMuscleSel.size + ' muscles';
  }
  if (eqB) eqB.classList.toggle('has-sel', _goEquipSel.size > 0);
  if (muB) muB.classList.toggle('has-sel', _goMuscleSel.size > 0);
}


function _goNormalize(str) {
  return str.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/['']/g, "'");
}

// Fuzzy matching â tolÃĐrance aux fautes de frappe
function _fuzzyMatch(needle, haystack) {
  if (!needle || !haystack) return 0;
  if (haystack.indexOf(needle) >= 0) return 100; // Exact substring = score max
  // Score par distance de Levenshtein partielle (mots)
  var needleWords = needle.split(/\s+/);
  var haystackWords = haystack.split(/\s+/);
  var totalScore = 0;
  var matched = 0;
  for (var i = 0; i < needleWords.length; i++) {
    var nw = needleWords[i];
    if (nw.length < 2) continue;
    var bestWordScore = 0;
    for (var j = 0; j < haystackWords.length; j++) {
      var hw = haystackWords[j];
      // Exact word prefix match
      if (hw.indexOf(nw) === 0) { bestWordScore = Math.max(bestWordScore, 90); continue; }
      // Substring match
      if (hw.indexOf(nw) >= 0) { bestWordScore = Math.max(bestWordScore, 80); continue; }
      // Fuzzy: Levenshtein distance tolerance (max 2 edits for words >= 4 chars)
      if (nw.length >= 4) {
        var dist = _levenshtein(nw, hw.substring(0, Math.max(nw.length + 2, hw.length)));
        var maxDist = nw.length <= 5 ? 1 : 2;
        if (dist <= maxDist) { bestWordScore = Math.max(bestWordScore, 70 - dist * 10); }
      }
    }
    if (bestWordScore > 0) { totalScore += bestWordScore; matched++; }
  }
  if (needleWords.length === 0) return 0;
  return matched === needleWords.length ? Math.round(totalScore / needleWords.length) : (matched > 0 ? Math.round(totalScore / needleWords.length * 0.5) : 0);
}

function _levenshtein(a, b) {
  if (a.length === 0) return b.length;
  if (b.length === 0) return a.length;
  var matrix = [];
  for (var i = 0; i <= b.length; i++) matrix[i] = [i];
  for (var j = 0; j <= a.length; j++) matrix[0][j] = j;
  for (var i = 1; i <= b.length; i++) {
    for (var j = 1; j <= a.length; j++) {
      var cost = a[j - 1] === b[i - 1] ? 0 : 1;
      matrix[i][j] = Math.min(matrix[i - 1][j] + 1, matrix[i][j - 1] + 1, matrix[i - 1][j - 1] + cost);
    }
  }
  return matrix[b.length][a.length];
}

// Pre-computed search index for EXO_DATABASE
var _exoSearchIndex = null;

function buildExoSearchIndex() {
  _exoSearchIndex = [];
  var keys = Object.keys(EXO_DATABASE);
  for (var i = 0; i < keys.length; i++) {
    var k = keys[i];
    var e = EXO_DATABASE[k];
    var searchText = _goNormalize(e.name);
    if (e.nameAlt) {
      for (var j = 0; j < e.nameAlt.length; j++) { searchText += ' ' + _goNormalize(e.nameAlt[j]); }
    }
    var muscleStr = '';
    if (e.primaryMuscles) {
      for (var j = 0; j < e.primaryMuscles.length; j++) { muscleStr += ' ' + _goNormalize(e.primaryMuscles[j]); }
    }
    _exoSearchIndex.push({
      id: k,
      data: e,
      searchText: searchText,
      muscleSearchText: muscleStr,
      equipment: e.equipment,
      displayEquip: _goDeriveEquip(e),
      groups: _goExoGroups(e.primaryMuscles),
      difficulty: e.difficulty || 2,
      primaryMuscles: e.primaryMuscles || []
    });
  }
}

function goRenderSearchResults(query) {
  // Filtres multi-select : Set ÃĐquipement (displayEquip) Ã Set muscle (groupes canoniques).
  // Combinaison : equipement â sÃĐlection ET muscle â sÃĐlection (Set vide = pas de contrainte).
  var equipSel = _goEquipSel;
  var muscleSel = _goMuscleSel;
  var container = document.getElementById('goSearchResults');
  if (!container) return;
  var q = _goNormalize(query.trim());
  var allE1RMs = getAllBestE1RMs();
  var results = [];

  // Build index on first use
  if (!_exoSearchIndex) buildExoSearchIndex();

  // Search using pre-computed index
  for (var i = 0; i < _exoSearchIndex.length; i++) {
    var entry = _exoSearchIndex[i];
    // Equipment filter (multi) â sur la catÃĐgorie d'affichage dÃĐrivÃĐe (displayEquip)
    if (equipSel.size && !equipSel.has(entry.displayEquip)) continue;
    // Muscle filter (multi) â intersection avec les groupes canoniques de l'exo
    if (muscleSel.size) {
      var hasGroup = false;
      for (var j = 0; j < entry.groups.length; j++) {
        if (muscleSel.has(entry.groups[j])) { hasGroup = true; break; }
      }
      if (!hasGroup) continue;
    }
    // Text search â fuzzy matching
    if (q) {
      // 1. Exact substring match (original logic)
      var exactMatch = entry.searchText.indexOf(q) >= 0;
      if (!exactMatch) {
        var qWords = q.split(/\s+/);
        exactMatch = qWords.every(function(w) { return entry.searchText.indexOf(w) >= 0; });
      }
      if (!exactMatch) {
        exactMatch = q.split(/\s+/).every(function(w) { return entry.muscleSearchText.indexOf(w) >= 0; });
      }
      // 2. Fuzzy match si pas de match exact
      var fuzzyScore = 0;
      if (!exactMatch) {
        fuzzyScore = _fuzzyMatch(q, entry.searchText);
        if (fuzzyScore < 50) fuzzyScore = Math.max(fuzzyScore, _fuzzyMatch(q, entry.muscleSearchText));
        if (fuzzyScore < 50) continue;
      }
      entry._searchScore = exactMatch ? 100 : fuzzyScore;
    } else {
      entry._searchScore = 50;
    }
    results.push(entry.data);
    entry.data._searchScore = entry._searchScore;
  }

  // Search custom exercises (displayEquip + groups dÃĐrivÃĐs Ã  la volÃĐe, mÃŠme rÃĻgles)
  (db.customExercises || []).forEach(function(e) {
    if (equipSel.size && !equipSel.has(_goDeriveEquip(e))) return;
    if (muscleSel.size) {
      var cg = _goExoGroups(e.primaryMuscles);
      var ok = false;
      for (var k = 0; k < cg.length; k++) { if (muscleSel.has(cg[k])) { ok = true; break; } }
      if (!ok) return;
    }
    if (q) {
      var nameN = _goNormalize(e.name);
      if (nameN.indexOf(q) < 0) return;
    }
    results.push(e);
  });

  var h = '';

  // Sort: search score first, then history, then difficulty
  results.sort(function(a, b) {
    var aScore = a._searchScore || 50;
    var bScore = b._searchScore || 50;
    if (bScore !== aScore) return bScore - aScore;
    var aE1 = allE1RMs[a.name] ? 1 : 0;
    var bE1 = allE1RMs[b.name] ? 1 : 0;
    if (bE1 !== aE1) return bE1 - aE1;
    return (a.difficulty || 2) - (b.difficulty || 2);
  });

  // Counter
  var hasFilters = equipSel.size || muscleSel.size || q;
  if (hasFilters) h += '<div style="font-size:11px;color:var(--sub);padding:4px 16px;">' + results.length + ' exercice' + (results.length > 1 ? 's' : '') + ' trouvÃĐ' + (results.length > 1 ? 's' : '') + '</div>';

  // If no query, show recent exercises first
  if (!q && !equipSel.size && !muscleSel.size) {
    var recents = _goGetRecentExercises(5);
    if (recents.length) {
      h += '<div class="go-search-section">RÃĐcents</div>';
      recents.forEach(function(name) {
        var ms = _ecMuscleStyle(name);
        var e1rm = allE1RMs[name] ? allE1RMs[name].e1rm : 0;
        // Chercher l'id pour l'image
        var _rExoId = null;
        for (var _rk in EXO_DATABASE) { if (EXO_DATABASE[_rk].name === name) { _rExoId = _rk; break; } }
        var _rImgUrl = _rExoId ? getExoImageUrl(_rExoId, 0) : null;
        h += '<div class="go-search-item" onclick="goSelectSearchResult(\'' + name.replace(/'/g, "\\'") + '\',\'' + (_rExoId || '') + '\')">';
        if (_rImgUrl) {
          h += '<div class="go-search-item-icon" style="padding:0;"><img src="' + _rImgUrl + '" loading="lazy" style="width:100%;height:100%;object-fit:cover;border-radius:50%;" onerror="this.parentNode.style.background=\'' + ms.bg + '\';this.parentNode.innerHTML=\'' + ms.icon + '\';"></div>';
        } else {
          h += '<div class="go-search-item-icon" style="background:' + ms.bg + ';">' + ms.icon + '</div>';
        }
        h += '<div class="go-search-item-info"><div class="go-search-item-name">' + name + '</div>';
        h += '<div class="go-search-item-sub">RÃĐcent</div></div>';
        if (e1rm > 0) h += '<div class="go-search-item-e1rm">' + Math.round(e1rm) + 'kg</div>';
        h += '</div>';
      });
      h += '<div class="go-search-section">Tous les exercices</div>';
    }
  }

  // Render results
  if (results.length === 0 && q) {
    h += '<div style="text-align:center;padding:40px 0;color:var(--sub);">Aucun rÃĐsultat pour "' + query + '"</div>';
  }

  // Polish E 2a â rendu progressif : on ne monte qu'un premier lot (BATCH), puis on
  // append les lots suivants au scroll (IntersectionObserver sur une sentinelle). Ãvite
  // le montage DOM des ~1020 items d'un coup ET borne les requÃŠtes images lazy.
  // Items dans #goResultsItems ; sentinelle + lien "crÃĐer" en bas (append AVANT eux).
  h += '<div id="goResultsItems"></div>';
  h += '<div id="goResultsSentinel" style="height:1px;"></div>';
  h += '<div class="go-search-create" onclick="goCloseSearch();goOpenWizard();">â CrÃĐer un exercice personnalisÃĐ</div>';
  container.innerHTML = h;

  _goRenderState = { results: results, rendered: 0, batch: 50, allE1RMs: allE1RMs };
  _goAppendResultBatch();
  _goSetupResultsObserver(container);
}

// Construit le HTML d'une ligne de rÃĐsultat (factorisÃĐ pour le rendu par lots).
function _goBuildResultItemHtml(e, allE1RMs) {
  var ms = _ecMuscleStyle(e.name);
  var equipLabels = { barbell: 'Barre', dumbbell: 'HaltÃĻres', machine: 'Machine', cable: 'CÃĒble', bodyweight: 'Corps', other: 'Autre' };
  var diffStars = '';
  if (e.difficulty) { for (var ds = 1; ds <= e.difficulty; ds++) diffStars += 'â'; }
  var sub = (equipLabels[e.equipment] || '') + ' Â· ' + (ms.tag || '') + (diffStars ? ' Â· ' + diffStars : '');
  var e1rm = allE1RMs[e.name] ? allE1RMs[e.name].e1rm : 0;
  var _sImgUrl = e.id ? getExoImageUrl(e.id, 0) : null;
  var out = '<div class="go-search-item" onclick="goSelectSearchResult(\'' + e.name.replace(/'/g, "\\'") + '\',\'' + (e.id || '') + '\')">';
  if (_sImgUrl) {
    out += '<div class="go-search-item-icon" style="padding:0;overflow:hidden;border-radius:10px;"><img src="' + _sImgUrl + '" loading="lazy" style="width:100%;height:100%;object-fit:cover;" onerror="this.parentNode.style.background=\'' + ms.bg + '\';this.parentNode.innerHTML=\'' + ms.icon + '\';"></div>';
  } else {
    out += '<div class="go-search-item-icon" style="background:' + ms.bg + ';">' + ms.icon + '</div>';
  }
  out += '<div class="go-search-item-info"><div class="go-search-item-name">' + e.name + '</div>';
  out += '<div class="go-search-item-sub">' + sub + '</div></div>';
  if (e1rm > 0) out += '<div class="go-search-item-e1rm">' + Math.round(e1rm) + 'kg</div>';
  out += '</div>';
  return out;
}

// Append le lot suivant dans #goResultsItems (append-only, pas de virtualisation).
function _goAppendResultBatch() {
  var st = _goRenderState;
  if (!st) return;
  var itemsEl = document.getElementById('goResultsItems');
  if (!itemsEl) return;
  var end = Math.min(st.rendered + st.batch, st.results.length);
  var frag = '';
  for (var i = st.rendered; i < end; i++) frag += _goBuildResultItemHtml(st.results[i], st.allE1RMs);
  if (frag) itemsEl.insertAdjacentHTML('beforeend', frag);
  st.rendered = end;
  if (st.rendered >= st.results.length && _goResultsObserver) {
    _goResultsObserver.disconnect();
    _goResultsObserver = null;
  }
}

// (RÃĐ)installe l'observateur de scroll sur la sentinelle de bas de liste.
function _goSetupResultsObserver(container) {
  if (_goResultsObserver) { _goResultsObserver.disconnect(); _goResultsObserver = null; }
  var sentinel = document.getElementById('goResultsSentinel');
  if (!sentinel) return;
  if (!_goRenderState || _goRenderState.rendered >= _goRenderState.results.length) return; // tout dÃĐjÃ  rendu
  if (typeof IntersectionObserver === 'undefined') {
    // Fallback : listener scroll near-bottom
    container.addEventListener('scroll', function _onScroll() {
      if (!_goRenderState || _goRenderState.rendered >= _goRenderState.results.length) { container.removeEventListener('scroll', _onScroll); return; }
      if (container.scrollTop + container.clientHeight >= container.scrollHeight - 400) _goAppendResultBatch();
    });
    return;
  }
  _goResultsObserver = new IntersectionObserver(function(entries) {
    if (entries.some(function(en) { return en.isIntersecting; })) _goAppendResultBatch();
  }, { root: container, rootMargin: '400px' });
  _goResultsObserver.observe(sentinel);
}

function _goGetRecentExercises(limit) {
  var seen = {};
  var recents = [];
  for (var i = db.logs.length - 1; i >= 0 && recents.length < limit; i--) {
    var ses = db.logs[i];
    for (var j = 0; j < (ses.exercises || []).length && recents.length < limit; j++) {
      var name = ses.exercises[j].name;
      if (!seen[name]) { seen[name] = true; recents.push(name); }
    }
  }
  return recents;
}

function goSelectSearchResult(name, exoId) {
  // Capturer l'index de remplacement AVANT goCloseSearch() qui efface _goReplaceIdx :
  // sinon le flux ÂŦ ð Recherche manuelle Âŧ tombe toujours en mode ajout (index perdu).
  var _replaceIdx = (typeof window._goReplaceIdx === 'number') ? window._goReplaceIdx : null;
  goCloseSearch();
  if (_replaceIdx !== null) {
    // Replace mode
    var idx = _replaceIdx;
    activeWorkout.exercises[idx].name = name;
    activeWorkout.exercises[idx].exoId = exoId || null;
    activeWorkout.exercises[idx].restSeconds = goGetDefaultRest(name, exoId);
    activeWorkout.exercises[idx].sets = [];
    goAutoSave();
    goRequestRender();
    return;
  }
  // Add mode â vague 4 : l'avertissement difficultÃĐ se pose AVANT le push.
  // L'ancien confirm() synchrone poussait puis pop-ait si refus ; en async,
  // on n'ajoute l'exercice QUE si l'utilisateur confirme (aucun ÃĐtat rÃĐsiduel).
  var _addExo = function() {
    activeWorkout.exercises.push({
      exoId: exoId || null,
      name: name,
      sets: [],
      restSeconds: goGetDefaultRest(name, exoId),
      notes: ''
    });
    goAutoSave();
    goRequestRender();
  };
  var _exoData = exoId ? EXO_DATABASE[exoId] : null;
  if (_exoData && _exoData.difficulty >= 4 && (db.user.level || 'intermediaire') === 'debutant') {
    var alts = (_exoData.alternatives || []).map(function(altId) { var a = EXO_DATABASE[altId]; return a ? a.name : null; }).filter(Boolean);
    var body = _exoData.name + ' est un exercice avancÃĐ (difficultÃĐ ' + _exoData.difficulty + '/5).';
    if (_exoData.tips) body += '<br><br>ðĄ ' + _exoData.tips;
    if (alts.length) body += '<br><br>Alternatives : ' + alts.join(', ');
    showConfirm({
      title: 'â ïļ Exercice avancÃĐ',
      body: body,
      confirmLabel: 'Continuer quand mÃŠme',
      onConfirm: _addExo
    });
    return;
  }
  _addExo();
}

