    h += '<div class="go-wizard-grid">';
    var equipOpts = [{val:'barbell',icon:'ðïļ',label:'Barre'},{val:'dumbbell',icon:'ðŠ',label:'HaltÃĻres'},{val:'machine',icon:'âïļ',label:'Machine'},{val:'cable',icon:'ð',label:'CÃĒble'},{val:'bodyweight',icon:'ðĪļ',label:'Corps'},{val:'other',icon:'ðĶ',label:'Autre'}];
