// ============================================================
// PR CELEBRATION â Toast (Type A) + Overlay (Type B) + Partage
// ============================================================
// Chantier A vague 1 â rebranchÃĐ sur le toast unifiÃĐ. Position haute + style
// cÃĐlÃĐbration conservÃĐs par choix dÃĐlibÃĐrÃĐ (variante paramÃĐtrÃĐe, pas un 2áĩ systÃĻme).
function showPRToast(exoName, weight, reps, kind) {
  var label = kind === 'reps'
    ? Math.round(weight) + ' kg Ã ' + reps + ' â record de reps'
    : Math.round(weight) + ' kg â record de charge';
  showToast('âĄ Nouveau PR â ' + exoName + ' Â· ' + label,
    { variant: 'pr', position: 'top', duration: 2600 });
}

function showPROverlay(liftName, weightKg, newTier) {
  var existing = document.getElementById('prOverlayB');
  if (existing && existing.parentNode) existing.parentNode.removeChild(existing);

  var tierHtml = newTier
    ? '<div style="font-size:14px;color:#FFD700;margin-top:8px;">ð Nouveau rang : ' + newTier + '</div>'
    : '';

  var overlay = document.createElement('div');
  overlay.id = 'prOverlayB';
  overlay.style.cssText = [
    'position:fixed', 'inset:0', 'z-index:var(--z-overlay)',
    'background:rgba(8,4,18,0.96)',
    'display:flex', 'flex-direction:column',
    'align-items:center', 'justify-content:center',
    'text-align:center', 'padding:32px'
  ].join(';');

  overlay.innerHTML =
    '<div style="font-size:48px;margin-bottom:16px;animation:prPulse 0.6s ease infinite alternate">âĄ</div>' +
    '<div style="font-size:13px;letter-spacing:4px;color:rgba(255,255,255,0.5);text-transform:uppercase;margin-bottom:8px">Record Personnel</div>' +
    '<div style="font-size:28px;font-weight:800;color:white;margin-bottom:4px">' + liftName + '</div>' +
    '<div style="font-size:56px;font-weight:900;background:linear-gradient(135deg,#BF5AF2,#FF375F);-webkit-background-clip:text;-webkit-text-fill-color:transparent;margin-bottom:8px">' + weightKg + ' kg</div>' +
    tierHtml +
    '<div style="margin-top:32px;display:flex;gap:12px">' +
      '<button onclick="sharePRImage(\'' + liftName.replace(/'/g, "\\'") + '\',' + weightKg + ')" style="background:rgba(255,255,255,0.1);color:white;border:1px solid rgba(255,255,255,0.2);border-radius:14px;padding:12px 20px;font-size:14px;font-weight:600">ðĪ Partager</button>' +
      '<button onclick="document.getElementById(\'prOverlayB\').remove()" style="background:linear-gradient(135deg,#BF5AF2,#FF375F);color:white;border:none;border-radius:14px;padding:12px 24px;font-size:14px;font-weight:600">Continuer â</button>' +
    '</div>';

  document.body.appendChild(overlay);
}

function sharePRImage(liftName, weightKg) {
  var canvas = document.createElement('canvas');
  canvas.width = 800; canvas.height = 400;
  var ctx = canvas.getContext('2d');

  var grad = ctx.createLinearGradient(0, 0, 800, 400);
  grad.addColorStop(0, '#0D0816');
  grad.addColorStop(1, '#1A0A2E');
  ctx.fillStyle = grad;
  ctx.fillRect(0, 0, 800, 400);

  ctx.fillStyle = 'rgba(255,255,255,0.4)';
  ctx.font = '600 18px system-ui';
  ctx.textAlign = 'center';
  ctx.fillText('RECORD PERSONNEL', 400, 120);

  ctx.fillStyle = 'white';
  ctx.font = '800 52px system-ui';
  ctx.fillText(liftName, 400, 200);

  ctx.fillStyle = '#BF5AF2';
  ctx.font = '900 80px system-ui';
  ctx.fillText(weightKg + ' kg', 400, 300);

  ctx.fillStyle = 'rgba(255,255,255,0.3)';
  ctx.font = '500 16px system-ui';
  ctx.fillText('TrainHub', 400, 360);

  canvas.toBlob(function(blob) {
    var file = new File([blob], 'pr-' + liftName + '.png', { type: 'image/png' });
    if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
      navigator.share({
        files: [file],
        title: 'PR ' + liftName + ' â ' + weightKg + 'kg',
        text: 'Nouveau record sur TrainHub ! ðŠ'
      }).catch(function() {});
    } else {
      var a = document.createElement('a');
      a.href = canvas.toDataURL('image/png');
      a.download = 'pr-' + liftName + '.png';
      a.click();
    }
  });
}

window.showPRToast = showPRToast;
window.showPROverlay = showPROverlay;
window.sharePRImage = sharePRImage;

// ============================================================
// PULL-TO-REFRESH (mobile)
// ============================================================
(function() {
  var startY = 0, pulling = false, indicator = null;
  function getIndicator() {
    if (!indicator) {
      indicator = document.createElement('div');
      indicator.className = 'ptr-indicator';
      indicator.textContent = 'RafraÃŪchissement...';
      document.body.appendChild(indicator);
    }
    return indicator;
  }
  document.addEventListener('touchstart', function(e) {
    if (window.scrollY === 0) { startY = e.touches[0].clientY; pulling = true; }
  }, { passive: true });
  document.addEventListener('touchmove', function(e) {
    if (!pulling) return;
    var diff = e.touches[0].clientY - startY;
    if (diff > 60) { getIndicator().classList.add('visible'); }
  }, { passive: true });
  document.addEventListener('touchend', function() {
    if (!pulling) return;
    pulling = false;
    var ind = getIndicator();
    if (ind.classList.contains('visible')) {
      ind.classList.remove('visible');
      if (typeof refreshUI === 'function') refreshUI();
      if (typeof syncSupabase === 'function') syncSupabase();
    }
  }, { passive: true });
})();

// ============================================================
// SIGN OUT
// ============================================================
async function appSignOut() {
  showModal(
    'Se dÃĐconnecter ?',
    'Confirmer',
    'var(--red)',
    async function() {
      if (typeof supabase !== 'undefined' && supabase) {
        try { await supabase.auth.signOut(); } catch(e) {}
      }
      if (typeof supaClient !== 'undefined' && supaClient) {
        try { await supaClient.auth.signOut(); } catch(e) {}
      }
      // Effacer la session (garder les donnÃĐes d'entraÃŪnement)
      db.user.email = '';
      db.user.supabaseId = '';
      if (db.social) db.social.onboardingCompleted = false;
      saveDBNow();
      setTimeout(function() { window.location.reload(); }, 300);
    },
    'Annuler'
  );
}

// ============================================================
// POST-LOGIN SYNC
// ============================================================
async function postLoginSync() {
  try {
    if (typeof syncFromCloud === 'function') await syncFromCloud();
    else if (typeof loadFromCloud === 'function') await loadFromCloud();
    // v230 â Recalculer currentBlock.week depuis lastDeloadDate (ou blockStartDate) aprÃĻs load
    if (typeof wpDetectPhase === 'function' && db.weeklyPlan) {
      try { wpDetectPhase(); if (typeof saveDB === 'function') saveDB(); } catch (e) {}
    }
    // v231 â Re-render du tab Plan aprÃĻs sync cloud (sinon S1 figÃĐ jusqu'au refresh)
    if (typeof renderProgrammeV2 === 'function') {
      try { renderProgrammeV2(); } catch (e) {}
    }
    if (db.pendingSync && navigator.onLine) {
      db.pendingSync = false;
      if (typeof syncToCloud === 'function') syncToCloud(true);
    }
    if (typeof ensureProfile === 'function') await ensureProfile();
    if (!db.social || !db.social.onboardingCompleted) {
      setTimeout(function() {
        if (typeof showSocialOnboarding === 'function') showSocialOnboarding();
      }, 800);
    }
    // Notifications J1âJ30
    if (typeof checkScheduledNotifications === 'function') checkScheduledNotifications();
    // RGPD â check health consent
    checkRequiredConsents();
    // RGPD â recover in-progress workout from IDB after token refresh
    checkWorkoutBackup();
  } catch(e) {
    console.error('postLoginSync error:', e);
  }
}

